-- Module: Signs and signals
INSERT INTO module (id, courseId, slug, title, description, ordinal) VALUES (
  'module_signs-and-signals', 'course_national_teen_core', 'signs-and-signals', 'Signs and signals', 'How traffic signs, signals, and pavement markings communicate the rules of the road and keep everyone safe.', 0
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_signs-and-signals_reading-traffic-signs', 'module_signs-and-signals', 'reading-traffic-signs', 'Reading traffic signs', 'Traffic signs are a visual language. Once you learn the grammar (shape and color), you can read most signs in a fraction of a second, even before you can make out the words. That speed matters. At 45 mph you cover about 66 feet every second, so a sign you can''t decode fast is a sign you''ve already driven past.

## Shapes tell you what kind of message it is

The shape of a sign is a clue to its purpose. You can recognize it from far away, in fog, or when it''s partly blocked by a tree.

- **Octagon (8 sides):** Stop. The only sign with this shape. If you ever see the back of an octagon, you know without thinking that drivers on the other side have a stop.
- **Upside-down triangle:** Yield. Slow down, be ready to stop, give the right-of-way.
- **Diamond:** Warning. Something ahead could surprise you, like a curve, a deer crossing, or a narrow bridge.
- **Pentagon (school shape):** School zone or school crossing.
- **Pennant (long horizontal triangle):** No-passing zone, posted on the left side of the road.
- **Rectangle (tall):** Regulatory, like speed limits or one-way.
- **Rectangle (wide):** Guide signs, like directions and distances.
- **Round:** Railroad crossing advance warning.
- **Crossbuck (X shape):** The actual railroad crossing. Treat it like a yield sign at minimum.

## Colors tell you the tone

Color adds another layer of meaning so you don''t have to read every word.

- **Red:** Stop, yield, or prohibition (do not enter, wrong way).
- **Yellow:** General warning. Caution ahead.
- **Fluorescent yellow-green:** Warning specifically about people, school zones, pedestrian crossings, bike crossings.
- **Orange:** Construction or temporary work zones. Take these seriously; lanes shift, workers are nearby, and fines often double.
- **Green:** Guidance and directions. Exits, distances, street names.
- **Blue:** Driver services. Hospitals, rest areas, gas, food, lodging.
- **Brown:** Recreation and points of interest. Parks, historic sites.
- **White with black letters:** Regulatory, like speed limits.

## Regulatory signs are laws, not suggestions

A regulatory sign tells you something you legally must or must not do. The classics:

- **Stop:** A full stop behind the line, then proceed when safe. Rolling through is illegal and a common cause of T-bone crashes.
- **Yield:** Slow, look, and let cross traffic or pedestrians go first. You only need to stop if conditions require it.
- **Speed limit:** The maximum legal speed in ideal conditions. In rain, snow, fog, or heavy traffic, the safe speed is lower, and you''re still responsible for driving to conditions.
- **Do Not Enter and Wrong Way:** You''re about to enter a road going against traffic. Stop, back out carefully if you can, and find another route.
- **One Way:** Traffic flows in the direction of the arrow only.
- **No Turn on Red:** Even when the light is red and the way looks clear, you cannot turn.

## Warning signs buy you reaction time

Warning signs (yellow diamonds, mostly) give you advance notice so you can adjust before you reach the hazard. A curve sign often comes with an advisory speed in black on yellow. That speed isn''t a legal limit, but it''s a strong recommendation based on how the curve was engineered. Ignoring it is how cars end up in ditches.

Common warning signs to recognize:

- Curve and sharp turn arrows
- Merge and lane-ends
- Two-way traffic ahead (after a divided section ends)
- Slippery when wet
- Deer, cattle, or other animal crossings
- Pedestrian and bicycle crossings
- Hill (steep grade ahead)

## Guide and service signs

Green guide signs help with navigation. Blue service signs help with logistics. Neither carries a legal requirement, but they reduce stress and prevent last-second lane changes when you''re hunting for an exit. Plan your exits a mile ahead, not at the gore point.

## Reading signs as a system

Signs often come in groups. A warning sign sets up the situation, a regulatory sign tells you the rule, and a guide sign confirms where you''re going. Train yourself to scan all three on every block. Good drivers don''t react to signs; they anticipate them.', 14, 0
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_signs-and-signals_reading-traffic-signs', 'lesson_signs-and-signals_reading-traffic-signs', 'Quiz: Reading traffic signs', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_signs-and-signals_reading-traffic-signs_0', 'quiz_signs-and-signals_reading-traffic-signs', 'You see the back of an octagonal sign facing traffic on a cross street. What does that tell you?', '["Cross traffic has a yield sign","Cross traffic has a stop sign","The intersection has a traffic signal that is out","You must stop because the sign is missing on your side"]', 1, 'The octagon shape is reserved exclusively for stop signs. Recognizing the shape from behind lets you know cross traffic must stop, which helps you predict their behavior.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_signs-and-signals_reading-traffic-signs_1', 'quiz_signs-and-signals_reading-traffic-signs', 'A diamond-shaped yellow sign shows a curve with the number 35 below it in black. What does the 35 mean?', '["The legal speed limit through the curve is 35 mph","A minimum speed of 35 mph is required","An advisory speed of 35 mph is recommended for the curve","The curve is 35 feet long"]', 2, 'Black-on-yellow speeds on warning signs are advisory, based on how the curve was engineered. They aren''t a legal limit, but ignoring them is a common cause of run-off-road crashes.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_signs-and-signals_reading-traffic-signs_2', 'quiz_signs-and-signals_reading-traffic-signs', 'What does an orange sign typically indicate?', '["A school zone with children present","A scenic or recreational area ahead","A construction or temporary work zone","A required detour for trucks only"]', 2, 'Orange is reserved for construction and temporary traffic control. Lanes can shift, workers may be present, and fines for violations are often increased in these zones.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_signs-and-signals_reading-traffic-signs_3', 'quiz_signs-and-signals_reading-traffic-signs', 'You approach an intersection with a sign reading ''No Turn on Red.'' The light is red and no other cars are visible. What should you do?', '["Turn right after stopping, since no one is coming","Wait for the green light before turning","Treat it as a yield and turn slowly","Turn only if a pedestrian signal shows walk"]', 1, 'A ''No Turn on Red'' sign is a regulatory sign with the force of law. It applies regardless of whether traffic is visible, because pedestrians, bikes, or hidden vehicles may still be present.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_signs-and-signals_reading-traffic-signs_4', 'quiz_signs-and-signals_reading-traffic-signs', 'What is the meaning of a fluorescent yellow-green sign?', '["Construction zone ahead","Warning specifically about people, such as school zones or pedestrian crossings","Guide sign for tourist destinations","Required minimum speed reduction"]', 1, 'Fluorescent yellow-green is used to make people-related warnings stand out, including school zones, pedestrian crossings, and bike crossings. The vivid color is designed to grab your attention quickly.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_signs-and-signals_traffic-signals-and-right-of-way', 'module_signs-and-signals', 'traffic-signals-and-right-of-way', 'Traffic signals and right-of-way', 'A traffic signal is more than a colored light. It''s an instruction, a timer, and a coordination tool that lets thousands of cars share an intersection without crashing. Knowing exactly what each phase means, and what to do during transitions, separates safe drivers from the ones who cause fender-benders at every light.

## The basic phases

- **Steady red:** Stop behind the marked line, crosswalk, or before the intersection if no line exists. Remain stopped until the light changes (or, where allowed, until you can safely turn right on red after a complete stop).
- **Steady yellow:** The light is about to turn red. Stop if you can do so safely. Yellow is not ''speed up.''
- **Steady green:** You may proceed if the intersection is clear. Green is permission, not a guarantee that the way is safe.
- **Flashing red:** Treat exactly like a stop sign. Stop, yield, then go when safe.
- **Flashing yellow:** Slow down and proceed with caution. Cross traffic may not have to stop.

## Arrows tell you what''s protected

Green arrows give you a **protected** movement, meaning conflicting traffic and pedestrians have a red light and shouldn''t be in your path. A solid green ball, by contrast, only gives you a **permissive** movement for turns; you must yield to oncoming traffic and pedestrians before turning.

A **flashing yellow arrow** is a newer signal that means you may turn, but you must yield. It replaced the old habit of using a green ball for permissive lefts, because too many drivers assumed they had the right-of-way.

A **red arrow** means stop for that specific movement. In most places you cannot turn on a red arrow even when right-on-red is allowed for the rest of the intersection.

## What to do when the light is out

If a signal is dark, flashing red in all directions, or visibly malfunctioning, treat the intersection as an **all-way stop**. Every driver stops, and the first to arrive goes first. When two drivers arrive at the same time, the driver on the right goes first.

## Right-of-way is given, not taken

Right-of-way rules tell you who must yield, not who has a guaranteed pass. You can be legally in the right and still be in a hospital bed. Yield when in doubt.

Core rules:

- **At an uncontrolled intersection** (no signs, no signals), yield to the vehicle on your right if you arrive at the same time.
- **When turning left**, yield to oncoming traffic and to pedestrians in the crosswalk you''re turning into.
- **At a T-intersection**, the road that ends must yield to through traffic.
- **When entering a roadway** from a driveway, alley, or parking lot, yield to all traffic and pedestrians on the road.
- **Pedestrians in a crosswalk** (marked or unmarked at intersections) generally have right-of-way over vehicles.
- **Emergency vehicles** with lights and sirens have right-of-way over everyone. Pull to the right and stop if you can.
- **School buses** with flashing reds and an extended stop arm require traffic in both directions to stop on undivided roads.
- **Funeral processions** are typically allowed to proceed through intersections together, even on a red, if led by an escort.

## Pedestrian signals work in parallel

Walk and don''t-walk signals (and the newer countdown timers) are designed for pedestrians, but they tell you a lot too. A flashing ''don''t walk'' or a low countdown means the light is about to change. If you''re approaching, expect a yellow soon and prepare to stop, not to floor it.

## Common signal mistakes

- **Stopping in the crosswalk.** Stop behind the line so pedestrians have the space they''re entitled to.
- **Creeping into the intersection on a left turn and getting stuck on red.** Only enter the intersection when you can clear it. Otherwise you''ll block cross traffic.
- **Assuming a green light means go.** Always glance left, then right, then left again. Red-light runners cause some of the deadliest urban crashes.
- **Treating a yellow as a challenge.** The honest test is: can I stop safely? If yes, stop. If braking hard would risk a rear-end collision, continue through carefully.

## The bigger picture

Signals work because everyone follows them. The moment a driver decides the rules don''t apply to them, the whole system breaks down. Drive like the person in the next car is depending on you to behave predictably, because they are.', 13, 1
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_signs-and-signals_traffic-signals-and-right-of-way', 'lesson_signs-and-signals_traffic-signals-and-right-of-way', 'Quiz: Traffic signals and right-of-way', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_signs-and-signals_traffic-signals-and-right-of-way_0', 'quiz_signs-and-signals_traffic-signals-and-right-of-way', 'You approach an intersection where the traffic signal is completely dark due to a power outage. How should you proceed?', '["Continue through at the posted speed limit","Treat the intersection as a yield","Treat the intersection as an all-way stop","Wait at the intersection until the signal is restored"]', 2, 'A dark signal is treated as an all-way stop. Every driver stops, and the first to arrive proceeds first. This is the safest default when no signal is operating.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_signs-and-signals_traffic-signals-and-right-of-way_1', 'quiz_signs-and-signals_traffic-signals-and-right-of-way', 'You have a steady green ball (not an arrow) and want to turn left. What must you do?', '["Turn immediately because the green gives you the right-of-way","Yield to oncoming traffic and pedestrians, then turn when safe","Wait for a green arrow before turning under any circumstances","Honk to alert oncoming drivers and proceed"]', 1, 'A solid green ball gives you a permissive left turn, not a protected one. You must yield to oncoming traffic and pedestrians in the crosswalk before completing the turn.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_signs-and-signals_traffic-signals-and-right-of-way_2', 'quiz_signs-and-signals_traffic-signals-and-right-of-way', 'A traffic light turns yellow as you approach. What is the correct action?', '["Accelerate to clear the intersection before red","Stop if you can do so safely; otherwise proceed through carefully","Always stop, even if it requires hard braking","Slow down and proceed regardless of the light''s color"]', 1, 'Yellow means the light is about to turn red. The rule is to stop if you can do so safely. Slamming the brakes when a rear-end collision is likely is more dangerous than continuing through with caution.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_signs-and-signals_traffic-signals-and-right-of-way_3', 'quiz_signs-and-signals_traffic-signals-and-right-of-way', 'Two cars arrive at an uncontrolled intersection at exactly the same time. Who has the right-of-way?', '["The faster vehicle","The vehicle on the left","The vehicle on the right","Whoever signals first"]', 2, 'When two vehicles arrive at an uncontrolled intersection at the same time, the vehicle on the right has the right-of-way. This is a default rule used worldwide to resolve ambiguity.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_signs-and-signals_traffic-signals-and-right-of-way_4', 'quiz_signs-and-signals_traffic-signals-and-right-of-way', 'What does a flashing yellow arrow at a left-turn signal mean?', '["You have a protected left turn; oncoming traffic is stopped","You may turn left, but you must yield to oncoming traffic and pedestrians","You must stop and wait for a green arrow","Left turns are prohibited from this lane"]', 1, 'A flashing yellow arrow means a permissive left turn. You may turn, but oncoming traffic has the green light, so you must yield to them and to pedestrians before turning.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_signs-and-signals_pavement-markings', 'module_signs-and-signals', 'pavement-markings', 'Pavement markings', 'Pavement markings are the lines, arrows, and words painted on the road surface. They guide you when signs and signals aren''t visible, especially at night when your headlights catch the reflective paint long before you''d see a sign. Like signs, the markings follow a consistent code. Once you know it, you can drive confidently on roads you''ve never seen before.

## Line colors

Line color tells you about the relationship between you and oncoming traffic.

- **Yellow lines** separate traffic moving in **opposite directions**. If a yellow line is on your left, you''re on a two-way road.
- **White lines** separate traffic moving in the **same direction**, or mark the edge of the road on the right.

If you ever see a yellow line on your right while driving forward, you''re on the wrong side of the road. Stop and reorient immediately.

## Line patterns

Line patterns tell you what you''re allowed to do.

- **Solid line:** Do not cross unless you''re making a legal turn into or out of a driveway, alley, or parking spot.
- **Broken (dashed) line:** Crossing is permitted when safe (passing, lane changes).
- **Double solid line:** Strong prohibition. Do not cross. Used on two-way roads where passing is dangerous and on freeway shoulders.
- **One solid + one broken:** Passing is allowed only from the side with the broken line. If the solid line is on your side, no passing.

## Edge lines and shoulders

The **white edge line** on the right marks the boundary between the travel lane and the shoulder. A solid white edge line means the shoulder is for emergencies only. On many roads the line becomes broken to mark a turn lane or merge area.

A **yellow edge line on the left** of a one-way road marks the left boundary. You''ll see this on divided highways and on the entry side of one-way streets.

## Special lane markings

- **Turn lanes:** Marked by arrows on the pavement and overhead or roadside signs. Only make the movement indicated by the arrow. A left arrow means turn left only; a straight-and-left arrow means either is allowed.
- **Two-way left-turn lanes:** A center lane bordered by a solid yellow line on the outside and a broken yellow line on the inside. Either direction of traffic can use it, but **only for turning left** or for entering the road from a side street. It''s not a passing lane and not a travel lane.
- **High-occupancy vehicle (HOV) lanes:** Often marked with a white diamond. Restricted to vehicles with a minimum number of occupants during posted hours.
- **Bike lanes:** Solid white lines, often with a bicycle symbol. Don''t drive in them except to turn across them, and yield to cyclists when you do.
- **Bus and transit lanes:** Marked and often colored. Restricted to authorized vehicles.

## Crosswalks and stop lines

- **Stop line:** A solid white bar across your lane. Stop **behind** it at a red light or stop sign. The line marks where the intersection legally begins.
- **Crosswalk:** Marked by two parallel white lines or by a ''ladder'' pattern of white stripes. Pedestrians have right-of-way here. Even where no lines are painted, every intersection has a legal crosswalk along the natural path of the sidewalk.
- **Yield line:** A row of white triangles (''shark teeth'') across your lane. Slow, look, and yield.

## Words and symbols on the road

Words and symbols painted on the pavement back up signs. Common ones:

- **STOP** or **YIELD** painted ahead of the line where the sign sits.
- **SCHOOL** in front of a school zone.
- **ONLY** with an arrow, meaning the lane is exclusively for that movement.
- **PED XING** for pedestrian crossing.
- **RR** with an X marking a railroad crossing.
- **Arrows** showing allowed turns and lane direction.

## Reading markings at night and in bad weather

Lane paint is engineered to reflect headlights, but rain, snow, and worn paint can hide it. In those conditions:

- Slow down and follow the path of vehicles ahead at a safe distance.
- Use the edge line on the right as your reference rather than the center line, which may be obscured by other cars.
- Don''t assume a missing line means you can go anywhere. The road still has lanes; you just can''t see them.

Good drivers read pavement markings constantly, the same way they read signs. They become a backup when signs are obscured and a primary cue when they aren''t.', 12, 2
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_signs-and-signals_pavement-markings', 'lesson_signs-and-signals_pavement-markings', 'Quiz: Pavement markings', 80, 1
