INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_signs-and-signals_pavement-markings_0', 'quiz_signs-and-signals_pavement-markings', 'What does a yellow line on the road indicate?', '["The edge of the road on the right","A separation between lanes going the same direction","A separation between lanes going opposite directions","A bicycle lane boundary"]', 2, 'Yellow lines separate traffic moving in opposite directions. White lines separate traffic moving in the same direction. If you see yellow on your right while moving forward, you''re going the wrong way.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_signs-and-signals_pavement-markings_1', 'quiz_signs-and-signals_pavement-markings', 'You are on a two-lane road. The center line is solid yellow on your side and broken yellow on the other side. May you pass?', '["Yes, passing is allowed if oncoming traffic is clear","No, the solid line on your side prohibits passing","Yes, but only during daylight hours","No, double yellow lines always prohibit passing"]', 1, 'On a combined solid-and-broken yellow line, only drivers on the broken-line side may pass. The solid line on your side means passing from your direction is not allowed.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_signs-and-signals_pavement-markings_2', 'quiz_signs-and-signals_pavement-markings', 'A center lane is bordered on each side by a solid yellow line outside and a broken yellow line inside. How may you use it?', '["As a normal travel lane in either direction","Only for passing slower vehicles","Only for left turns and for entering the road from side streets","Only for emergency vehicles"]', 2, 'This is a two-way left-turn lane. Drivers from either direction may use it only to make a left turn or to enter the road from a side street. It is not a travel or passing lane.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_signs-and-signals_pavement-markings_3', 'quiz_signs-and-signals_pavement-markings', 'What does a solid white line on the right edge of your lane mean?', '["The shoulder is for emergencies only and crossing is generally discouraged","You may freely drive on the shoulder during heavy traffic","The lane is closed ahead","A bike lane begins at the line"]', 0, 'A solid white edge line marks the right boundary of the travel lane. The shoulder beyond it is for emergencies, breakdowns, or authorized stops, not normal driving.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_signs-and-signals_pavement-markings_4', 'quiz_signs-and-signals_pavement-markings', 'You are approaching a stop sign with a solid white bar painted across your lane just before the intersection. Where should you stop?', '["In the crosswalk for better visibility","Past the bar so you can see cross traffic","Behind the white bar (stop line)","Anywhere within the intersection"]', 2, 'The white bar is the stop line, marking where your vehicle must stop. Stopping past it can block crosswalks or push you into the intersection. If you cannot see cross traffic, edge forward slowly after the initial stop.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_signs-and-signals_work-zones-school-zones-and-railroad-crossings', 'module_signs-and-signals', 'work-zones-school-zones-and-railroad-crossings', 'Work zones, school zones, and railroad crossings', 'Some areas have their own special package of signs, signals, and markings because the risks are higher than average. Work zones, school zones, and railroad crossings are the three you''ll meet most often. Each has its own rhythm, and each demands more attention, not less.

## Work zones

Work zones change the road. Lanes shift, lanes disappear, speed limits drop, and people are walking around just feet from moving traffic. Crashes in work zones often injure the workers, not just the drivers.

Key signs and signals to recognize:

- **Orange diamond warning signs:** ''Road Work Ahead,'' ''Lane Closed,'' ''Flagger Ahead.'' These give you time to slow down and merge.
- **Reduced speed limit signs:** Often posted as ''Work Zone Speed Limit XX.'' These are legally enforceable, and many places double fines.
- **Channelizing devices:** Cones, barrels, and drums guide you through shifts in lane alignment. Stay between them. Do not weave.
- **Flaggers:** A flagger''s hand signals override signs and signals. A red flag or a ''STOP'' paddle means stop. A ''SLOW'' paddle means proceed slowly through the zone.
- **Arrow boards and message signs:** Tell you which lane is closing and how far ahead.

How to drive a work zone:

- Merge early when you see the warning signs. Late merging causes chain-reaction braking.
- Increase following distance. The car ahead may brake hard for a worker or equipment.
- Watch for stopped vehicles. Rear-end crashes are the most common type in work zones.
- Don''t change lanes inside the cones unless markings allow it.
- Put your phone away. Work zones are not the place to glance at a text.

## School zones

School zones protect kids who don''t always make rational traffic decisions. They run into the road for a dropped ball. They cross between parked cars. They look the wrong way.

School-zone cues:

- **Pentagon-shaped school sign:** Marks a school ahead.
- **Fluorescent yellow-green crossing signs:** Mark crossings used by students.
- **School zone speed limit signs:** Often combined with flashing yellow beacons. The reduced limit applies whenever the lights are flashing, or during posted times, or ''when children are present,'' depending on the wording.
- **Crossing guards:** Their directions have the force of law. Stop when they hold up a stop paddle, even if the light is green.
- **School buses with flashing red lights and an extended stop arm:** All traffic in both directions on undivided roads must stop. On a divided highway, traffic going the opposite way is usually exempt, but check the signs in your area before assuming.

Driving rules in school zones:

- Obey the posted reduced speed limit whenever it applies. Speeding tickets in school zones are usually steep.
- Scan continuously for kids between parked cars, at corners, and on bikes.
- Never pass a stopped vehicle that may be yielding to a pedestrian in a crosswalk. Stop too. The other driver may be seeing something you can''t.
- Drop-off and pickup zones have their own rules; follow posted signs and any school staff directing traffic.

## Railroad crossings

A train can take more than a mile to stop. The driver of a train cannot swerve. If you and a train arrive at the crossing at the same time, the train wins, every time, and the outcome is often fatal.

Railroad-crossing cues:

- **Round yellow advance warning sign with an X and the letters RR:** A crossing is ahead. Slow down and look for the crossing itself.
- **Pavement markings:** A large white X with the letters RR painted in the lane.
- **Crossbuck (white X-shaped sign):** Marks the crossing. Treat as a yield sign at minimum. Stop if a train is approaching.
- **Number-of-tracks sign:** Posted below the crossbuck. If it says ''2,'' look both ways twice; a second train can be hidden by the first.
- **Flashing red lights and bells:** A train is coming or already on the crossing. Stop at least 15 feet from the nearest rail and wait until the lights stop and the gates rise fully.
- **Gates:** Never drive around lowered gates. It is illegal and often deadly.

How to cross safely:

- Slow down as you approach.
- Lower your radio and turn off the fan so you can hear horns or bells.
- Look both ways down the tracks, not just at the signals. Equipment can fail.
- If your view is blocked, edge forward only until you can see clearly.
- Once you start across, do not stop. Make sure there''s room on the far side before you cross.
- If your vehicle stalls on the tracks, get everyone out and away from the tracks immediately, walking toward the train at an angle (so debris from a collision flies away from you). Then call the emergency number posted at the crossing.

## A common thread

Work zones, school zones, and railroad crossings all share one feature: the consequences of inattention are much worse than the inconvenience of being careful. Slow down, scan more, and assume something unexpected is about to happen. That mindset is what keeps drivers and everyone around them alive.', 14, 3
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_signs-and-signals_work-zones-school-zones-and-railroad-crossings', 'lesson_signs-and-signals_work-zones-school-zones-and-railroad-crossings', 'Quiz: Work zones, school zones, and railroad crossings', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_signs-and-signals_work-zones-school-zones-and-railroad-crossings_0', 'quiz_signs-and-signals_work-zones-school-zones-and-railroad-crossings', 'You are approaching a railroad crossing. The lights are flashing red and the bells are ringing, but no train is yet visible. What must you do?', '["Cross quickly before the train arrives","Stop at least 15 feet from the nearest rail and wait until the signals stop","Drive around the gates if they are still rising","Proceed at reduced speed if the gates are not down"]', 1, 'Flashing red lights and bells mean a train is coming. You must stop at least 15 feet from the nearest rail and remain stopped until the signals stop flashing and any gates rise fully. Trains are often closer and faster than they appear.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_signs-and-signals_work-zones-school-zones-and-railroad-crossings_1', 'quiz_signs-and-signals_work-zones-school-zones-and-railroad-crossings', 'A flagger in a work zone holds up a ''STOP'' paddle, but the lane ahead looks clear and the temporary signs do not say to stop. What should you do?', '["Continue through; signs override flagger instructions","Stop, because flagger instructions override signs and signals in a work zone","Slow down but keep moving","Stop only if you see workers ahead"]', 1, 'In a work zone, a flagger''s instructions have the force of law and override other signs and signals. Flaggers can see conditions, equipment, and workers that you cannot.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_signs-and-signals_work-zones-school-zones-and-railroad-crossings_2', 'quiz_signs-and-signals_work-zones-school-zones-and-railroad-crossings', 'A school bus on a two-lane undivided road has stopped with its red lights flashing and stop arm extended. What are vehicles in the oncoming lane required to do?', '["Continue at reduced speed","Pass the bus only on the left","Stop and wait until the lights stop flashing and the arm retracts","Honk to warn the bus driver before proceeding"]', 2, 'On undivided roads, traffic in both directions must stop for a school bus with flashing red lights and an extended stop arm. Children may cross in front of or behind the bus, and they are often hard to see.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_signs-and-signals_work-zones-school-zones-and-railroad-crossings_3', 'quiz_signs-and-signals_work-zones-school-zones-and-railroad-crossings', 'What does a pentagon-shaped sign indicate?', '["Construction zone","Railroad crossing ahead","School zone or school crossing","Hospital ahead"]', 2, 'The five-sided pentagon shape is reserved for school zones and school crossings. The unique shape lets drivers recognize the warning from a distance, even before reading the text.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_signs-and-signals_work-zones-school-zones-and-railroad-crossings_4', 'quiz_signs-and-signals_work-zones-school-zones-and-railroad-crossings', 'Your vehicle stalls on a railroad track with no train visible. What should you do first?', '["Try to restart the engine until a train appears","Push the vehicle off the tracks yourself","Get everyone out of the vehicle and away from the tracks immediately, then call for help","Stay in the vehicle with hazards on and wait for assistance"]', 2, 'Get everyone out and well away from the tracks first, walking at an angle toward any approaching train so debris from a collision flies away from you. Then call the emergency number posted at the crossing. A stalled vehicle is replaceable; lives are not.', 4
);

-- Module: Right-of-way
INSERT INTO module (id, courseId, slug, title, description, ordinal) VALUES (
  'module_right-of-way', 'course_national_teen_core', 'right-of-way', 'Right-of-way', 'How to figure out who goes first at intersections, roundabouts, and uncontrolled crossings so traffic flows safely and predictably.', 1
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_right-of-way_what-right-of-way-really-means', 'module_right-of-way', 'what-right-of-way-really-means', 'What Right-of-Way Really Means', 'Right-of-way is one of the most misunderstood ideas in driving. People talk about it like it''s a prize you win at an intersection. It isn''t. Right-of-way is the rule that decides who is supposed to move next so that two cars (or a car and a person, or a car and a bike) don''t try to use the same space at the same time.

Here''s the key idea you need to lock in early: **the law tells you who must yield, not who has the right to take.** No driver ever truly "has" the right-of-way. They are only given it when other road users yield it to them. That difference sounds small, but it changes how you drive. A driver who thinks "it''s my turn, go" causes crashes. A driver who thinks "is everyone actually yielding to me?" avoids them.

## Why the rules exist

Traffic works because drivers can predict what other drivers will do. Right-of-way rules are the shared script. When everyone follows the same script, intersections clear smoothly. When someone improvises (rolling a stop sign, swinging wide through a roundabout, waving another driver through out of turn), the script breaks and people get hurt.

Three things make right-of-way rules so important:

- **Intersections are where most urban crashes happen.** Paths cross there. Speeds drop and rise. Drivers are deciding, looking, and turning all at once.
- **Vulnerable road users have the least protection.** Pedestrians, cyclists, and people using wheelchairs or scooters lose every collision with a car. The rules tilt in their favor for a reason.
- **Eye contact is not a contract.** You may think the other driver saw you. They may be looking at their phone, their kid, or right through you. Assume nothing until the car actually slows.

## The general hierarchy

When you''re not sure who goes, work down this list in order:

1. **Emergency vehicles with lights and sirens.** Everyone yields, pulls right when safe, and stops.
2. **Traffic signals and signs.** A red light or stop sign overrides almost any other rule.
3. **Pedestrians in or entering a crosswalk.** Marked or unmarked, they get to cross.
4. **Vehicles already in the intersection.** If someone is already through, let them finish.
5. **The driver on the right** when two cars arrive at the same time at an uncontrolled intersection or all-way stop.
6. **Through traffic over turning traffic.** Left-turning drivers yield to oncoming cars going straight.

This list isn''t a magic spell, but it covers most situations you will see for years.

## Yielding is an action, not a feeling

Yielding means slowing down, stopping if needed, and letting the other road user go before you do. It is something you do with the brake and the steering wheel, not just something you think. A common teen mistake is to ease forward while "yielding," which signals to the other driver that you''re going. Either commit to stopping or commit to going. Half-decisions confuse everyone.

## When the other driver is wrong

Sometimes you legally have the right-of-way and the other driver takes it anyway. Maybe they rolled the stop. Maybe they cut across three lanes. Your job in that moment is not to prove a point. It''s to avoid the crash. Brake, steer, or both. You can be 100% legally right and still end up in the hospital. A defensive driver gives up right-of-way whenever holding onto it would cause a collision.

## Reading an intersection before you reach it

Good drivers start solving the intersection before they arrive. As you approach, ask:

- What kind of control is here? Signal, stop sign, yield sign, nothing?
- Who else is approaching, and from where?
- Are there pedestrians at the corners or in the crosswalks?
- Is anyone signaling a turn?
- Is the lane I want actually clear past the intersection, or will I get stuck blocking it?

If you can answer those five questions before you''re at the white line, the intersection almost solves itself. If you arrive without an answer, you''re guessing, and guessing at 35 mph is how mistakes turn into crashes.

## The mindset to carry forward

Think of right-of-way less like a rulebook and more like good manners with serious stakes. You give space. You take turns. You watch out for people who can''t protect themselves. The driver who treats every intersection as a small negotiation, not a contest, is the driver who gets through a lifetime of driving without hurting anyone.', 12, 0
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_right-of-way_what-right-of-way-really-means', 'lesson_right-of-way_what-right-of-way-really-means', 'Quiz: What Right-of-Way Really Means', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_right-of-way_what-right-of-way-really-means_0', 'quiz_right-of-way_what-right-of-way-really-means', 'Which statement best describes how right-of-way actually works?', '["It is something you earn by arriving at the intersection first.","The law says who must yield, not who is allowed to take the space.","Whoever flashes their headlights first gets to go.","It only applies when a police officer is watching."]', 1, 'Right-of-way rules are written as duties to yield. No driver is ever guaranteed the space; they only get it when others actually yield. Thinking otherwise leads to drivers taking the intersection when it isn''t safe.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_right-of-way_what-right-of-way-really-means_1', 'quiz_right-of-way_what-right-of-way-really-means', 'You have a green light and a clear legal right to go, but another driver is running their red light straight at you. What should you do?', '["Hold your speed because you have the right-of-way.","Honk and keep going to prove the point.","Brake, steer, or do whatever it takes to avoid the crash.","Accelerate to clear the intersection before they reach you."]', 2, 'Being legally right does not protect you from injury. A defensive driver gives up right-of-way whenever holding onto it would cause a collision.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_right-of-way_what-right-of-way-really-means_2', 'quiz_right-of-way_what-right-of-way-really-means', 'At an uncontrolled intersection, two cars arrive at the same moment. According to the general hierarchy, who should yield?', '["The driver on the right yields to the driver on the left.","The driver on the left yields to the driver on the right.","The larger vehicle yields to the smaller vehicle.","Whoever signals first gets to go."]', 1, 'When two drivers reach an uncontrolled or all-way-stop intersection at the same time, the driver on the left yields to the driver on the right. Vehicle size and turn signals do not decide it.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_right-of-way_what-right-of-way-really-means_3', 'quiz_right-of-way_what-right-of-way-really-means', 'Why is making eye contact with another driver not a reliable way to confirm they will yield to you?', '["Drivers are legally not allowed to make eye contact.","Eye contact only counts at four-way stops.","A driver can appear to look at you without actually processing what they see.","Eye contact means the other driver is challenging you."]', 2, 'People can stare straight at a car or pedestrian and still not register them, especially when distracted. Wait until the vehicle actually slows or stops before you trust it to yield.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_right-of-way_what-right-of-way-really-means_4', 'quiz_right-of-way_what-right-of-way-really-means', 'Which of these is the best way to "read" an intersection before reaching it?', '["Glance at the signal only when you are about to cross the line.","Identify the type of control, other road users, and whether your exit lane is clear before you arrive.","Focus only on the car directly in front of you.","Assume any intersection without a signal is a free-for-all."]', 1, 'Good drivers solve the intersection in advance by scanning for the type of control, other traffic and pedestrians, signals, and whether they can clear the intersection. Arriving without that information forces last-second guesses.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_right-of-way_controlled-intersections-signs-and-signals', 'module_right-of-way', 'controlled-intersections-signs-and-signals', 'Controlled Intersections: Signs and Signals', 'A controlled intersection is one where signs or signals tell drivers what to do. Most of the intersections you''ll meet in town are controlled. The good news: the rules are clear. The bad news: many crashes happen here because drivers stop paying attention to what the signs and signals actually require.

## Stop signs

A stop sign means a full stop, every time, even if you can see the intersection is empty. A full stop means the wheels stop turning. A "rolling stop" is not a stop, and it''s one of the most common ways new drivers get into low-speed crashes and tickets.

At a stop sign:

- Stop at the white stop line if there is one. If not, stop before the crosswalk. If there''s no crosswalk, stop where you can see cross traffic.
- After stopping, yield to any pedestrians in or entering the crosswalk.
- Yield to any vehicle that is close enough on the cross street to be a hazard.
- Then proceed when it''s safe.

If you stop behind a car at a stop sign, you are not done. When that car moves, you pull up to the line and stop again. The sign controls each driver individually.

## All-way (four-way) stops

At an all-way stop, every approach has a stop sign. The basic order:

- **First to fully stop is first to go.**
- If two drivers stop at the same time, the driver on the right goes first.
- If you are turning left and a car across from you is going straight or turning right, they go first.

The most useful skill at a four-way stop is patience plus eye contact. If everyone is being polite at once, gently take your turn when it''s clearly yours. Don''t wave others through out of order; you confuse the people behind them.

## Yield signs

A yield sign means slow down, be ready to stop, and let other traffic and pedestrians go first. You only stop if you have to. The key word is "ready." If you fly past a yield sign without ever scanning, you''ve treated it like nothing was there.

You''ll see yield signs at freeway on-ramps, T-intersections, and entrances to roundabouts. The merge lane onto a freeway often ends in a yield sign or a yield-style merge: the cars already on the freeway have the right-of-way, and you adjust your speed to fit into the gap.

## Traffic signals

Signals seem obvious until you have to make a judgment call. The basics:

- **Solid red:** stop and stay stopped until green. Right turn on red is often allowed after a full stop and a yield, but only where it isn''t prohibited by a posted sign.
- **Solid yellow:** the light is about to turn red. Stop if you can do so safely. Don''t speed up to beat it.
- **Solid green:** go if the intersection is clear. A green light is not a command to enter; it''s permission. If a car is still finishing their left turn, let them clear.
- **Flashing red:** treat it like a stop sign.
- **Flashing yellow:** slow down and proceed with caution.

## Protected vs. permitted left turns

This trips up new drivers constantly.

- A **green arrow** is a protected turn. Oncoming traffic has a red. You can turn without yielding to them, but you still yield to pedestrians in your crosswalk.
- A **solid green light** while you''re in a left-turn lane is a permitted turn. You must yield to oncoming traffic and pedestrians, then turn when there''s a safe gap.
- A **flashing yellow arrow** is also permitted: you may turn, but you must yield to oncoming traffic and pedestrians.

If you''re sitting in the intersection on a permitted green waiting for a gap and the light turns yellow, complete your turn carefully when oncoming traffic stops. Don''t panic and freeze.

## The dilemma zone

When a green light turns yellow, there''s a short distance where you''re not sure if you can stop in time or should keep going. Your default should be: **if you can stop safely, stop.** Slamming the brakes on a wet road can be just as dangerous as running the yellow. Use your judgment based on your speed, the road surface, and the car behind you. If you decide to go, don''t speed up; maintain your speed and clear the intersection.

## Pedestrian signals

The walk signal is for pedestrians, but it tells you a lot. A flashing "don''t walk" or a countdown timer ticking down means your green is about to end. If you''re approaching and the countdown is at 3, you''re not making this light. Start slowing down.

## The habit to build

At every controlled intersection, do a mental check: **What does the control say? What does traffic actually look like? Who has not yet yielded?** The sign or signal is your starting point, not your ending point. Real intersections are made of people, and people sometimes ignore the rules. Your eyes verify what the signs promise.', 14, 1
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_right-of-way_controlled-intersections-signs-and-signals', 'lesson_right-of-way_controlled-intersections-signs-and-signals', 'Quiz: Controlled Intersections: Signs and Signals', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_right-of-way_controlled-intersections-signs-and-signals_0', 'quiz_right-of-way_controlled-intersections-signs-and-signals', 'Four cars arrive at a four-way stop in this order: you (north), then a car to your west, then a car to your east, then a car to your south. You all want to go straight. Who goes first?', '["The car on your south, because they are oncoming.","You, because you stopped first.","The car on your right (your east), because they are on the right.","Whoever has the largest vehicle."]', 1, 'At a four-way stop, the first driver to fully stop goes first. The right-side rule only breaks ties when two drivers arrive at the same time.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_right-of-way_controlled-intersections-signs-and-signals_1', 'quiz_right-of-way_controlled-intersections-signs-and-signals', 'You have a solid green light and want to turn left. Oncoming traffic also has a green. What is required of you?', '["You may turn immediately because your light is green.","Oncoming traffic must yield to you because you are turning.","You must yield to oncoming traffic and to pedestrians, then turn when there is a safe gap.","You must wait for the light to turn yellow before turning."]', 2, 'A solid green is a permitted left turn. You must yield to oncoming through traffic and to pedestrians in your crosswalk before turning.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_right-of-way_controlled-intersections-signs-and-signals_2', 'quiz_right-of-way_controlled-intersections-signs-and-signals', 'A yield sign requires you to:', '["Come to a full stop every time, just like a stop sign.","Slow down, be ready to stop, and let other road users go first.","Maintain your current speed and merge whenever you arrive.","Stop only if a police officer is present."]', 1, 'A yield sign means slow down, be prepared to stop, and let traffic and pedestrians with the right-of-way go first. You only stop fully if you have to.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_right-of-way_controlled-intersections-signs-and-signals_3', 'quiz_right-of-way_controlled-intersections-signs-and-signals', 'The light turns yellow as you approach an intersection. What is the best default response?', '["Speed up to clear the intersection before it turns red.","Slam on the brakes regardless of conditions.","Stop if you can do so safely; otherwise maintain speed and clear the intersection.","Stop in the middle of the crosswalk to be safe."]', 2, 'A yellow light is a warning that red is coming. The right call is to stop if it''s safe to do so. If stopping would cause a crash (a tailgater, slick road), maintain speed and clear the intersection without speeding up.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_right-of-way_controlled-intersections-signs-and-signals_4', 'quiz_right-of-way_controlled-intersections-signs-and-signals', 'What does a flashing red light mean for you as a driver?', '["Slow down and proceed with caution; do not stop.","Treat it like a stop sign: full stop, then proceed when safe.","It means the signal is broken and you can ignore it.","Stop and wait for the light to turn green."]', 1, 'A flashing red light has the same meaning as a stop sign. Come to a complete stop, yield to other traffic and pedestrians, then proceed when it is safe.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_right-of-way_uncontrolled-intersections-and-pedestrians', 'module_right-of-way', 'uncontrolled-intersections-and-pedestrians', 'Uncontrolled Intersections and Pedestrians', 'Not every intersection has a sign or signal. In neighborhoods, parking lots, alleys, and rural areas, you''ll meet intersections where the rules are unwritten on the pavement but very much in the law. These are uncontrolled intersections, and they cause more crashes than they should because drivers stop expecting them.

## What "uncontrolled" really means

An uncontrolled intersection is one with no stop sign, yield sign, or signal facing your direction of travel. Sometimes one street has stop signs and the cross street doesn''t (a two-way stop). Sometimes nobody has anything. Either way, the law has a default order so drivers can still figure out who goes.

The core rules to memorize:

- If you arrive first and the other driver hasn''t, you go first.
- If you arrive at the same time, **the driver on the left yields to the driver on the right.**
- If you are turning left, you yield to oncoming traffic going straight or turning right.
- A vehicle on a paved road generally has the right-of-way over a vehicle entering from an unpaved road or driveway.

One more rule that matters in real neighborhoods: **a vehicle leaving a driveway, alley, parking lot, or private road must yield to traffic and pedestrians on the public road.** That includes you pulling out of your own driveway. The sidewalk crossing your driveway is still a pedestrian space.

## Two-way stops

A two-way stop is more dangerous than it looks. You have stop signs, the cross street doesn''t. When you stop, you might assume any approaching car will also stop. They won''t. They may be going 45 mph and not expecting you to pull out.

At a two-way stop:

- Stop fully.
- Look left, right, and left again. The car closest to you on your left is the first threat.
- Wait for a gap big enough not just to enter the intersection, but to fully clear it or merge with traffic.
- When in doubt, wait. A few extra seconds is cheap.

## T-intersections

A T-intersection is where one road ends at another. If the through road (the top of the T) has no sign or signal, traffic on the through road has the right-of-way. The driver coming up the stem of the T must yield, whether or not there''s a sign. Treat the absence of a sign as a yield, not as permission to drive through.

## Pedestrians: the most important yielders

A pedestrian is anyone outside a vehicle: people walking, jogging, using a wheelchair or mobility scooter, kids on foot. Drivers must yield to pedestrians in a crosswalk, and that includes crosswalks you can''t see.

Key facts that surprise new drivers:

- **Every intersection has crosswalks**, even if there are no painted lines. The lines just make it visible. The right to cross is the same.
- **You must yield to pedestrians who are in your half of the road, and to those approaching close enough to be in danger.** You don''t get to scoot through just because they''re not directly in front of your bumper.
- **You may not pass a vehicle stopped at a crosswalk.** If the car next to you stops for no obvious reason near an intersection, assume there''s a pedestrian you can''t see and stop too.
- **Blind or low-vision pedestrians using a white cane or guide dog always have the right-of-way.** Stop and wait, no matter where they are.

Kids deserve extra space. They dart. They don''t look. They may not understand that a green light for them is a permission slip, not a force field. Slow down in school zones and near parks, even when the speed limit doesn''t drop.

## Cyclists and micromobility users

Cyclists and people on scooters often have the same right-of-way as cars when they''re in the roadway, and the same right-of-way as pedestrians when they''re in a crosswalk (rules vary, but treat them as protected users either way). Common situations to watch:

- **Right hooks:** you turn right across a cyclist going straight in a bike lane. Always check your right blind spot and mirror before turning right.
- **Left crosses:** you turn left across an oncoming cyclist. Cyclists are smaller and harder to spot. Don''t assume the road is clear just because you don''t see a car.
- **Door zone:** if you''re driving next to parked cars, leave room for a door to open or a cyclist to swerve.

## Emergency and special vehicles

When you see or hear an emergency vehicle with lights and sirens:

- Pull to the right edge of the road when safe and stop.
- Don''t stop in an intersection. Clear it first, then pull over.
- Wait until they pass and any others behind them pass.
- Don''t follow within 500 feet (about 1.5 football fields).

For a stopped emergency vehicle, tow truck, or roadside worker with flashing lights, move over a lane if you can, or slow down significantly if you can''t. This is sometimes called a "move-over" duty and it exists because people working on the shoulder die every year from drivers who didn''t give them space.

## School buses

When a school bus stops with its red lights flashing and stop arm out, traffic in both directions usually has to stop, unless you are on the opposite side of a divided road with a physical barrier. The kids walk in front of the bus where you can''t see them. Treat the flashing red lights as a non-negotiable full stop.

## The habit that keeps you safe

Uncontrolled intersections punish autopilot. The fix is simple: every time the pavement changes, every time you enter a neighborhood, every time you leave a driveway, ask, "Who else might be here, and who is supposed to yield?" If the answer is "me," then yield like you mean it.', 13, 2
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_right-of-way_uncontrolled-intersections-and-pedestrians', 'lesson_right-of-way_uncontrolled-intersections-and-pedestrians', 'Quiz: Uncontrolled Intersections and Pedestrians', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_right-of-way_uncontrolled-intersections-and-pedestrians_0', 'quiz_right-of-way_uncontrolled-intersections-and-pedestrians', 'You are pulling out of your driveway onto a residential street. A car is coming down the street and a pedestrian is walking on the sidewalk that crosses your driveway. Who must yield?', '["The pedestrian, because they are crossing a driveway, not a street.","The car on the street, because you signaled first.","You, to both the pedestrian on the sidewalk and the car on the street.","Nobody; whoever moves first wins."]', 2, 'A vehicle leaving a driveway must yield to traffic on the road and to pedestrians on the sidewalk crossing the driveway. You are the entering vehicle, so the duty to yield is on you.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_right-of-way_uncontrolled-intersections-and-pedestrians_1', 'quiz_right-of-way_uncontrolled-intersections-and-pedestrians', 'At an uncontrolled intersection, you and another car arrive at the same moment. The other car is on your right. What should you do?', '["Go first because you got there at the same time.","Yield to the car on your right.","Wave the other car through and then go.","Honk to claim the intersection."]', 1, 'When two vehicles arrive at the same time at an uncontrolled intersection, the driver on the left yields to the driver on the right.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_right-of-way_uncontrolled-intersections-and-pedestrians_2', 'quiz_right-of-way_uncontrolled-intersections-and-pedestrians', 'The car in the lane next to you suddenly stops near an intersection, even though there is no light or stop sign. The safest action is to:', '["Pass them quickly so you don''t get stuck.","Stop too, because there may be a pedestrian in the crosswalk you can''t see.","Honk to find out why they stopped.","Change lanes and continue at the same speed."]', 1, 'It is illegal and dangerous to pass a vehicle stopped at a crosswalk. Assume there is a pedestrian you cannot see and stop until you know it is clear.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_right-of-way_uncontrolled-intersections-and-pedestrians_3', 'quiz_right-of-way_uncontrolled-intersections-and-pedestrians', 'You are turning right at an intersection and there is a bike lane to your right with a cyclist going straight. What should you do?', '["Turn quickly to get ahead of the cyclist.","Honk so the cyclist knows to slow down.","Check your right mirror and blind spot, yield to the cyclist, then turn.","Cyclists must always yield to cars, so you can turn freely."]', 2, 'Turning right across a cyclist going straight is called a "right hook" and is a common cause of crashes. Check your right blind spot and yield to the cyclist before turning.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_right-of-way_uncontrolled-intersections-and-pedestrians_4', 'quiz_right-of-way_uncontrolled-intersections-and-pedestrians', 'An ambulance with lights and sirens is approaching from behind while you are in the middle of an intersection. What should you do?', '["Stop immediately in the intersection.","Clear the intersection first, then pull to the right and stop.","Speed up and stay ahead of the ambulance.","Follow closely behind so other cars know to move."]', 1, 'Stopping inside the intersection blocks the emergency vehicle and other traffic. Clear the intersection first, then pull to the right edge of the road and stop until it passes.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_right-of-way_roundabouts-merges-and-special-situations', 'module_right-of-way', 'roundabouts-merges-and-special-situations', 'Roundabouts, Merges, and Special Situations', 'Some right-of-way situations don''t fit the simple "who''s on the right" rules. Roundabouts, freeway merges, lane changes, and roadway hazards all have their own logic. They feel intimidating at first because there''s motion in every direction, but each one is built on the same idea: traffic already in motion has priority over traffic trying to enter.

## Roundabouts

A roundabout is a circular intersection where traffic flows counter-clockwise (in countries that drive on the right). Roundabouts are safer than traditional intersections because they remove the chance of a high-speed broadside crash; everyone is moving the same direction at low speed.

The rules are simpler than they look:

- **Slow down as you approach.** Most roundabouts are designed for 15-25 mph inside the circle.
- **Yield to traffic already in the roundabout.** They have the right-of-way. You enter on a gap.
- **Yield to pedestrians in the crosswalks** at the entrance and exit.
- **Do not stop inside the roundabout.** Once you''re in, keep moving. Stopping causes rear-end crashes.
- **Use your right turn signal as you approach your exit**, not when you enter. The signal tells drivers waiting to enter that you''re leaving.

### Multi-lane roundabouts

Multi-lane roundabouts add one more skill: picking the right lane before you enter. Generally:

- **Right lane:** for first exit (right turn) or going straight.
- **Left lane:** for going straight, left turns, or U-turns.

Watch for the lane-use signs and pavement arrows before the roundabout. Pick your lane early. Once you''re inside, do not change lanes. If you miss your exit, just go around again. Looping is free; cutting across lanes is dangerous.

### Emergency vehicles in roundabouts

If an emergency vehicle is approaching, do not stop in the circle. Exit first, then pull over to let them through.

## Freeway and highway merges

Merging is a place where being timid is as dangerous as being aggressive. The basic rule is that traffic on the freeway has the right-of-way; merging traffic must adjust speed and find a gap.

Good merging is a three-step move:

1. **On the on-ramp:** accelerate to roughly the speed of traffic. Crawling onto a freeway at 35 mph when traffic is moving at 65 mph is a setup for a crash.
2. **In the merge lane:** look over your left shoulder and into your mirror, find a gap, and signal.
3. **Merge smoothly** into the gap without forcing other drivers to slam on their brakes.

Drivers already on the freeway should move over a lane when possible to make room, but they aren''t required to. If they don''t, you have to fit. Speed up or slow down to find a gap; do not stop in the merge lane unless traffic is fully stopped.

### Zipper merge

When a lane is closing ahead (construction, a crash), the safest approach is the zipper merge: use both lanes until the merge point, then alternate one car from each lane. It feels rude to use the closing lane all the way to the front, but research shows it actually cuts backup length by up to 40%. Let people in. Don''t ride bumpers to block them.

## Lane changes within traffic

A lane change is a small right-of-way negotiation. The cars in the lane you want to enter have the right-of-way. You must:

- Signal before you move, not while you move.
- Check your mirror and your blind spot.
- Find a gap and slide into it without making anyone else brake.

If the car in the next lane speeds up when you signal, don''t fight them. Drop back and try again. Most road rage incidents start with a lane change someone took without asking.

## Funerals and processions

A funeral procession is a line of vehicles, usually with headlights on and hazard lights flashing, following a lead vehicle. In most places, the procession is treated as a single unit: once the lead car legally enters an intersection, the rest can follow even on a red light. As another driver, you yield to the procession and do not cut into it.

## Work zones and incident scenes

In a work zone, the normal rules can be overridden by:

- Temporary signs (lower speed limits, lane closures).
- Flaggers with signs or flags. A flagger''s directions outrank a traffic signal.
- Pilot vehicles guiding you through one-way sections.

Obey the flagger. Slow down. Fines are usually doubled, but more importantly, workers are inches from traffic.

## Trains and railroad crossings

Trains always have the right-of-way. They cannot stop quickly. At a crossing:

- Stop if lights are flashing, gates are down, or a train is close enough to be a hazard, even without active signals.
- Never try to beat a train. Trains are bigger and closer than they look, and they are moving faster than they appear.
- Don''t stop on the tracks in traffic. Make sure there''s room on the far side before you cross.

## Animals and unusual obstacles

Livestock being herded on a roadway have the right-of-way. So do horses being ridden; pass them slowly and give wide space because horses can spook. Wildlife doesn''t follow rules at all. In areas with deer, moose, or elk, slow down at dawn and dusk, and remember that if you see one animal, more are likely nearby.

## The pattern

Notice the pattern across all these situations: the people or vehicles already moving, already in the lane, already on the track, already in the circle have the priority. Your job as the entering driver is to fit in safely. Once you internalize that, the special situations stop being special. They''re just one rule applied to a hundred different intersections.', 14, 3
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_right-of-way_roundabouts-merges-and-special-situations', 'lesson_right-of-way_roundabouts-merges-and-special-situations', 'Quiz: Roundabouts, Merges, and Special Situations', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_right-of-way_roundabouts-merges-and-special-situations_0', 'quiz_right-of-way_roundabouts-merges-and-special-situations', 'As you approach a single-lane roundabout, you see a car already circulating. What should you do?', '["Enter immediately because you have the right-of-way as a new arrival.","Stop fully and wait for the entire roundabout to be empty.","Yield to the circulating car and enter when there is a safe gap.","Honk and enter at the same time as the circulating car."]', 2, 'Drivers entering a roundabout must yield to traffic already in the circle. You don''t need an empty roundabout, just a safe gap.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_right-of-way_roundabouts-merges-and-special-situations_1', 'quiz_right-of-way_roundabouts-merges-and-special-situations', 'You are inside a multi-lane roundabout and realize you are in the wrong lane to take your exit. What is the safest move?', '["Change lanes inside the roundabout to reach your exit.","Stop and wait for traffic to clear so you can cross over.","Continue around the roundabout and try the exit again on the next loop.","Reverse to get into the correct lane."]', 2, 'Lane changes inside a roundabout cause sideswipes. If you miss your exit, simply continue around the circle and try again. Stopping or reversing is unsafe.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_right-of-way_roundabouts-merges-and-special-situations_2', 'quiz_right-of-way_roundabouts-merges-and-special-situations', 'You are on a freeway on-ramp and traffic on the freeway is moving at about 65 mph. What is the best approach?', '["Enter the freeway at 35 mph and speed up after you merge.","Stop at the end of the ramp and wait for a long gap.","Accelerate on the ramp to roughly freeway speed, then merge into a gap.","Drive on the shoulder until you find an opening."]', 2, 'Merging works best when your speed matches the flow of traffic. Entering slowly forces drivers behind you to brake hard and makes a safe merge much harder.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_right-of-way_roundabouts-merges-and-special-situations_3', 'quiz_right-of-way_roundabouts-merges-and-special-situations', 'A lane is closing ahead due to construction. What is the safest and most efficient way for drivers to merge?', '["All drivers should merge as soon as they see the first warning sign.","Use both lanes until the merge point, then alternate one car from each lane (zipper merge).","The closing lane should always yield from a half-mile back.","Drivers should race to the merge point to claim a spot."]', 1, 'The zipper merge uses both lanes up to the closure and then alternates vehicles. Studies show it shortens backups significantly and is safer than early merging or aggressive blocking.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_right-of-way_roundabouts-merges-and-special-situations_4', 'quiz_right-of-way_roundabouts-merges-and-special-situations', 'You are stopped at a railroad crossing with no active signals, but you can see a train approaching in the distance. What should you do?', '["Cross quickly before the train arrives.","Stop and wait for the train to pass, since trains always have the right-of-way.","Drive around the area to find another crossing.","Honk to alert the train and then cross."]', 1, 'Trains always have the right-of-way and cannot stop quickly. They are also closer and faster than they appear. If a train is close enough to be a hazard, stop and wait, even without active signals.', 4
);

-- Module: Scanning and hazard perception
INSERT INTO module (id, courseId, slug, title, description, ordinal) VALUES (
  'module_scanning-and-hazard-perception', 'course_national_teen_core', 'scanning-and-hazard-perception', 'Scanning and hazard perception', 'Learn to actively read the road, spot threats early, and stay ahead of trouble instead of reacting to it.', 2
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_scanning-and-hazard-perception_why-scanning-matters', 'module_scanning-and-hazard-perception', 'why-scanning-matters', 'Why scanning matters', 'Most crashes are not caused by bad luck. They are caused by drivers who saw the problem too late, or never saw it at all. Scanning is the habit of constantly moving your eyes to gather information about what is around you, what is changing, and what could go wrong in the next few seconds.

When you scan well, you get something incredibly valuable: time. Time to lift off the gas. Time to cover the brake. Time to pick an escape path. A driver who sees a hazard two seconds earlier than another driver has roughly twice as long to respond. That difference is often the difference between a near miss and a crash.

## The brain can only react to what the eyes notice

Your car does exactly what you tell it to do. But you can only tell it the right thing if your eyes have already given your brain the right information. New drivers tend to make two classic mistakes:

- They lock their eyes on one spot, usually the car directly in front of them.
- They look down at the road just past the hood of their own car.

Both habits shrink the world down to a tiny bubble. Inside that bubble, you are always reacting to surprises, because everything outside it is invisible until it suddenly enters.

## Scanning is active, not passive

Looking is not the same as seeing. You can stare straight ahead for a full minute and still miss a pedestrian stepping off a curb if your brain was somewhere else. Active scanning means deliberately asking questions as your eyes move:

- What is the car ahead doing? Speeding up, slowing down, drifting?
- What is happening at the next intersection?
- Are there brake lights three or four cars ahead?
- Is anything moving near the edges of the road, like a kid, a dog, or a cyclist?
- What is behind me, and what is in my blind spots?

You are not just collecting pretty pictures. You are building a moving map of risk.

## The cost of distraction

Every second your eyes are off the road, you are driving blind. At 55 mph, two seconds is about 160 feet, longer than half a football field. A glance at a text message, a long look at the radio, or even a stare at an interesting billboard erases your scanning entirely. Trained drivers treat their eyes as the most important tool in the car, more important than the steering wheel itself.

## What good scanning looks like

A driver with strong scanning habits does several things at once:

- Keeps their eyes moving every couple of seconds.
- Looks far ahead, not just at the bumper in front of them.
- Checks mirrors regularly, not only before lane changes.
- Notices changes, like a brake light flicker or a head turning in a parked car.
- Plans an out, an escape route they could use if something goes wrong.

This sounds like a lot. It becomes automatic with practice, the same way you stopped having to think about tying your shoes. The goal of this module is to turn scanning into a habit you do without thinking, so your brain is free to make good decisions when something unexpected happens.

## The mindset shift

Beginners think driving is about controlling the car. Experienced safe drivers know driving is mostly about managing information. The pedals and the wheel are easy. The hard part, and the part that keeps you alive, is seeing the world clearly and early. Everything else in this module builds on that one idea.', 12, 0
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_scanning-and-hazard-perception_why-scanning-matters', 'lesson_scanning-and-hazard-perception_why-scanning-matters', 'Quiz: Why scanning matters', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_scanning-and-hazard-perception_why-scanning-matters_0', 'quiz_scanning-and-hazard-perception_why-scanning-matters', 'What is the main benefit a driver gains from scanning the road effectively?', '["Better fuel economy","More time to recognize and respond to hazards","A smoother ride for passengers","Less wear on the brakes"]', 1, 'Scanning gives you earlier information, and earlier information gives you more time to react. The other benefits are not what scanning is designed to produce.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_scanning-and-hazard-perception_why-scanning-matters_1', 'quiz_scanning-and-hazard-perception_why-scanning-matters', 'Which of these is a common scanning mistake new drivers make?', '["Checking the rearview mirror too often","Locking their eyes on the car directly in front of them","Looking too far down the road","Glancing at intersections before entering"]', 1, 'New drivers often fixate on the vehicle ahead, which shrinks their view of the road. Checking mirrors and looking far ahead are good habits, not mistakes.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_scanning-and-hazard-perception_why-scanning-matters_2', 'quiz_scanning-and-hazard-perception_why-scanning-matters', 'Why is ''looking'' not the same as ''seeing'' when driving?', '["Mirrors distort what you look at","Your eyes can be pointed at something while your brain is focused elsewhere","The windshield blocks part of your view","Only peripheral vision detects movement"]', 1, 'Active scanning requires attention, not just eye direction. If your mind is on a text or a song, your eyes can be open and still miss critical information.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_scanning-and-hazard-perception_why-scanning-matters_3', 'quiz_scanning-and-hazard-perception_why-scanning-matters', 'At highway speeds, even a two-second glance away from the road is dangerous because:', '["The engine can stall during that time","You travel a long distance essentially blind","Your mirrors automatically reset","The steering wheel becomes harder to turn"]', 1, 'At 55 mph you cover about 160 feet in two seconds. During that time you cannot see or respond to anything new, which is why distracted driving is so dangerous.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_scanning-and-hazard-perception_why-scanning-matters_4', 'quiz_scanning-and-hazard-perception_why-scanning-matters', 'Which statement best describes the mindset of an experienced safe driver?', '["Driving is mostly about controlling the pedals and wheel","Driving is mostly about managing information from the road","Driving is mostly about reacting quickly to surprises","Driving is mostly about following the car ahead at the right distance"]', 1, 'Vehicle control becomes easy with practice. The skill that separates safe drivers is gathering and interpreting information early so they rarely get surprised.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_scanning-and-hazard-perception_the-search-pattern', 'module_scanning-and-hazard-perception', 'the-search-pattern', 'Building a search pattern', 'Good scanning is not random. Safe drivers follow a repeatable pattern that sweeps their eyes across the road in a predictable way. A search pattern keeps you from getting tunnel vision and makes sure no part of your environment goes unchecked for too long.

## Look high, look wide, look often

Three simple rules guide every search pattern:

- **High:** Look far down the road, not just at the car in front of you.
- **Wide:** Sweep your eyes across the full width of the scene, including sidewalks, shoulders, and side streets.
- **Often:** Keep your eyes moving. No single spot deserves a long stare.

A useful rough target is to move your eyes to a new area about every two seconds. You are not racing your eyeballs around; you are flowing from one zone to the next.

## The 12-15 second view

Look as far ahead as you can see clearly, roughly where you will be in 12 to 15 seconds. In the city, that might be the next block. On a highway, it might be a quarter mile or more. Why so far?

- You will spot brake lights, slow traffic, or lane closures before they are a problem.
- You will see traffic lights early enough to decide whether you can stop comfortably.
- You will notice the overall flow of traffic, not just one car.

After looking far, bring your eyes back through the middle distance (about 4 to 8 seconds ahead), then close to your car, then back out again. Think of it as a loop, not a stare.

## Use the edges of the road

Hazards rarely appear in the middle of your lane out of nowhere. They come from the sides: a parked car door, a pedestrian stepping off a curb, a dog running out from a yard, a car easing out of a driveway. Train your eyes to check the edges, not just the center.

At intersections, look left, then right, then left again before you go. The reason for the second left look is that the closest threat to you comes from the left in many traffic patterns, and the situation can change in the seconds it took you to look right.

## Mirrors are part of the pattern

Mirrors are not just for lane changes. A common rule of thumb is to glance at a mirror every 5 to 8 seconds. You are checking:

- Is anyone closing fast behind you?
- Is a vehicle in your blind spot?
- Did the car behind you just brake hard, suggesting a chain of events you should know about?

Knowing what is behind you matters because your best escape from a hazard ahead might be braking hard, and that only works if no one is tailgating you.

## Blind spot checks

Mirrors do not show everything. Before any lane change, merge, or turn, do a quick head turn to check the blind spot on the side you are moving toward. This is a fast glance, not a long stare; your eyes should be back on the road ahead within a second.

## A sample search loop

A practical pattern looks like this, repeated continuously:

- Far ahead (where will I be in 12-15 seconds?).
- Middle distance (what is the car a few ahead doing?).
- Just in front (gap to the car immediately ahead).
- Sides and edges (sidewalks, driveways, side streets).
- Mirror (rear, then the side mirror that matters most for your situation).
- Repeat.

At first, this feels like a checklist. With practice it becomes a smooth, almost unconscious flow. The goal is for your eyes to never settle anywhere long enough to miss what is happening somewhere else.

## Avoid the freeway stare

Long, straight highways are deceptively dangerous because the scene barely changes. Drivers fall into a stare where the car ahead becomes the whole world. Fight it by deliberately moving your eyes, checking mirrors on a schedule, and looking at distant landmarks. Boredom is when scanning matters most.', 14, 1
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_scanning-and-hazard-perception_the-search-pattern', 'lesson_scanning-and-hazard-perception_the-search-pattern', 'Quiz: Building a search pattern', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_scanning-and-hazard-perception_the-search-pattern_0', 'quiz_scanning-and-hazard-perception_the-search-pattern', 'Roughly how far ahead should you try to look while driving?', '["Just past the hood of your car","About 2 seconds ahead","About 12 to 15 seconds ahead","As far as the horizon, with full focus"]', 2, 'A 12 to 15 second view gives you enough warning to plan, while still being close enough to see clearly. Looking just over the hood is too short, and trying to focus on the horizon ignores the middle ground.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_scanning-and-hazard-perception_the-search-pattern_1', 'quiz_scanning-and-hazard-perception_the-search-pattern', 'Which is a recommended habit for using your mirrors?', '["Only check them before changing lanes","Glance at one every 5 to 8 seconds","Stare into the rearview for several seconds at a time","Avoid them on highways to focus on the road ahead"]', 1, 'Frequent short glances keep you aware of what is behind without taking your eyes off the road for long. Mirrors should be used constantly, not only for lane changes.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_scanning-and-hazard-perception_the-search-pattern_2', 'quiz_scanning-and-hazard-perception_the-search-pattern', 'Why do you look left, then right, then left again at an intersection?', '["It is required at every stop sign","Traffic from the left is usually closest to you, and it can change while you look right","Looking twice helps your eyes refocus","It signals other drivers that you are paying attention"]', 1, 'In typical traffic flow, cars coming from the left reach you first. The second look catches anything that changed during the right glance.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_scanning-and-hazard-perception_the-search-pattern_3', 'quiz_scanning-and-hazard-perception_the-search-pattern', 'Why are hazards more likely to come from the edges of the road than the center of your lane?', '["Lanes are usually clear of obstacles","Pedestrians, doors, animals, and vehicles enter from sidewalks, curbs, and driveways","Center striping reflects light and warns drivers","Most cars drift to the right when distracted"]', 1, 'The center of your lane was just driven through by the car ahead, so new threats almost always enter from the sides. Scanning the edges catches them early.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_scanning-and-hazard-perception_the-search-pattern_4', 'quiz_scanning-and-hazard-perception_the-search-pattern', 'Long, straight highways are dangerous to scanning because:', '["Speed limits are higher than drivers expect","The unchanging scene encourages drivers to stare and stop scanning","Mirrors vibrate too much to be useful","Lane markings are spaced too far apart"]', 1, 'When the view barely changes, drivers fall into a fixed stare and miss subtle clues. Deliberately moving your eyes fights this ''highway hypnosis.''', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_scanning-and-hazard-perception_identifying-hazards-early', 'module_scanning-and-hazard-perception', 'identifying-hazards-early', 'Identifying hazards early', 'Scanning tells you where to look. Hazard perception tells you what to look for. A hazard is anything that could force you to change speed or direction, or that could become dangerous if conditions shift. The earlier you spot one, the more options you have.

## Three categories of hazards

It helps to sort what you see into three buckets. Most driving threats fall into one of them:

- **Other road users:** cars, trucks, motorcycles, cyclists, pedestrians, scooter riders, kids on bikes.
- **The road and environment:** potholes, lane closures, debris, standing water, ice patches, sharp curves, glare from the sun.
- **Your own vehicle and state:** worn tires, low washer fluid, fatigue, frustration, distraction.

Good drivers are constantly assessing all three. A perfect driver in a poorly maintained car is still in danger, and so is a sharp car driven by someone who is exhausted.

## Predict, don''t just react

The core skill of hazard perception is prediction. When you see something, ask: what could this become in the next few seconds? Examples:

- A ball rolls into the street. A child may chase it.
- Brake lights flash three cars ahead. Traffic may stop suddenly.
- A parked car has its wheels turned out. It may pull into your lane.
- A driver beside you keeps drifting toward your lane line. They may be distracted.
- A pedestrian at the curb is looking at their phone. They may step out without checking.

None of these are emergencies yet. That is exactly the point. You spot them before they become emergencies, and you adjust early: ease off the gas, cover the brake, change your lane position, or simply increase your following distance.

## Clues that change everything

Small details often tell you what is about to happen:

- **Brake lights and turn signals** further ahead in traffic warn you of slowdowns and lane changes before they reach you.
- **Tire angles** on parked or stopped cars suggest the direction they might move.
- **Head and eye movement** of pedestrians and other drivers reveal their intentions.
- **Shadows under parked cars** can hint at a person standing on the far side.
- **Bouncing brake lights** of a car ahead can mean the driver is panicking or the road surface is uneven.

You do not need to consciously list these. With practice, your brain learns to flag them automatically the way it flags a friend''s face in a crowd.

## Hidden hazards

The worst hazards are the ones you cannot fully see. Common hidden hazards include:

- A view blocked by a large vehicle, especially at intersections.
- A blind curve where the road disappears around a bend.
- A hilltop where you cannot see what is on the other side.
- A truck stopped at a crosswalk, which may hide a pedestrian walking across.
- A driveway or alley between buildings.

When your view is blocked, assume the worst. Slow down. Be ready for something to step, roll, or pull out from behind whatever is in the way. The professional saying is, ''If you cannot see, do not go.''

## Weather and light as hazards

The environment itself is a hazard you must read:

- Wet roads after a dry spell are slipperiest in the first few minutes, before rain washes oil off the surface.
- Bright sun low in the sky can blind both you and other drivers, especially at sunrise and sunset.
- Fog, snow, and heavy rain shrink your scanning distance, so you must slow down to match what you can actually see.
- Cold mornings can leave invisible ice patches on bridges and shaded curves.

If conditions cut your visibility in half, your speed should usually come down too. The rule is simple: never drive faster than you can see.

## Build a habit of ''what if''

A powerful mental habit is constant ''what if'' thinking. What if that car pulls out? What if this light turns yellow? What if the truck ahead brakes hard? You are not being paranoid. You are running quick simulations so that when something does happen, your brain has already rehearsed a response and you act in a fraction of a second instead of freezing.', 14, 2
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_scanning-and-hazard-perception_identifying-hazards-early', 'lesson_scanning-and-hazard-perception_identifying-hazards-early', 'Quiz: Identifying hazards early', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_scanning-and-hazard-perception_identifying-hazards-early_0', 'quiz_scanning-and-hazard-perception_identifying-hazards-early', 'Which of the following best describes a ''hazard'' in driving?', '["Only objects that are already in your lane","Anything that could force you to change speed or direction, now or soon","Only other vehicles within 100 feet of you","Any object larger than your car"]', 1, 'A hazard is any potential threat, not just something already blocking you. Early hazard perception is about future problems, not just present ones.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_scanning-and-hazard-perception_identifying-hazards-early_1', 'quiz_scanning-and-hazard-perception_identifying-hazards-early', 'You see a ball roll into the street ahead. What is the most important thing this tells you?', '["The road surface might be uneven","A child may run out after it","Someone may have lost their groceries","Local kids are not paying attention to traffic laws"]', 1, 'A ball almost always means a child is nearby and may chase it without looking. Predicting the next step is the heart of hazard perception.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_scanning-and-hazard-perception_identifying-hazards-early_2', 'quiz_scanning-and-hazard-perception_identifying-hazards-early', 'A truck is stopped at a crosswalk in the lane next to yours. What should you assume?', '["The truck is broken down","A pedestrian you cannot see may be walking across in front of it","The driver is texting and will move soon","The crosswalk is closed"]', 1, 'Large vehicles can hide pedestrians from your view. When something blocks your line of sight, assume someone could be there and slow down.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_scanning-and-hazard-perception_identifying-hazards-early_3', 'quiz_scanning-and-hazard-perception_identifying-hazards-early', 'Why are wet roads sometimes most slippery right after rain begins?', '["Rain temporarily cools the pavement","Water mixes with oil and grime on the road before it gets washed away","Tires get cold and lose grip","Brake pads need time to warm up in the rain"]', 1, 'The first few minutes of rain lift oil and dirt off the surface, creating a slick layer. Once heavier rain washes it away, traction improves somewhat.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_scanning-and-hazard-perception_identifying-hazards-early_4', 'quiz_scanning-and-hazard-perception_identifying-hazards-early', 'What is the purpose of constant ''what if'' thinking while driving?', '["It makes drivers more nervous, which keeps them alert","It rehearses responses so you react instantly when something does happen","It is a relaxation technique to reduce road rage","It helps you remember traffic laws"]', 1, 'Mental rehearsal turns potential surprises into something your brain has already prepared for. Trained reactions are faster than fresh ones.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_scanning-and-hazard-perception_managing-space-and-time', 'module_scanning-and-hazard-perception', 'managing-space-and-time', 'Managing space and time around your car', 'Spotting hazards early only helps if you have room to do something about them. Space is your safety margin. The more space you keep around your car, the more time you have to scan, decide, and act. Hazard perception and space management are two halves of the same skill.

## Think of a bubble around your car

Imagine an invisible bubble surrounding your vehicle on all four sides. Your job is to keep that bubble as big as conditions allow. When traffic squeezes the bubble, your risk goes up. When you create space, your risk goes down.

There are four zones to manage:

- **Front:** the gap between you and the car ahead.
- **Rear:** the gap behind you, including any tailgaters.
- **Left and right:** the space beside you, especially in adjacent lanes.

You cannot always control all four. But you can almost always influence at least one by adjusting your speed or lane position.

## Following distance: the 3-second minimum

The most important space is in front of you, because that is where most collisions happen. A simple way to check your following distance:

- Pick a fixed object ahead, like a sign or a crack in the road.
- When the car in front of you passes it, count: ''one one-thousand, two one-thousand, three one-thousand.''
- If you reach the same object before you finish counting, you are too close.

Three seconds is a minimum for dry, clear conditions. Increase it to four or more seconds when:

- The road is wet, snowy, or icy.
- Visibility is poor.
- You are following a motorcycle, large truck, or a vehicle whose brake lights you cannot see.
- You are tired or driving an unfamiliar car.
- Someone is tailgating you (yes, more space, not less).

## Why more space helps with tailgaters

It sounds backwards, but if someone is riding your bumper, you should leave more room in front, not less. The extra cushion means you can brake gradually instead of slamming the brakes, which reduces the chance the tailgater rear-ends you. Never brake-check someone; it can cause a serious crash.

## Managing the sides

You often have a choice of where to position your car within your lane. Use it. If a row of parked cars is on your right, drift slightly toward the left side of your lane to add space in case a door opens. If a large truck is beside you, ease away from it. The goal is to avoid being boxed in with no escape route.

A useful rule: try not to drive directly beside another vehicle for long. Either pass it cleanly or drop back so you have room to maneuver. Sitting in someone''s blind spot is one of the most dangerous places on the road.

## Keep an escape route

For every situation, ask yourself: ''If something bad happened right now, where would I go?'' Possibilities include:

- A shoulder or breakdown lane.
- An open lane next to you.
- A gap behind you, which you can use by braking.
- A driveway or open parking area.

Good drivers constantly update this mental escape plan. It changes every few seconds as traffic moves. You may go an entire trip without ever using one, but the day you need it, having thought about it first is what saves you.

## Speed is part of space

Speed and space are linked. The faster you go, the more distance you cover per second, and the more space you need ahead of you. Stopping distances grow much faster than speed. Doubling your speed can roughly quadruple your stopping distance, because both your reaction distance and your braking distance grow.

This is why slowing down in bad conditions is not just polite; it is the only way to keep your safety bubble the right size. If you cannot see far, you cannot stop in time at high speed.

## Bringing it all together

Scanning, hazard perception, and space management work as one system:

- You scan with a deliberate pattern.
- You spot small clues and predict what they might become.
- You keep enough space and an escape route so you can act in time.

Do all three, and you become the kind of driver who almost never gets surprised. The crashes that strike other drivers as ''sudden'' are the ones you saw coming and quietly avoided ten seconds earlier. That is the whole goal of this module, and the foundation of every other driving skill you will learn.', 13, 3
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_scanning-and-hazard-perception_managing-space-and-time', 'lesson_scanning-and-hazard-perception_managing-space-and-time', 'Quiz: Managing space and time around your car', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_scanning-and-hazard-perception_managing-space-and-time_0', 'quiz_scanning-and-hazard-perception_managing-space-and-time', 'What is the minimum recommended following distance in good conditions?', '["1 second","2 seconds","3 seconds","6 seconds"]', 2, 'Three seconds is the standard minimum in dry, clear conditions. Less than that does not leave enough time to react if the car ahead brakes suddenly.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_scanning-and-hazard-perception_managing-space-and-time_1', 'quiz_scanning-and-hazard-perception_managing-space-and-time', 'Someone is tailgating you on the highway. What is the safest response?', '["Brake-check them so they back off","Speed up to put distance between you","Increase the space in front of you so you can brake gradually","Move into the left lane and stay there"]', 2, 'More space ahead lets you slow gently rather than slamming the brakes, which protects you from being rear-ended. Brake-checking and speeding up both create new dangers.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_scanning-and-hazard-perception_managing-space-and-time_2', 'quiz_scanning-and-hazard-perception_managing-space-and-time', 'Why is driving directly beside another vehicle for long periods discouraged?', '["It is illegal in most areas","It blocks your view of the road","It leaves you with no easy escape route if you need to swerve","It uses more fuel"]', 2, 'Riding next to someone removes your sideways escape and often puts you in a blind spot. Pass cleanly or drop back so you have room to maneuver.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_scanning-and-hazard-perception_managing-space-and-time_3', 'quiz_scanning-and-hazard-perception_managing-space-and-time', 'How does doubling your speed affect your stopping distance?', '["It roughly doubles","It roughly quadruples","It barely changes","It depends only on the tires"]', 1, 'Both reaction distance and braking distance grow with speed, so total stopping distance grows much faster than speed itself. Doubling speed roughly quadruples how far you need to stop.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_scanning-and-hazard-perception_managing-space-and-time_4', 'quiz_scanning-and-hazard-perception_managing-space-and-time', 'What is the purpose of constantly identifying an ''escape route'' as you drive?', '["So you can avoid traffic jams","So you have a planned place to go if a hazard suddenly appears","So you can leave the highway quickly when bored","So you do not need to use mirrors as often"]', 1, 'An escape route is a pre-planned out for emergencies, like an open shoulder or adjacent lane. Thinking about it ahead of time means you act instantly instead of freezing when something goes wrong.', 4
);

-- Module: Speed and space management
INSERT INTO module (id, courseId, slug, title, description, ordinal) VALUES (
  'module_speed-and-space-management', 'course_national_teen_core', 'speed-and-space-management', 'Speed and space management', 'How to choose a safe speed, keep a cushion of space around your car, and move with the flow of traffic.', 3
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_speed-and-space-management_choosing-a-safe-speed', 'module_speed-and-space-management', 'choosing-a-safe-speed', 'Choosing a safe speed', 'The posted speed limit is a ceiling, not a target. It tells you the fastest a normal driver can usually go on that road in good conditions. Your job is to pick a speed that fits what is actually happening right now: the weather, the traffic, the road surface, your visibility, and your own experience.

## Speed limits vs. safe speed

A 45 mph sign on a sunny, empty road means 45 is probably fine. The same sign in heavy rain, at night, with a line of brake lights ahead, means 45 is too fast. Almost every state has a law that says you must drive at a speed that is reasonable for current conditions, even if that is well below the posted limit. Getting rear-ended is bad. Rear-ending someone because you could not stop in time is worse, and it is almost always considered your fault.

## What changes your safe speed

Think of these as dials that turn your safe speed down:

- **Weather:** Rain, snow, fog, and ice all reduce tire grip and visibility. Wet roads can double your stopping distance. Ice can multiply it many times over.
- **Light:** At night you can only see as far as your headlights reach. If you are driving faster than you can stop within that lit zone, you are overdriving your headlights.
- **Traffic density:** More cars means less room to react. Cars merging, braking, or changing lanes shrink the space you have to work with.
- **Road type and surface:** Gravel, potholes, construction zones, and sharp curves all demand a slower speed than smooth straight pavement.
- **Your experience:** A new driver needs more time to process what is happening. Going a little slower buys you that time.

## The physics you cannot argue with

Speed does not add risk in a straight line. It multiplies it. The energy your car carries grows with the square of its speed. Doubling your speed from 30 to 60 mph quadruples the energy that has to be absorbed in a crash. That is why a small bump in speed can turn a fender bender into a serious injury.

Stopping distance has two parts:

- **Reaction distance:** how far you travel while your brain notices a problem and your foot moves to the brake. About three quarters of a second for an alert driver, longer if you are tired or distracted.
- **Braking distance:** how far you travel once the brakes are doing their work. This grows quickly with speed and with worse road conditions.

At 30 mph on dry pavement, a typical car needs roughly 90 feet to stop from the moment you spot a hazard. At 60 mph, it is closer to 300 feet, more than the length of a football field.

## Going with the flow

Driving much slower than the cars around you is not automatically safe. Big speed differences cause crashes too. Other drivers will brake hard behind you, swerve around you, or tailgate. On most roads the safest place is moving at about the same speed as surrounding traffic, as long as that speed is legal and reasonable for conditions. If everyone is going 10 over and the road is icy, the answer is not to match them. The answer is to slow down, move right, and let them pass.

## Quick habits to build

- Glance at your speedometer every 5 to 10 seconds, especially after a turn or coming off a ramp.
- When conditions get worse, take your foot off the gas before you think about the brake. Coasting down is smoother and safer than stabbing the pedal.
- On unfamiliar roads, assume the next curve is sharper than it looks until you can see through it.
- If something feels too fast, it is. Trust that signal and ease off.', 14, 0
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_speed-and-space-management_choosing-a-safe-speed', 'lesson_speed-and-space-management_choosing-a-safe-speed', 'Quiz: Choosing a safe speed', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_speed-and-space-management_choosing-a-safe-speed_0', 'quiz_speed-and-space-management_choosing-a-safe-speed', 'The posted speed limit on a road is best understood as:', '["The exact speed every driver should travel at","The maximum legal speed in normal, good conditions","A suggestion that does not really apply to confident drivers","The minimum speed required to keep traffic moving"]', 1, 'Posted limits are the upper bound for good conditions. In rain, snow, fog, heavy traffic, or low visibility you are still required to slow to a reasonable speed.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_speed-and-space-management_choosing-a-safe-speed_1', 'quiz_speed-and-space-management_choosing-a-safe-speed', 'If you double your speed from 30 mph to 60 mph, the energy involved in a crash roughly:', '["Stays about the same","Doubles","Triples","Quadruples"]', 3, 'Kinetic energy grows with the square of speed, so doubling speed roughly quadruples crash energy. Small speed increases create much larger consequences than people expect.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_speed-and-space-management_choosing-a-safe-speed_2', 'quiz_speed-and-space-management_choosing-a-safe-speed', 'You are driving at night on a dark country road. What does it mean to overdrive your headlights?', '["Using your high beams when oncoming traffic is close","Driving so fast you cannot stop within the distance your headlights light up","Forgetting to switch from low to high beams on an empty road","Following another car so closely that your headlights reflect off it"]', 1, 'If a hazard appears at the edge of your headlight beam and you cannot stop in time, you were going too fast for your visibility. Slow down until your stopping distance fits inside what you can see.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_speed-and-space-management_choosing-a-safe-speed_3', 'quiz_speed-and-space-management_choosing-a-safe-speed', 'Traffic on the freeway is moving about 10 mph over the limit. You feel safest at the posted speed. What is the best move?', '["Stay in the left lane at the posted limit so faster drivers learn to slow down","Match the flow exactly, even if it is well over the limit","Stay close to the posted limit but move to a right-hand lane and let faster traffic pass","Slow down well below the limit so other drivers have more room"]', 2, 'Big speed differences cause crashes, but matching unsafe or illegal speeds is not the answer. Keep a reasonable speed and stay right so faster traffic can pass safely.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_speed-and-space-management_choosing-a-safe-speed_4', 'quiz_speed-and-space-management_choosing-a-safe-speed', 'Stopping distance is made up of which two parts?', '["Acceleration distance and braking distance","Reaction distance and braking distance","Following distance and skid distance","Visual distance and audible distance"]', 1, 'Reaction distance is how far you travel before your foot hits the brake. Braking distance is how far you travel while the brakes slow you down. Both grow with higher speeds and worse conditions.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_speed-and-space-management_the-space-bubble-around-your-car', 'module_speed-and-space-management', 'the-space-bubble-around-your-car', 'The space bubble around your car', 'Good drivers think about space the way a goalie thinks about angles. Your car sits inside a bubble of empty space, and you want to keep that bubble as big as you can on every side. Space gives you time. Time gives you options. Options keep you out of crashes.

## The six zones around your car

Picture your car at the center of a tic-tac-toe grid. There are six zones that matter:

- **Front:** the most important zone. Almost everything you have to react to comes from in front of you.
- **Rear:** the zone you control the least. You manage it by braking smoothly and giving warning with your brake lights.
- **Left side and right side:** the lanes or shoulders next to you. These are your escape routes.
- **Front-left and front-right:** the diagonal areas where cars merge into your path or pull out from driveways.

When all six zones are open, you have full flexibility. When one or more closes, your options shrink and risk goes up.

## The front zone: following distance

The front zone is non-negotiable. If you have no space in front of you, no other zone can save you.

Use the **three-second rule** in good conditions:

1. Pick a fixed point ahead, like a sign or a shadow on the road.
2. When the car ahead passes it, count: one-thousand-one, one-thousand-two, one-thousand-three.
3. If you reach the point before you finish counting, you are too close. Ease off.

Three seconds is the floor, not a goal. Add at least one second for each of these:

- Rain or wet pavement
- Snow, ice, or slush (add several seconds)
- Night driving
- Towing or being heavily loaded
- Driving a vehicle you are not used to
- Following a motorcycle (they can stop very quickly)
- A driver ahead who seems distracted or unpredictable

In heavy rain or snow, four to six seconds is reasonable. On ice, even more.

## The rear zone: managing tailgaters

You cannot force a tailgater to back off, but you can lower the risk:

- **Increase your front gap.** This sounds backwards, but it works. With more space ahead, you can slow down gradually instead of hitting the brakes hard. That keeps the tailgater from rear-ending you.
- **Move over.** If there is a right lane available, use it and let them pass.
- **Do not brake-check.** Tapping the brakes to teach a lesson is how chain-reaction crashes start.

## Side zones: keep escape routes open

Try not to drive in clusters. When you are surrounded by cars on every side, a single mistake by any driver in the pack can trap you. If a group of cars catches up to you, adjust your speed slightly to drift out of the cluster. A few seconds of patience can leave you alone on an open stretch of road with options in every direction.

Avoid riding next to large trucks for long stretches. Their blind spots are huge, and you have no easy escape if they drift into your lane.

## Why space is more powerful than reflexes

A new driver might assume that good reflexes can make up for tight following distances. They cannot. Reaction time is mostly fixed by biology, around three quarters of a second for an alert person. Space, on the other hand, is something you can adjust at any moment with your right foot. You can buy yourself another second of reaction time just by lifting off the gas. That is an enormous safety upgrade for almost no effort.

## Putting it together

Every few seconds, do a quick mental check: front, rear, left, right. Are all four open? If one is closed, can you open it by changing speed or lane position? Drivers who do this constantly look calm and smooth from the outside. They are not lucky. They are just keeping their bubble inflated.', 13, 1
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_speed-and-space-management_the-space-bubble-around-your-car', 'lesson_speed-and-space-management_the-space-bubble-around-your-car', 'Quiz: The space bubble around your car', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_speed-and-space-management_the-space-bubble-around-your-car_0', 'quiz_speed-and-space-management_the-space-bubble-around-your-car', 'Which zone around your car is the most important to keep open?', '["The rear zone","The front zone","The left side zone","The right side zone"]', 1, 'Most hazards develop ahead of you, and you need space in front to brake or steer. Other zones matter, but front space is the one that prevents the most common crashes.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_speed-and-space-management_the-space-bubble-around-your-car_1', 'quiz_speed-and-space-management_the-space-bubble-around-your-car', 'In good weather and light traffic, the minimum following distance you should keep is about:', '["One second","Two seconds","Three seconds","Half a second"]', 2, 'Three seconds is the baseline for good conditions and an alert driver. Add more time for rain, snow, night driving, or any situation that reduces traction or visibility.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_speed-and-space-management_the-space-bubble-around-your-car_2', 'quiz_speed-and-space-management_the-space-bubble-around-your-car', 'A driver is tailgating you on a two-lane highway. What is the safest response?', '["Tap your brakes to warn them to back off","Speed up so they have to work to keep up","Increase your following distance so you can slow gradually, and move over when you can","Slow way down until they choose to pass"]', 2, 'Brake-checking and sudden slowdowns invite a crash. Giving yourself more front space lets you handle stops smoothly, and moving over removes the tailgater from your problem entirely.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_speed-and-space-management_the-space-bubble-around-your-car_3', 'quiz_speed-and-space-management_the-space-bubble-around-your-car', 'You are on a freeway and a cluster of cars catches up to you on all sides. What is the best move?', '["Stay where you are so traffic stays predictable","Slightly adjust your speed to drift out of the pack and into open space","Brake hard so the cars behind you have to back off","Speed up well above the limit to pull away from the group"]', 1, 'Being boxed in removes your escape routes. A small speed change, faster or slower, can break you out of the cluster without aggressive maneuvers.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_speed-and-space-management_the-space-bubble-around-your-car_4', 'quiz_speed-and-space-management_the-space-bubble-around-your-car', 'Why is keeping more space around your car more effective than relying on quick reflexes?', '["Reflexes work fine, but extra space looks more polite to other drivers","Reaction time is mostly fixed by biology, but you can change your space cushion any time","Space helps your car brake harder than it normally could","Reflexes only work in dry weather, while space works in any weather"]', 1, 'Human reaction time has a floor of roughly three quarters of a second. You cannot train past it much, but you can always add space, which gives you more time to react no matter how fast your reflexes are.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_speed-and-space-management_reading-traffic-flow', 'module_speed-and-space-management', 'reading-traffic-flow', 'Reading traffic flow', 'Traffic is not random. It moves in patterns, and good drivers learn to read those patterns so they are reacting to what is about to happen, not what already happened. This is the difference between driving and just steering.

## Look far ahead

New drivers tend to stare at the back bumper of the car in front of them. That gives them only a second or two of warning when something goes wrong. Experienced drivers look much farther down the road, usually 12 to 15 seconds ahead. On a city street that is about a block. On a highway it can be a quarter mile or more.

Looking far ahead helps you:

- See brake lights before the car right in front of you reacts
- Spot lane closures, debris, or stalled cars while you still have time to change lanes calmly
- Notice changes in road surface or weather before you hit them
- Predict when a light will change so you can ease off the gas instead of slamming the brakes

Your eyes lead, your hands and feet follow. If you keep your eyes pointed only at the next car, you will always be late.

## Scan, do not stare

Good drivers move their eyes in a pattern. About every two seconds, sweep:

- Far ahead
- Just in front of your car
- Both side mirrors
- The rearview mirror
- Your speedometer

This is not slow or distracting once it becomes a habit. It takes only a second or two and keeps a full picture of traffic in your head at all times.

## Reading other drivers

Cars give away their intentions in dozens of small ways. Watch for:

- **Brake lights down the line.** A wave of brake lights three or four cars ahead means traffic is slowing. Lift off the gas now.
- **Drift within a lane.** A driver weaving slightly may be distracted, tired, or impaired. Give them extra space.
- **Turned front wheels.** A car parked on the side with its wheels turned toward the road is about to pull out. Same goes for cars at a stop sign.
- **Slow rolling at intersections.** A driver who is not fully stopping is one who might not yield.
- **Mismatched turn signals.** A signal that has been on for a long time without a turn may have been left on by accident, or the driver may turn unexpectedly. Either way, do not bet on it.
- **Head movement.** If you can see a driver checking their mirror or looking over their shoulder, they are probably about to change lanes.

## Reading the road itself

The road tells you what is coming if you pay attention:

- **Brake light patterns at the same spot every day** mean a known slowdown, like a merge or a tricky intersection.
- **Skid marks or dark patches** suggest a place where cars often lose traction.
- **Glare on the pavement** after rain can hide standing water and slick patches.
- **Shaded curves** in cold weather hold ice longer than sunny ones.
- **Trash, branches, or sand on the shoulder** can mean a recent crash or a debris field worth slowing for.

## Anticipate the bottleneck

Traffic jams often form at predictable places: on-ramps, lane drops, hills where slow trucks pile up, and intersections with short green lights. When you see one coming, do not wait until you are stuck in it. Slow down gradually, leave extra space, and look for a lane that is moving better. Smooth driving in heavy traffic is almost entirely about anticipating the next slowdown instead of reacting to it.

## Make your own intentions clear

Reading traffic is a two-way street. Other drivers are trying to read you too. Help them:

- Signal at least a few seconds before you turn or change lanes, not as you do it.
- Position your car clearly in a lane, not straddling the line.
- Use steady speeds. Sudden bursts and brakes are hard for others to predict.
- Make eye contact at four-way stops and crosswalks when you can.

When every driver around you can guess what you will do next, the whole system gets safer.', 13, 2
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_speed-and-space-management_reading-traffic-flow', 'lesson_speed-and-space-management_reading-traffic-flow', 'Quiz: Reading traffic flow', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_speed-and-space-management_reading-traffic-flow_0', 'quiz_speed-and-space-management_reading-traffic-flow', 'About how far ahead should an experienced driver be looking on the road?', '["Just at the bumper of the car in front","Two to three seconds ahead","Twelve to fifteen seconds ahead","As far as the horizon, regardless of road type"]', 2, 'Looking 12 to 15 seconds ahead lets you spot brake lights, lane changes, and hazards early. Watching only the bumper in front gives you almost no time to react.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_speed-and-space-management_reading-traffic-flow_1', 'quiz_speed-and-space-management_reading-traffic-flow', 'You see brake lights flashing on three or four cars several vehicles ahead of you. The car directly in front of you has not braked yet. What should you do?', '["Wait until the car directly in front brakes, then react","Speed up to get past the slowdown before it reaches you","Lift off the gas now and prepare to brake","Change lanes immediately without checking mirrors"]', 2, 'Brake lights down the line are an early warning that traffic is slowing. Easing off the gas now gives you a smoother, safer slowdown than waiting for the car right in front to react.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_speed-and-space-management_reading-traffic-flow_2', 'quiz_speed-and-space-management_reading-traffic-flow', 'A parked car on the side of the road has its front wheels turned toward your lane. What is the safest assumption?', '["The driver is just being lazy about parking","The car is broken down and will not move","The car is about to pull out into traffic","The car is signaling that you should pass on the left"]', 2, 'Turned front wheels usually mean the driver is preparing to merge into the lane. Cover the brake, give extra space, and be ready for them to pull out.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_speed-and-space-management_reading-traffic-flow_3', 'quiz_speed-and-space-management_reading-traffic-flow', 'Which of these is the best way to help other drivers predict what you will do?', '["Signal a moment after you start the lane change","Make sudden speed changes so others notice you","Signal a few seconds early and keep a steady speed and lane position","Straddle lane lines so others can see your car better"]', 2, 'Early signals, steady speed, and clear lane position make your intentions easy to read. Sudden moves and late signals force other drivers to guess, which is when crashes happen.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_speed-and-space-management_reading-traffic-flow_4', 'quiz_speed-and-space-management_reading-traffic-flow', 'Which scanning habit best matches what good drivers actually do?', '["Stare at the car in front and only glance away if something feels wrong","Sweep eyes every couple of seconds between far ahead, near, mirrors, and speedometer","Check the rearview mirror only when you plan to brake","Watch the speedometer continuously to avoid going over the limit"]', 1, 'A regular scan keeps a complete picture of traffic in your head. Locking your eyes on any one spot, including the speedometer, blinds you to what is developing elsewhere.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_speed-and-space-management_speed-and-space-in-tough-conditions', 'module_speed-and-space-management', 'speed-and-space-in-tough-conditions', 'Speed and space in tough conditions', 'Everything you have learned about safe speed and space cushions still applies in bad weather and tricky environments. The difference is that the numbers change. You need more space, more time, and more attention, and you need to slow down before things go wrong, not after.

## Rain

The most dangerous time in the rain is often the first 10 to 15 minutes. Oil, dust, and rubber that have built up on the road float to the surface and make pavement unusually slick. After a heavy rain has been falling for a while, the road actually grips better because the surface has been rinsed off.

Adjustments for rain:

- Increase following distance to at least four seconds, more in heavy rain.
- Turn on your headlights. In most places this is required any time your wipers are on.
- Slow down before puddles. Hitting standing water at speed can cause **hydroplaning**, where your tires ride on top of the water and lose grip.
- If you hydroplane, do not brake hard or jerk the wheel. Ease off the gas, keep the wheel pointed straight, and wait for the tires to grip again.

## Snow and ice

Snow and ice cut your traction dramatically. On packed snow you may have less than half the grip of dry pavement. On ice it can drop to almost nothing.

Adjustments for snow and ice:

- Increase following distance to six seconds or more. On ice, leave even more.
- Accelerate gently. Mashing the gas just spins the tires and loses traction.
- Brake early and softly. Sudden braking causes skids.
- Watch for **black ice**, a thin clear coating that looks like wet pavement. It is most common on bridges, overpasses, shaded curves, and the first cold mornings of the season.
- If you start to skid, look and steer where you want to go. Yanking the wheel the wrong way makes the skid worse.

## Fog

Fog reduces visibility, sometimes to a few car lengths. Your safe speed in fog is whatever lets you stop within the distance you can see.

- Use **low beams**, not high beams. High beams reflect off the fog and make it harder to see.
- Use fog lights if your car has them.
- Increase following distance, because you have less warning of slowdowns.
- If fog gets too thick to drive safely, pull completely off the road into a parking lot or rest area, not just onto the shoulder. Cars parked on the shoulder in fog get hit.

## Night

At night your useful vision shrinks to the area lit by your headlights. Your depth perception and color recognition both get worse.

- Slow down so you can stop within the distance your headlights light up.
- Use high beams on dark roads when there is no oncoming traffic and no car close ahead of you. Switch to low beams when other drivers are nearby.
- Watch for animals at the edges of the road. Eyes reflecting your headlights are a clear warning.
- Keep your windshield clean inside and out. A smeared windshield turns oncoming headlights into a blinding glare.

## Heavy traffic and stop-and-go

In slow, dense traffic the biggest risks are rear-end crashes and lane-change crashes. Tight space and constant speed changes punish anyone who is not paying attention.

- Keep at least one full car length of space ahead, even when stopped. This gives you somewhere to go if you are about to be rear-ended, and lets you pull out if the car ahead breaks down.
- Avoid changing lanes constantly to chase the faster lane. You rarely save real time, and every lane change adds risk.
- Stay off your phone. Crawling traffic is the easiest place to drift into the car in front of you.

## Construction zones

Work zones combine narrower lanes, uneven surfaces, sudden speed drops, and workers near traffic. Fines are usually higher here for a reason.

- Slow down well before the cones start, not at the last second.
- Merge early when a lane is closing ahead. Late merges create dangerous bottlenecks.
- Increase following distance. Workers, equipment, or pavement changes can force the car ahead to brake hard.
- Never assume a work zone is empty just because you do not see workers right at that moment.

## The one rule that ties it all together

When conditions get worse, two things must change: your speed comes down, and your space cushion goes up. Drivers who get into trouble in bad weather are almost always the ones who tried to keep driving the way they would on a clear summer afternoon. Adjust early, adjust visibly, and you will handle conditions that send other drivers into the ditch.', 15, 3
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_speed-and-space-management_speed-and-space-in-tough-conditions', 'lesson_speed-and-space-management_speed-and-space-in-tough-conditions', 'Quiz: Speed and space in tough conditions', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_speed-and-space-management_speed-and-space-in-tough-conditions_0', 'quiz_speed-and-space-management_speed-and-space-in-tough-conditions', 'When is rain most likely to make the road dangerously slick?', '["After it has been raining heavily for an hour","In the first 10 to 15 minutes after rain starts","Only during thunderstorms","Only when the temperature is near freezing"]', 1, 'Oil and dust on the pavement rise to the surface when light rain begins, creating a very slick layer. Heavier, longer rain washes the road cleaner, so grip can actually improve.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_speed-and-space-management_speed-and-space-in-tough-conditions_1', 'quiz_speed-and-space-management_speed-and-space-in-tough-conditions', 'You feel your car start to hydroplane on a wet road. What should you do?', '["Brake firmly and steer hard away from the water","Accelerate to push through the water faster","Ease off the gas, keep the wheel straight, and let the tires regain grip","Yank the parking brake to slow down quickly"]', 2, 'Hard braking or steering during a hydroplane can send the car into a spin. Gently lifting off the gas and keeping the wheel steady lets the tires reconnect with the pavement.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_speed-and-space-management_speed-and-space-in-tough-conditions_2', 'quiz_speed-and-space-management_speed-and-space-in-tough-conditions', 'Which headlights should you use in heavy fog?', '["High beams, so you can see as far as possible","Low beams, with fog lights if available","Hazard flashers only","No lights, because they reflect off the fog"]', 1, 'High beams bounce off the water droplets and create glare that makes seeing worse. Low beams and fog lights point lower and give you better visibility.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_speed-and-space-management_speed-and-space-in-tough-conditions_3', 'quiz_speed-and-space-management_speed-and-space-in-tough-conditions', 'When you are stopped in heavy traffic, about how much space should you leave between your car and the one ahead?', '["Bumper to bumper, to keep cars from cutting in","Just enough to see the rear lights of the car ahead","At least one full car length","About three car lengths, even when stopped"]', 2, 'Leaving about one car length of space gives you room to steer around a stalled car or escape if you are about to be rear-ended. Stopping bumper to bumper takes away every option.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_speed-and-space-management_speed-and-space-in-tough-conditions_4', 'quiz_speed-and-space-management_speed-and-space-in-tough-conditions', 'Where is black ice most likely to form first?', '["On long, flat stretches in direct sun","On bridges, overpasses, and shaded curves","In the middle of busy intersections","Only on gravel roads"]', 1, 'Bridges and overpasses cool from above and below, and shaded spots stay cold longer. These places freeze before the rest of the road and often catch drivers by surprise.', 4
);

-- Module: Night driving
INSERT INTO module (id, courseId, slug, title, description, ordinal) VALUES (
  'module_night-driving', 'course_national_teen_core', 'night-driving', 'Night driving', 'How to drive safely after dark when visibility, depth perception, and other drivers'' alertness all drop.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_night-driving_why-night-driving-is-harder', 'module_night-driving', 'why-night-driving-is-harder', 'Why night driving is harder', 'Driving at night is not just daytime driving with the lights on. Your eyes work differently in the dark, the road gives you less information, and the drivers around you are more likely to be tired or impaired. Most new drivers underestimate how much changes the moment the sun goes down.

## Your eyes lose superpowers after dark

In daylight, your eyes pick up sharp detail, true colors, and accurate distances. After sunset, three things drop fast:

- **Visual acuity.** You can''t read signs or spot hazards as far away. A pedestrian in dark clothing might not be visible until you''re 50 feet from them, even with headlights.
- **Depth perception.** Judging how far away a car is, or how fast it''s closing on you, gets harder. Two headlights in the distance can look closer or farther than they really are.
- **Color vision.** Reds and other warm colors fade first. Brake lights still work, but subtle color cues (like a yellow caution sign in a shadow) are weaker.

Your eyes also need time to adjust. Walking from a bright room into a dark yard, you can''t see for a few seconds. The same thing happens when you leave a well-lit parking lot or pass under bright stadium lights. Plan for that adjustment instead of being surprised by it.

## You see less of the road

Low-beam headlights typically light up the road about 150 to 250 feet ahead. High beams reach roughly 350 to 500 feet. That sounds like a lot, but at highway speeds you cover that distance in just a few seconds. If something appears at the edge of your headlights, you have very little time to react.

This creates a rule of thumb worth memorizing: **don''t outdrive your headlights.** Your stopping distance should fit inside the area your headlights light up. If you can''t stop within what you can see, you''re going too fast for the conditions, even if you''re under the speed limit.

## Other drivers are riskier at night

The road population changes after dark:

- More drivers are tired, especially after 10 p.m. and in the early morning hours.
- More drivers have been drinking or using other substances. Fatal crashes per mile driven are several times higher at night than during the day.
- Pedestrians and cyclists are harder to see and may be wearing dark clothing.
- Animals are more active at dawn and dusk, and many are most active at night.

You can''t control any of that, but you can assume it. Drive like the car coming the other way might drift, and like something might step out from the shoulder. That mindset is not paranoid; it''s realistic.

## Glare is a real hazard, not an annoyance

Bright lights at night briefly blind you. After staring into oncoming high beams, your eyes can take several seconds to recover. During those seconds, you''re effectively driving without seeing.

To reduce glare:

- Keep your windshield clean inside and out. A film of grime scatters light and makes glare worse.
- Dim your dashboard lights. A bright dash makes the road outside look darker.
- Don''t stare at oncoming headlights. Look toward the right edge of your lane and use it to guide you until the car passes.
- Use the night setting on your rearview mirror, or tilt the lever, to cut glare from cars behind you.

## Fatigue sneaks up on you

Your body wants to sleep when it''s dark. Even if you feel fine at the start of a drive, drowsiness builds. Warning signs include heavy eyelids, drifting in your lane, missing exits, or not remembering the last few miles. If any of that happens, pull over somewhere safe and rest, switch drivers, or end the trip. Caffeine and loud music are temporary tricks, not solutions.

## The takeaway

Night driving asks more from you than day driving: more focus, more space, more humility about what you can and can''t see. The drivers who handle it well are the ones who slow down a little, look farther ahead, and stop trusting that everyone else is paying attention.', 12, 0
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_night-driving_why-night-driving-is-harder', 'lesson_night-driving_why-night-driving-is-harder', 'Quiz: Why night driving is harder', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_night-driving_why-night-driving-is-harder_0', 'quiz_night-driving_why-night-driving-is-harder', 'What does "don''t outdrive your headlights" mean?', '["Never use high beams on an unfamiliar road","Keep your speed low enough that you can stop within the distance your headlights light up","Always drive slower than the posted speed limit at night","Turn off your headlights briefly to check how far you can see naturally"]', 1, 'If you can''t stop within the area your headlights illuminate, a hazard at the edge of your light will appear too late to avoid. Speed limits are set for ideal conditions, not for what you personally can see.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_night-driving_why-night-driving-is-harder_1', 'quiz_night-driving_why-night-driving-is-harder', 'Which change to your vision happens after dark?', '["Your peripheral vision becomes sharper than your central vision","Your eyes become more sensitive to the color red","Depth perception and visual acuity both get worse","Your reaction time speeds up to compensate for low light"]', 2, 'In low light, you lose detail and you also have a harder time judging distance and closing speed. Reaction time does not speed up at night.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_night-driving_why-night-driving-is-harder_2', 'quiz_night-driving_why-night-driving-is-harder', 'An oncoming car has very bright headlights. What should you do?', '["Stare at the headlights so your eyes adjust faster","Flash your high beams at the driver until they dim theirs","Close one eye to protect your night vision","Look toward the right edge of your lane and use it as a guide until the car passes"]', 3, 'Looking toward the right edge keeps you in your lane without staring into the glare, which would temporarily blind you. Flashing high beams or closing an eye creates new problems instead of solving this one.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_night-driving_why-night-driving-is-harder_3', 'quiz_night-driving_why-night-driving-is-harder', 'Why are other drivers a bigger risk at night than during the day?', '["Vehicle headlights make most drivers overconfident","More drivers on the road at night are fatigued or impaired","Roads are usually more crowded after sunset","Cars handle worse in cooler nighttime air"]', 1, 'Fatal crash rates per mile are much higher at night largely because more drivers are tired or under the influence. Roads are typically less crowded after dark, not more.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_night-driving_why-night-driving-is-harder_4', 'quiz_night-driving_why-night-driving-is-harder', 'You notice you don''t remember the last few miles you drove and you keep drifting in your lane. What is the right response?', '["Turn up the music and roll down a window to push through","Drink coffee or an energy drink and keep going","Pull over somewhere safe to rest, switch drivers, or end the trip","Speed up slightly so the trip ends sooner"]', 2, 'Those are classic signs of drowsy driving, which is as dangerous as driving impaired. Music and caffeine are short-term tricks, not real fixes. Stopping is the only safe choice.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_night-driving_using-your-lights', 'module_night-driving', 'using-your-lights', 'Using your lights the right way', 'Your headlights do two jobs: they let you see, and they let other people see you. Most new drivers focus on the first job and forget about the second. Knowing which lights to use, and when, is one of the simplest skills that separates a confident night driver from a dangerous one.

## Headlights on means visible

A huge share of vehicles are hit at dusk because the driver waited too long to turn on their lights. By the time you notice it''s hard to see, other drivers have already had trouble seeing you for several minutes.

Good habits:

- Turn on your headlights as soon as the sun starts to set, not when it''s fully dark.
- Turn them on in rain, fog, snow, or any time visibility drops.
- Turn them on at dawn until full daylight.
- If your wipers are on, your headlights should be on too. Many places make this a law, but the safety reason is the same everywhere.

Daytime running lights are not enough at night. They light up the front of your car but usually leave the tail lights dark. From behind, you look like a parked car.

## Low beams: your default

Low beams are aimed down and to the right so they light up the road in front of you without blinding oncoming drivers. They are your default setting for almost every situation: city streets, suburban roads, highways with traffic, and anywhere there are streetlights.

Low beams reach about 150 to 250 feet ahead. That''s enough for moderate speeds but not for high speeds on a dark road.

## High beams: powerful but social

High beams roughly double how far you can see, reaching 350 to 500 feet ahead. They''re meant for dark, open roads where you need that extra range.

Use high beams when:

- You''re on a rural or unlit road with no cars in front of you or coming toward you.
- You''re driving fast enough that low beams don''t give you enough warning.

Switch back to low beams when:

- A car is coming toward you, usually within about 500 feet (when you can clearly see headlights approaching).
- You''re following another car within about 200 to 300 feet. High beams shine straight into their mirrors and blind them.
- You enter a lit area, fog, heavy rain, or snow.

In fog, rain, or snow, high beams actually make things worse. The light bounces off the water or snow in the air and reflects back at you, creating a wall of glare. Low beams cut through better.

If an oncoming driver leaves their high beams on, don''t flash yours back as revenge. You''ll just blind each other. Look toward the right edge of your lane and let them pass.

## Fog lights and auxiliary lights

Some cars have separate fog lights mounted low on the front bumper. They''re aimed low and wide to light up the road surface without reflecting off fog. Use them only in real low-visibility weather, and turn them off afterward. Running fog lights on a clear night is rude and can be illegal in many places because they dazzle other drivers.

## Don''t forget the lights you don''t see

Walk around your car once a week with the lights on and check that everything works:

- Headlights, both low and high beam
- Tail lights
- Brake lights (have someone watch while you press the pedal)
- Turn signals, front and back
- Reverse lights
- License plate light

A burned-out tail light is invisible to you while you''re driving but is a real reason cars get rear-ended at night. Replace bulbs as soon as you notice them out.

Keep your headlight lenses clean. Plastic lenses fog and yellow over time, which can cut your light output in half. A simple restoration kit or a wipe-down helps a lot.

## Inside the car matters too

Dim your dashboard. A bright dash makes the dark road look darker by contrast and tires your eyes faster. Most cars have a dimmer dial or button near the headlight controls.

Don''t drive with the dome light on. It reflects in the windshield and ruins your night vision. If a passenger needs light, pull over.

## The short version

Lights on early, low beams as your default, high beams only when you''re alone on a dark road, and never high beams in fog or close behind another car. Check your bulbs. Keep your lenses clean. Your lights are how the rest of the world finds you in the dark.', 13, 1
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_night-driving_using-your-lights', 'lesson_night-driving_using-your-lights', 'Quiz: Using your lights the right way', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_night-driving_using-your-lights_0', 'quiz_night-driving_using-your-lights', 'You''re driving on a dark rural road with no other cars in sight. Which lights should you use?', '["Low beams only, because they''re safer","High beams, because they let you see much farther","Fog lights, because they reach the farthest","Hazard lights, so animals can see you"]', 1, 'High beams roughly double how far you can see, and a dark empty road is exactly where that extra range matters. You''d switch back to low beams when a car approaches or you catch up to one.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_night-driving_using-your-lights_1', 'quiz_night-driving_using-your-lights', 'Why are high beams a bad choice in fog, heavy rain, or snow?', '["They drain the battery faster in cold weather","They are illegal to use any time it''s raining","Light bounces off the water or snow in the air and creates glare back at you","They overheat the headlight bulbs"]', 2, 'In poor weather, high beams reflect off droplets and flakes and create a wall of glare. Low beams are aimed lower and cut through better.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_night-driving_using-your-lights_2', 'quiz_night-driving_using-your-lights', 'When should you turn on your headlights?', '["Only after it is fully dark outside","As soon as the sun starts to set, or any time visibility drops","Only when you can no longer see the road clearly","Only when other cars near you have theirs on"]', 1, 'By the time it''s fully dark, other drivers have already had a hard time seeing you for several minutes. Turning lights on early is about being visible, not just about your own vision.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_night-driving_using-your-lights_3', 'quiz_night-driving_using-your-lights', 'You''re following another car at night on a two-lane highway. About how close should you be before you switch from high beams to low beams?', '["Within about 200 to 300 feet behind them","Only when you''re directly behind their bumper","Never, since they can''t see your high beams from in front","Only if they flash their brake lights at you"]', 0, 'Your high beams reflect off the car''s mirrors directly into the driver''s eyes. The driver in front can absolutely be blinded by high beams behind them, even though they''re facing away.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_night-driving_using-your-lights_4', 'quiz_night-driving_using-your-lights', 'Why is it a bad idea to drive with bright dashboard lights or the dome light on at night?', '["It drains your headlight power","It signals to other drivers that you''re lost","It makes the road outside look darker and reduces your night vision","It causes your headlights to dim automatically"]', 2, 'Your eyes adjust to the brightest light in view. A bright cabin makes the darker road harder to see and tires your eyes faster, so dim the dash and keep the dome light off while driving.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_night-driving_seeing-and-being-seen', 'module_night-driving', 'seeing-and-being-seen', 'Seeing and being seen', 'Most night-driving crashes come down to one of two failures: the driver didn''t see something in time, or someone else didn''t see the driver in time. This lesson is about closing both of those gaps. The tools are simple: scan farther, scan smarter, and make yourself easy to spot.

## Scan farther ahead than you think

During the day, good drivers look 12 to 15 seconds down the road. At night, you can''t see that far, but you should still push your eyes to the very edge of your headlights and beyond. Don''t just stare at the hood.

Useful habits:

- Look at the farthest spot you can see clearly, then sweep back toward your car.
- Watch the sides of the road, not just the center. Animals, pedestrians, and parked cars live there.
- Watch for movement that isn''t lit. A walker in dark clothes may be a shape that briefly blocks a streetlight or a reflective sign.
- Use other cars'' headlights as scouts. If you see headlights bobbing on a road ahead, the road has hills or bumps. If they swing wide, there''s a curve.

## Use the corners of your eyes

There''s a small spot in the center of each eye that has the most detail but the worst night vision. The edges of your eye are better at picking up motion in low light. That''s why a faint star can look brighter when you don''t look straight at it.

For driving, this means:

- Don''t lock your eyes on one point. Keep them moving.
- If you sense something at the edge of your vision, don''t dismiss it. Glance at it and then glance back to the road.
- Slight side-to-side scanning helps your eyes pick up motion you''d miss with a fixed stare.

## Spotting pedestrians and cyclists

This is one of the deadliest gaps at night. A person in dark clothes on an unlit road can be effectively invisible until you''re very close.

Look for these clues:

- A small bobbing reflection that might be a pedal reflector, shoe stripe, or backpack tag.
- Eyes catching your headlights. Human eyes don''t glow much, but animals'' do.
- A patch of road that looks slightly different from the pavement around it.
- Movement near crosswalks, bus stops, parked cars, and the shoulders of rural roads.

Near schools, parks, and bars, slow down and assume someone is about to step out. Don''t trust that a pedestrian sees you just because your headlights are on. They may be looking at a phone or be impaired.

## Watch for animals

Deer and other animals are most active at dawn, dusk, and through the night. If you see one, expect more. Many animals travel in groups, and a single one crossing the road often has friends right behind it.

If an animal is in your path:

- Brake firmly in a straight line.
- Don''t swerve hard to avoid it. Swerving causes serious crashes with oncoming cars, trees, or rollovers. Hitting a deer is bad; hitting a tree at 50 mph is much worse.
- Use your horn if you have time. A long honk can scare animals out of the road.

## Make yourself easy to see

Being visible is half of safety. Your job isn''t just to see; it''s to be seen.

- Lights on early, every time.
- Keep tail lights, brake lights, and turn signals clean and working. Snow, mud, and dust can hide them.
- Signal earlier than you would in daylight. Other drivers need more time to register what you''re doing.
- Tap your brakes lightly when slowing down on a dark road, even if there''s no one behind you yet. It paints your tail lights brighter for a second.
- If you have to stop on the shoulder, turn on your hazard lights and, if you have them, set out reflective triangles or flares behind your car.

## Keep glass and mirrors clean

A dirty windshield in daylight is annoying. At night, every smear becomes a starburst when headlights hit it. Clean the inside of your windshield too; a thin film of oil from your dashboard builds up over time and causes most of the night glare you blame on the outside.

Check your wiper blades. Streaky wipers turn rain into a light show.

## A simple mindset

At night, assume:

- Pedestrians won''t see you.
- Other drivers are tired.
- Something is about to happen in the dark gap between your headlights and the next streetlight.

That mindset will slow you down a little, make you scan a little harder, and keep your finger ready over the high-beam stalk. That''s most of the job.', 13, 2
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_night-driving_seeing-and-being-seen', 'lesson_night-driving_seeing-and-being-seen', 'Quiz: Seeing and being seen', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_night-driving_seeing-and-being-seen_0', 'quiz_night-driving_seeing-and-being-seen', 'A deer steps into your lane on a two-lane road at night. What is the safest reaction?', '["Swerve hard into the oncoming lane to go around it","Brake firmly in a straight line and stay in your lane","Speed up to pass before it reaches your side of the road","Turn off your headlights so it doesn''t freeze in place"]', 1, 'Swerving causes much worse crashes (oncoming cars, trees, rollovers) than hitting the animal. Braking straight gives you the best chance and keeps the car under control. Turning off your headlights makes everything worse, including for any car behind you.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_night-driving_seeing-and-being-seen_1', 'quiz_night-driving_seeing-and-being-seen', 'Why is it useful to scan with the corners of your eyes at night?', '["Side vision is sharper than central vision at night","The edges of your eye are better at picking up motion in low light","It prevents your eyes from getting dry","Looking sideways turns on a special part of your high beams"]', 1, 'The center of your retina is best for fine detail in daylight, but the edges are better at detecting motion in low light. Slight scanning helps you catch movement you''d miss with a fixed stare.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_night-driving_seeing-and-being-seen_2', 'quiz_night-driving_seeing-and-being-seen', 'You see headlights ahead bobbing up and down on a road you''ve never driven. What is that telling you?', '["The other driver is signaling for help","There''s an animal in the road ahead","The road has hills or significant bumps coming up","Their headlights are misaligned and you can ignore it"]', 2, 'Other cars'' headlights are free scouts. Bobbing means hills or bumps; swinging wide means curves. Reading the road ahead through other vehicles is a key night-driving skill.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_night-driving_seeing-and-being-seen_3', 'quiz_night-driving_seeing-and-being-seen', 'Which habit makes you easier for other drivers to see at night?', '["Signaling later than usual so you don''t confuse anyone","Tapping your brakes lightly when slowing on a dark road","Driving with your interior dome light on","Following closer behind other cars so they shield you from glare"]', 1, 'A brief brake tap flashes your tail lights brighter for a moment, which helps anyone who might come up behind you. Signaling later, dome lights, and tailgating all make things worse.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_night-driving_seeing-and-being-seen_4', 'quiz_night-driving_seeing-and-being-seen', 'Why does cleaning the inside of your windshield matter for night driving?', '["It prevents your defroster from breaking","Outside dirt doesn''t actually cause any glare at night","An oily film builds up inside and turns headlights into starburst glare","It makes your headlights point straighter"]', 2, 'Dashboards and vinyl release oils that slowly coat the inside of the glass. That film scatters oncoming light into starbursts and is the cause of a lot of glare drivers blame on the outside of the windshield.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_night-driving_planning-night-trips', 'module_night-driving', 'planning-night-trips', 'Planning night trips and handling problems', 'Good night driving starts before you turn the key. The trip you plan, the condition of your car, and the choices you make if something goes wrong all matter more after dark than during the day. This lesson is about the parts of night driving that happen outside the moment-to-moment scanning.

## Before you leave

A quick pre-trip routine can prevent most night emergencies.

- **Sleep.** If you''re already tired, don''t start a long night drive. There is no fix for sleep except sleep.
- **Eyes.** If you wear glasses or contacts, wear them. Don''t wear sunglasses at night, even if oncoming lights bother you. Tinted lenses make a dark road dangerously darker.
- **Fuel and charge.** Start with at least half a tank or a healthy battery charge. Running out in the dark on the shoulder is a serious risk.
- **Phone.** Charge it. Have a charger in the car. Tell someone where you''re going and when you expect to arrive on longer trips.
- **Lights and windows.** Quick walk-around: headlights, tail lights, blinkers, brake lights. Clean the windshield inside and out, and clear snow off the whole car if needed, not just a peephole.
- **Climate.** Set the temperature so you stay alert. Too warm makes you sleepy; the defroster keeps the windshield clear.

## Pick a smarter route

The shortest route isn''t always the best one at night.

Consider:

- **Lit roads over dark roads** when the time difference is small. Streetlights help you see pedestrians, animals, and lane lines.
- **Familiar roads over unfamiliar ones.** Surprises are worse at night.
- **Divided highways over narrow two-lane roads.** Most head-on crashes happen on undivided roads, and night is when impaired drivers drift.
- **Avoid bar-close hours when possible.** The hour or two after closing time is the most dangerous time to be on the road.

If your route includes long rural stretches, plan rest stops. Gas stations and rest areas are also your fallback for fatigue.

## Adjust how you drive

Night driving is a different sport played with the same equipment.

- **Slow down.** You don''t have to crawl, but a few miles per hour under the daytime pace gives you more time to react to what your headlights find.
- **Increase your following distance.** A daytime three-second gap should grow to four or more seconds at night. Brake lights are sometimes the only warning you get.
- **Look farther, signal earlier, brake earlier.** Smooth and early beats sudden and late.
- **Take breaks every couple of hours on long trips.** Get out of the car, walk around, splash water on your face.

## If your car breaks down at night

A breakdown after dark is more dangerous than the same breakdown at noon. Other drivers may not see you in time.

Steps:

1. Get off the road. Coast as far onto the shoulder as you can, ideally past a guardrail or onto an exit ramp. The farther from the travel lanes, the better.
2. Turn on your hazard lights as soon as you slow down, so traffic behind you knows.
3. Stay in the car with seatbelts on if you''re close to traffic. Getting out and standing on the shoulder is one of the most dangerous things you can do.
4. If you have reflective triangles or flares, place them behind your car only if it''s safe to walk there.
5. Call for help. Share your location. Modern phones can share a precise location even if you don''t know the road name.
6. If you must leave the car, exit on the side away from traffic.

## Headlights suddenly off or dim

If your headlights die on a dark road:

- Don''t slam the brakes. Cars behind you may not see your brake lights either.
- Try the high beams. Many cars run high beams on a separate circuit, so they may still work.
- Slow gradually, signal, and pull off the road.
- Turn on hazard lights, interior lights, anything that helps others see you.

## If oncoming high beams blind you

This happens to everyone. The right response:

- Slow down. Don''t stop in the lane.
- Look toward the right edge of your lane, not at the lights.
- Once the car passes, give your eyes a few seconds to recover before you assume the road ahead is clear.

## Sharing the road with bigger vehicles

Trucks, buses, and other large vehicles have huge blind spots, and those blind spots are worse at night because they rely on mirrors that catch glare. Pass them quickly when it''s safe, don''t linger beside them, and never cut in closely in front. A loaded truck can need twice as much distance to stop as a car, and at night the driver may see your tail lights late.

## The bottom line

Night driving rewards planning. A rested driver in a clean car with working lights, on a familiar route, who slows down a little and leaves more space, has a calm trip. A tired driver rushing on a dark backroad with one tail light out is the one in the crash report. You get to choose which driver you are before you ever leave the driveway.', 14, 3
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_night-driving_planning-night-trips', 'lesson_night-driving_planning-night-trips', 'Quiz: Planning night trips and handling problems', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_night-driving_planning-night-trips_0', 'quiz_night-driving_planning-night-trips', 'Why shouldn''t you wear sunglasses or tinted glasses while driving at night, even if oncoming headlights bother your eyes?', '["They reflect light back at other drivers and blind them","They make an already-dark road dangerously darker","They cancel out the effect of your headlights","They prevent your high beams from turning on automatically"]', 1, 'Tinted lenses cut the light reaching your eyes, which is the opposite of what you need at night. Clear lenses (or your normal prescription) are the right choice.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_night-driving_planning-night-trips_1', 'quiz_night-driving_planning-night-trips', 'Your car breaks down on the shoulder of a dark highway and you''re close to fast-moving traffic. What is generally the safest thing to do?', '["Get out and stand at the back of the car so drivers see you","Walk along the shoulder toward the nearest exit","Stay in the car with your seatbelt on and your hazard lights on while you call for help","Push the car back onto the road so it''s more visible"]', 2, 'Standing on a shoulder near fast traffic is one of the most dangerous things you can do. Staying belted in the vehicle with hazards on, behind a guardrail if possible, is usually safest until help arrives.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_night-driving_planning-night-trips_2', 'quiz_night-driving_planning-night-trips', 'How should your following distance change at night compared to during the day?', '["Reduce it, because there''s less traffic to deal with","Keep it the same, since the car ahead has brake lights","Increase it, because brake lights may be your only warning and you can see less","Match the distance of the car behind you"]', 2, 'At night you have less visual information and longer reaction time to surprises. A daytime three-second gap should grow to four seconds or more after dark.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_night-driving_planning-night-trips_3', 'quiz_night-driving_planning-night-trips', 'Your headlights suddenly go out on a dark road. What is a smart first move?', '["Slam the brakes immediately to stop as fast as possible","Try the high beams, since they often run on a separate circuit","Turn off the engine to reset the electrical system","Open the driver''s door so other drivers see the interior light"]', 1, 'High beams are often wired separately and may still work. Slamming the brakes risks getting rear-ended (your brake lights may also be out), and shutting off the engine can lock the steering or cut power assist.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_night-driving_planning-night-trips_4', 'quiz_night-driving_planning-night-trips', 'Which route choice is generally safer for a teen new to night driving?', '["A dark, unfamiliar shortcut to save five minutes","A slightly longer route on a familiar, well-lit divided highway","A narrow two-lane road right after bar closing time","Whichever route avoids the most stoplights"]', 1, 'Lit, familiar, divided roads remove the most common night risks: surprises, head-on crashes, and impaired drivers drifting across the center line. A few extra minutes is a small price for that.', 4
);

-- Module: Weather driving
INSERT INTO module (id, courseId, slug, title, description, ordinal) VALUES (
  'module_weather-driving', 'course_national_teen_core', 'weather-driving', 'Weather driving', 'How to read the weather, adjust your driving, and stay in control when rain, snow, ice, fog, or wind change the rules of the road.', 5
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_weather-driving_driving-in-rain', 'module_weather-driving', 'driving-in-rain', 'Driving in rain', 'Rain is the most common bad-weather situation you''ll drive in, and it causes more crashes than most teens expect. Water changes how your tires grip, how far your headlights reach, and how well other drivers can see you. The good news: a few simple habits handle almost every rainy drive.

## Why wet roads are dangerous

Dry pavement gives your tires solid grip. Add water and three things happen:

- Your tires have to push water out of the way to touch the road.
- Stopping distances get longer, often by 30% or more.
- Oil and grime that built up on the road float to the surface, making the first 10-15 minutes of rain the slipperiest part of any storm.

That last point surprises people. A light drizzle on a road that hasn''t seen rain in a week can be more slippery than a steady downpour an hour later.

## Slow down before you need to

The single biggest adjustment is speed. A safe dry-road speed is not a safe wet-road speed. A good rule: drop about 5-10 mph below the posted limit in steady rain, and more in heavy rain. You''re not being slow, you''re matching the road.

Also increase your following distance. In dry weather, aim for a 3-second gap to the car ahead. In rain, stretch that to at least 4-5 seconds. Pick a fixed point like a sign, count when the car ahead passes it, and see how long until you reach it.

## Hydroplaning

Hydroplaning is when your tires ride up on a layer of water instead of touching the road. You lose steering and braking at the same time. It usually happens above about 35 mph in standing water, or at lower speeds if your tires are worn.

If you start to hydroplane:

- Do not slam the brakes.
- Ease off the gas.
- Keep the steering wheel pointed straight ahead.
- Wait for the tires to reconnect, then steer gently.

Prevent it by avoiding puddles, driving in the tracks left by the car ahead (that pavement is drier), and keeping your tires properly inflated with good tread.

## See and be seen

Turn on your headlights any time your wipers are on. In many places it''s the law, and even where it isn''t, it makes you far more visible. Use low beams, not high beams. High beams reflect off the rain and create a wall of glare.

Keep your wipers in good shape. If they smear or chatter, replace them before the next storm, not during it. Defog your windshield using the defroster, not a sleeve, which leaves streaks.

## Watch for water you can''t judge

A puddle that looks shallow can be deep enough to stall your engine or even float a small car. Never drive through moving water across a road. Six inches of moving water can knock you off your feet, and a foot can carry a car away. Turn around and find another way.

After you drive through any deep water, lightly tap your brakes a few times to dry them. Wet brake pads grab unevenly and can pull your car to one side.

## Quick rainy-day checklist

- Headlights on with the wipers.
- Speed down, following distance up.
- No cruise control. Cruise control can keep applying power when you need to be slowing down.
- Both hands on the wheel, smooth inputs only.
- If visibility drops to almost zero, pull off into a safe spot like a parking lot, not the shoulder, and wait it out.', 13, 0
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_weather-driving_driving-in-rain', 'lesson_weather-driving_driving-in-rain', 'Quiz: Driving in rain', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_weather-driving_driving-in-rain_0', 'quiz_weather-driving_driving-in-rain', 'When is a rainy road typically most slippery?', '["After several hours of steady heavy rain","During the first 10-15 minutes of rainfall","Only after the rain has fully stopped","When rain mixes with bright sunlight"]', 1, 'Oil and grime built up on dry pavement float to the surface when rain first starts. Longer rain eventually rinses that film away, making the early part of a storm the slipperiest.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_weather-driving_driving-in-rain_1', 'quiz_weather-driving_driving-in-rain', 'Your car begins to hydroplane on a wet highway. What should you do first?', '["Brake hard to slow down quickly","Steer sharply toward the shoulder","Ease off the gas and keep the wheel straight","Pump the brakes rapidly"]', 2, 'Hard braking or sharp steering during hydroplaning can throw the car into a skid once the tires regrip. Easing off the gas and steering straight lets the tires reconnect with the pavement under control.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_weather-driving_driving-in-rain_2', 'quiz_weather-driving_driving-in-rain', 'Why should you avoid using cruise control in heavy rain?', '["It uses more fuel in wet conditions","It can keep applying power when you need to slow down or recover from a slip","It turns off your headlights automatically","It disables the windshield wipers"]', 1, 'Cruise control is built to maintain speed, not respond to slick pavement. If a tire loses grip, the system can keep adding throttle exactly when you need to ease off.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_weather-driving_driving-in-rain_3', 'quiz_weather-driving_driving-in-rain', 'You approach a stretch of road covered by moving water. What''s the safest choice?', '["Drive through slowly in a low gear","Speed up to push through the water quickly","Follow closely behind a larger vehicle through it","Turn around and find another route"]', 3, 'Moving water hides depth and current. Even a foot of moving water can sweep a car off the road, so the only safe move is to avoid it entirely.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_weather-driving_driving-in-rain_4', 'quiz_weather-driving_driving-in-rain', 'Why should you use low beams instead of high beams in heavy rain?', '["High beams drain the battery faster in wet weather","Low beams light up the road farther ahead","High beams reflect off the rain and create glare that hurts visibility","Low beams are required by federal law in all weather"]', 2, 'High beams bounce off raindrops and create a bright wall in front of you, which actually reduces how far you can see. Low beams aim down and stay under most of that reflection.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_weather-driving_snow-and-ice', 'module_weather-driving', 'snow-and-ice', 'Snow and ice', 'Snow and ice are the conditions where small mistakes become big crashes. The physics are simple: less grip means less steering, less braking, and less control. Driving well in winter is mostly about being gentle, patient, and looking far ahead.

## Prep before you go

A safe winter drive starts before you turn the key.

- Clear all snow off the car, not just a peephole on the windshield. Brush off the roof too. Snow flying off your roof can blind the driver behind you.
- Clear headlights, taillights, mirrors, and the back window completely.
- Check that your wipers, defroster, and heater all work before you need them.
- Keep at least half a tank of gas. It helps in traffic jams and prevents fuel-line problems in cold snaps.
- Carry a basic kit: ice scraper, gloves, a blanket, a phone charger, and some snacks for long trips.

Tires matter more than anything else. If you drive often in heavy snow, dedicated winter tires grip dramatically better than all-season tires. Bald or worn tires turn even a light snow into a serious problem.

## Drive smoothly

The golden rule on snow and ice: every input has to be smooth. Sudden gas, sudden braking, and sudden steering are the three things that break traction.

- Accelerate gently. If your wheels spin, ease off until they grip.
- Brake early and gradually. Look way ahead so you have time.
- Steer with small movements. Big corrections cause skids.

Following distance should be much longer than usual. Try 8-10 seconds behind the car ahead. You''ll need it.

## Black ice

Black ice is a thin, clear layer of ice that looks like wet pavement. It forms most often:

- On bridges and overpasses, which freeze first because cold air surrounds them.
- In shaded spots under trees or between tall buildings.
- Early in the morning or late at night when temperatures drop near freezing.

If the road looks shiny but other cars aren''t kicking up spray, suspect ice. When you hit it, do nothing dramatic. Don''t brake, don''t steer hard. Ease off the gas and let the car coast across.

## If you start to skid

There are two main kinds:

- **Rear-wheel skid (fishtail):** The back of the car slides out. Look where you want to go and steer gently in that direction. Don''t overcorrect, or the car will whip the other way.
- **Front-wheel skid (understeer):** The car keeps going straight when you turn the wheel. Ease off the gas, don''t add more steering. As the tires slow down, they''ll regrip and you can steer again.

In both cases, sudden braking makes things worse. Modern cars with anti-lock brakes will let you press the pedal firmly without locking up, but smooth pressure still beats panic.

## Stopping takes much longer

On packed snow, stopping distance can double. On ice, it can be 10 times longer than on dry pavement. That''s why looking far ahead matters so much. The earlier you see a red light, a stopped car, or a turn, the earlier you can start slowing down.

Approach intersections expecting that you might slide. Brake well before the line. If you''re not sure you can stop, start braking sooner, not harder.

## Hills, bridges, and ramps

- Going uphill, build a little momentum before the climb. Don''t try to power up a slick hill, your wheels will just spin.
- Going downhill, slow down before you start descending. Use a lower gear if your car has one so the engine helps slow you.
- Treat every bridge and overpass as if it''s iced over, even when other roads look fine.

## When to just not go

The smartest winter driving skill is knowing when to stay home. If a storm warning is active, roads are unplowed, or you don''t have to be somewhere, wait. No errand is worth a crash. If you''re already out and conditions get bad, find a safe place to park and wait it out.', 15, 1
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_weather-driving_snow-and-ice', 'lesson_weather-driving_snow-and-ice', 'Quiz: Snow and ice', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_weather-driving_snow-and-ice_0', 'quiz_weather-driving_snow-and-ice', 'Why is it important to clear snow off your entire car, including the roof?', '["Snow on the roof adds dangerous weight to the vehicle","Snow can blow off and blind drivers behind you","It causes the car battery to drain faster","It prevents your heater from working"]', 1, 'Snow sliding off your roof at speed can hit the windshield of the car behind you and completely block their view. Clearing all surfaces protects other drivers, not just you.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_weather-driving_snow-and-ice_1', 'quiz_weather-driving_snow-and-ice', 'You feel your car hit a patch of black ice on a bridge. What should you do?', '["Brake firmly to stop before the ice ends","Steer hard to one side to find better traction","Ease off the gas and let the car coast straight","Accelerate to get across faster"]', 2, 'Black ice gives almost no grip, so any sudden input causes a skid. Easing off the gas and holding the wheel steady lets the car glide across with the least risk.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_weather-driving_snow-and-ice_2', 'quiz_weather-driving_snow-and-ice', 'Your rear wheels start to slide to the right (a fishtail). What''s the correct response?', '["Brake hard and steer left","Look and steer gently to the right, where you want to go","Turn the wheel sharply to the left to counter the slide","Take your hands off the wheel and let the car correct itself"]', 1, 'In a rear-wheel skid you steer gently in the direction the back is sliding, which is also the direction you want the car to go. Overcorrecting or braking hard usually makes the skid worse.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_weather-driving_snow-and-ice_3', 'quiz_weather-driving_snow-and-ice', 'Which spots are most likely to ice over first when temperatures drop?', '["Long flat stretches of highway","Sunny south-facing streets","Bridges, overpasses, and shaded areas","Roads that have been recently salted"]', 2, 'Bridges and overpasses have cold air below and above them, so they lose heat faster than regular roads. Shaded spots never warm up enough to melt early frost, so they ice first.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_weather-driving_snow-and-ice_4', 'quiz_weather-driving_snow-and-ice', 'About how much longer can stopping distance be on icy pavement compared to dry pavement?', '["About the same","Roughly 25% longer","Roughly twice as long","Up to about 10 times as long"]', 3, 'Ice gives tires very little friction, and stopping distance can stretch to roughly 10 times what it would be on dry pavement. That''s why looking far ahead and braking early is critical in winter.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_weather-driving_fog-and-low-visibility', 'module_weather-driving', 'fog-and-low-visibility', 'Fog and low visibility', 'Fog turns familiar roads into mystery roads. You can''t see far, you can''t judge speed well, and other cars appear out of nowhere. Heavy fog causes some of the worst chain-reaction crashes on highways, often with dozens of vehicles involved. The way you survive fog is to slow down, light up smartly, and resist the urge to follow other cars too closely.

## Why fog is so dangerous

Fog is just a cloud at ground level. It scatters light, hides distance, and tricks your brain. Three specific problems:

- **You can''t see far enough to react.** At highway speeds, you may need 300 feet or more to stop. In thick fog, you might see only 100 feet.
- **Speed feels slower than it is.** Without clear reference points whipping past, 50 mph can feel like 30. People drive faster than they think.
- **Other drivers may panic.** Some slam on brakes. Some stop in the road. Some don''t have lights on at all.

## Use the right lights

This is where many drivers get it wrong. In fog:

- Turn on your low beams, not high beams. High beams reflect off the fog and make a bright wall right in front of you.
- If your car has fog lights, use them. They aim low and wide, under the fog layer.
- Daytime running lights are not enough. They often don''t turn on your taillights, which is what cars behind you need to see.
- Never drive with only parking lights. Use full headlights even in daytime fog.

## Slow down dramatically

Match your speed to what you can see. The simple rule: you should be able to stop within the distance your headlights show you. If visibility is half a block, you should be driving slow enough to stop in half a block.

Don''t trust the posted speed limit in fog. The limit assumes clear conditions. Foggy conditions ask you to choose a slower speed yourself.

## Don''t tailgate the lights ahead

It''s tempting to find another car''s taillights and follow them through the fog. Don''t. If they brake suddenly or stop, you''ll hit them. Worse, they might be lost, drifting between lanes, or following someone else who is.

Leave extra following distance, even though it makes you feel more alone. Aim for at least double your normal gap.

## Use the road, not the center line

Looking at the white line on the right edge of the road is usually better than staring at the dashed center line. Two reasons:

- The right-edge line keeps you out of oncoming traffic.
- Looking left toward oncoming headlights can dazzle you and make it harder to see anything else.

Keep your eyes moving and avoid fixating on any single light source.

## Other low-visibility situations

Fog isn''t the only thing that drops your sight distance. You''ll face the same challenge in:

- **Heavy rain or snow squalls** that hide the road ahead.
- **Smoke** from wildfires or controlled burns.
- **Dust storms** in dry, windy areas.
- **Sun glare** at sunrise and sunset, especially when driving east in the morning or west in the evening.

For sun glare, use your visor, wear polarized sunglasses, and keep your windshield clean inside and out. A dirty windshield turns sun glare into total whiteout.

## If it gets too bad to drive

Sometimes the right answer is to stop. But how you stop matters:

- Do not stop in the travel lane. Cars behind you can''t see you in time.
- Do not stop on the shoulder if you can avoid it. Other drivers sometimes drift toward taillights they see in the fog and hit parked cars.
- The safest option is to pull completely off the road into a parking lot, gas station, or rest area. Turn off your lights, including taillights, so other drivers don''t follow them off the road. Wait until visibility improves.', 11, 2
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_weather-driving_fog-and-low-visibility', 'lesson_weather-driving_fog-and-low-visibility', 'Quiz: Fog and low visibility', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_weather-driving_fog-and-low-visibility_0', 'quiz_weather-driving_fog-and-low-visibility', 'Which lights should you use when driving in heavy fog?', '["High beams, to see as far as possible","Low beams, plus fog lights if your car has them","Just parking lights, to avoid glare","Hazard lights at all times while moving"]', 1, 'High beams reflect off the fog and create blinding glare. Low beams, sometimes paired with fog lights aimed under the fog, give you the most usable light without bouncing it back at you.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_weather-driving_fog-and-low-visibility_1', 'quiz_weather-driving_fog-and-low-visibility', 'What''s the basic rule for choosing a safe speed in fog?', '["Drive 5 mph under the speed limit","Match the speed of the car ahead of you","Drive slow enough to stop within the distance your headlights show","Use cruise control set to the posted limit"]', 2, 'If you can''t stop within the distance you can see, you''re going too fast. Posted limits assume clear conditions, so fog requires you to pick your own safer speed.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_weather-driving_fog-and-low-visibility_2', 'quiz_weather-driving_fog-and-low-visibility', 'Why is it risky to follow another car''s taillights closely through fog?', '["Their taillights might burn out your headlights","Their lights make it harder for you to see lane lines","They might brake or stop suddenly and you won''t have time to react","It''s illegal to follow another car in fog"]', 2, 'If the car ahead stops abruptly or is itself lost, you''ll rear-end them before you can react. A wider gap and your own focus on the road is much safer than chasing taillights.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_weather-driving_fog-and-low-visibility_3', 'quiz_weather-driving_fog-and-low-visibility', 'When fog is so thick you decide you can''t safely keep driving, what should you do?', '["Stop in the right travel lane with hazards on","Pull onto the shoulder and leave your headlights on","Pull completely off the road into a parking lot and turn your lights off","Continue at 5 mph until the fog clears"]', 2, 'Stopping in a lane or on the shoulder invites a rear-end crash, because confused drivers sometimes steer toward any lights they see. Getting fully off the road and going dark removes that target.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_weather-driving_fog-and-low-visibility_4', 'quiz_weather-driving_fog-and-low-visibility', 'Why do drivers often go faster than they realize in fog?', '["Engines run more efficiently in cool, damp air","Without clear visual reference points, speed feels slower than it actually is","Fog blocks the speedometer from updating","Tire grip improves on wet pavement"]', 1, 'Your sense of speed comes partly from watching things rush past you. Fog removes those reference points, so 50 mph can feel like a relaxed 30, which is why glancing at the speedometer matters in fog.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_weather-driving_wind-and-extreme-weather', 'module_weather-driving', 'wind-and-extreme-weather', 'Wind and extreme weather', 'Wind doesn''t get the same respect as snow or rain, but it can shove your car across a lane, flip trailers, and turn debris into projectiles. Extreme weather like thunderstorms, hail, heat waves, and severe wind events also bring problems most new drivers haven''t thought about. This lesson covers how to handle the conditions that show up suddenly and how to spot when it''s time to get off the road.

## Driving in strong wind

Wind affects your car in three main ways:

- **Steady crosswinds** push the car sideways, especially on bridges and open highways.
- **Gusts** hit suddenly and can jerk the wheel out of a loose grip.
- **Wind from passing trucks** creates a sudden push and then a pull as the truck passes you.

To handle it:

- Keep both hands firmly on the wheel.
- Slow down. Lower speeds give you more time to correct.
- Anticipate where wind will hit hardest: bridges, overpasses, gaps between buildings, tunnel exits, and open stretches with no trees.
- Give large vehicles extra room. High-profile trucks, RVs, and trailers can be blown into your lane.

If you drive an SUV, pickup, or anything tall, you''re more affected by wind than a low sedan. That doesn''t mean don''t drive, it just means stay alert and slow down sooner.

## Watch for blown debris

Strong wind throws things into the road: branches, trash cans, tarps, even sheet metal off truck loads. Scan farther ahead than usual. If something is in your lane, brake straight ahead rather than swerving when possible. A controlled hit at low speed is often safer than a loss of control at high speed.

Be especially careful behind trucks carrying loose cargo. Drop back. If something flies off, you want time and space.

## Thunderstorms

Thunderstorms combine several hazards: heavy rain, wind gusts, lightning, and sometimes hail. The biggest mistakes drivers make:

- Driving into water across the road because the storm makes it hard to judge depth.
- Stopping under highway overpasses to shelter. This blocks lanes and creates pileups. It also doesn''t protect you from lightning or tornadoes.
- Continuing to drive when visibility drops to almost nothing.

If a storm gets severe, exit the highway and find real shelter, a gas station, a store, anywhere with a solid roof. Stay in your car if you can''t reach a building, but never under an overpass.

Lightning is rarely a direct threat inside a car. The metal shell carries the charge around you. Just don''t touch metal parts of the interior during a strike, and avoid stopping under tall isolated trees.

## Hail

Hail can crack windshields and dent body panels. If you get caught in a hailstorm:

- Slow down. Don''t slam the brakes.
- If safe, pull under cover like a gas station canopy, an overpass exit ramp shoulder well away from traffic, or a parking garage.
- Face away from the hail if you can, since the windshield is stronger than side windows.
- Stay in the car. The roof protects you.

## Extreme heat

Heat doesn''t make the road slippery, but it stresses your car and your judgment.

- Tires can blow out more easily when pavement is very hot, especially if they''re underinflated.
- Engines can overheat, especially in slow traffic.
- Cabin temperatures climb fast. Never leave a child or pet in a parked car, even with windows cracked. It can become deadly in minutes.
- Stay hydrated. Drowsiness from heat affects your reaction time.

If your engine starts to overheat, turn off the air conditioning, turn the heater on full (it pulls heat from the engine), and pull over as soon as it''s safe.

## Severe weather warnings

If you hear a tornado warning or severe thunderstorm warning while driving:

- Get off the road and into a solid building if you can.
- Do not try to outrun a tornado in a car. Tornadoes change direction and move fast.
- If no shelter exists and the tornado is approaching, leave the car and lie flat in a ditch or low spot, covering your head. A car is one of the worst places to be in a tornado.

The overall theme of severe weather: your trip is never as important as your safety. Pulling over, turning around, or waiting an hour costs nothing compared to a crash.', 12, 3
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_weather-driving_wind-and-extreme-weather', 'lesson_weather-driving_wind-and-extreme-weather', 'Quiz: Wind and extreme weather', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_weather-driving_wind-and-extreme-weather_0', 'quiz_weather-driving_wind-and-extreme-weather', 'Where are crosswinds most likely to push your car hardest?', '["On streets lined with tall buildings on both sides","On bridges, overpasses, and open stretches with no trees","On winding roads through dense forest","In tunnels"]', 1, 'Bridges, overpasses, and open country let wind hit your car broadside with nothing to block it. Buildings and trees act as natural windbreaks, so wind effects are usually milder there.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_weather-driving_wind-and-extreme-weather_1', 'quiz_weather-driving_wind-and-extreme-weather', 'An object suddenly blows into your lane on the highway. What''s usually the safest reaction?', '["Swerve hard into the next lane to miss it","Brake straight ahead and try to stop or hit it slower under control","Speed up to clear it before it lands","Close your eyes briefly and hope it misses"]', 1, 'Swerving at high speed can cause a rollover or a crash with another car. A controlled, straight-line brake at a lower speed is usually safer than a panic swerve, especially with smaller debris.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_weather-driving_wind-and-extreme-weather_2', 'quiz_weather-driving_wind-and-extreme-weather', 'During a severe thunderstorm on the highway, why should you NOT stop under an overpass for shelter?', '["Overpasses attract lightning more than open road","It''s not actually faster than driving home","It blocks lanes, causes pileups, and offers no real protection from wind or tornadoes","The concrete reflects sound and damages hearing"]', 2, 'Stopping under an overpass creates traffic hazards for cars behind you and doesn''t shield you from severe weather. A solid building like a gas station or store is much safer.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_weather-driving_wind-and-extreme-weather_3', 'quiz_weather-driving_wind-and-extreme-weather', 'Your car''s engine temperature gauge starts climbing toward the red zone in hot weather. What should you do?', '["Turn the air conditioning to maximum to cool the engine","Turn off the AC, turn the heater on full, and pull over as soon as it''s safe","Speed up so airflow cools the engine faster","Pour water from a bottle onto the hood"]', 1, 'The heater actually pulls heat off the engine and into the cabin, which helps cool it. Running the AC adds load and makes overheating worse, so turn it off and stop somewhere safe.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_weather-driving_wind-and-extreme-weather_4', 'quiz_weather-driving_wind-and-extreme-weather', 'A tornado is approaching and there''s no building nearby for shelter. What''s the recommended action?', '["Stay buckled in the car with the engine running","Drive as fast as possible in the opposite direction","Park under an overpass and hide on the embankment","Leave the car and lie flat in a ditch or low spot, covering your head"]', 3, 'Cars are easily lifted and tossed by tornadoes, and overpasses can actually channel wind faster. A low spot in the ground keeps you below the strongest winds and flying debris.', 4
);

-- Module: Impairment and distraction
INSERT INTO module (id, courseId, slug, title, description, ordinal) VALUES (
  'module_impairment-and-distraction', 'course_national_teen_core', 'impairment-and-distraction', 'Impairment and distraction', 'How fatigue, alcohol, drugs, and distraction wreck your driving, and concrete plans to refuse to drive impaired or distracted.', 6
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_impairment-and-distraction_why-impairment-changes-the-driver-you-are', 'module_impairment-and-distraction', 'why-impairment-changes-the-driver-you-are', 'Why impairment changes the driver you are', 'Driving is a constant stream of small decisions: how hard to brake, when to look left, whether that cyclist is about to swerve. You make hundreds of these every mile without noticing. Impairment is anything that slows those decisions down, makes them wrong, or convinces you they''re fine when they aren''t.

## The three things impairment attacks

Almost every impairment problem comes down to damage in one or more of these:

- **Reaction time.** How long between seeing a problem and your foot moving. Sober, alert drivers take about three quarters of a second. Tired or impaired, that can double or triple. At 45 mph, an extra second is another 66 feet of car traveling toward whatever scared you.
- **Judgment.** Picking the right move. An impaired brain underestimates risk, overestimates skill, and stops planning more than one step ahead.
- **Attention.** Holding several things in your head at once: the car ahead, the light changing, the kid on the curb, the speedometer. Impairment narrows your focus to one thing at a time, often the wrong thing.

A driver who is a little slower, a little worse at judging gaps, and a little less able to track everything at once is not a slightly worse driver. They are a significantly more dangerous one, because driving safely depends on all three working together.

## Why impaired drivers don''t feel impaired

The same systems that drive a car well are the ones that notice when something is wrong with you. When those systems are degraded, the warning light goes out at the same time the engine starts failing. This is why people who are clearly impaired say they feel "fine to drive." They aren''t lying. Their brain genuinely can''t tell.

Two consequences:

- You can''t trust your own "I''m good" feeling once anything has changed your brain chemistry or sleep state.
- You have to decide ahead of time, while sober and rested, what counts as not driving. The decision has to be made before the moment of getting behind the wheel.

## What impairment actually looks like behind the wheel

Impaired driving is rarely the dramatic swerving you see in movies. It''s quieter and more common:

- Drifting a few inches inside the lane, then overcorrecting.
- Braking later than you meant to, again and again.
- Missing a turn you''ve made a hundred times.
- Following too close because you didn''t notice the gap shrinking.
- Running a yellow that you would have stopped for any other day.

Any one of these can be the moment somebody on a bike or in a crosswalk gets hit.

## The categories we''ll cover

The rest of this module breaks impairment into four pieces that all hit the same three targets (reaction, judgment, attention):

- **Fatigue.** Sleep loss and drowsy driving. Legal, common, badly underestimated.
- **Alcohol.** What it does to your brain and body, and why "a little" still matters for a new driver.
- **Other drugs.** Cannabis, prescriptions, over-the-counter meds, and combinations. None of them make you a better driver.
- **Distraction.** Phones, passengers, food, the radio, your own thoughts. Distraction is impairment you choose in the moment.

## Your job as a new driver

You are not yet a driver who can absorb a little extra risk. You don''t have the years of pattern recognition that let experienced drivers catch their own small mistakes. Anything that makes you slower, less attentive, or less honest with yourself stacks on top of being new. That is the gap that gets new drivers killed and gets other people killed by new drivers.

The goal of this module is not to scare you. It''s to give you:

- A clear picture of what each kind of impairment does to you.
- A pre-decided plan for what you do instead of driving when you''re not fit to.
- Words you can use, in the moment, to refuse a ride or tell a passenger to stop.

The choice to not drive impaired is almost never made in the car. It''s made when you decide who''s driving home before you leave, when you set your phone down before you start the engine, and when you decide that being late or inconvenient is better than being the reason something terrible happened.', 12, 0
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_impairment-and-distraction_why-impairment-changes-the-driver-you-are', 'lesson_impairment-and-distraction_why-impairment-changes-the-driver-you-are', 'Quiz: Why impairment changes the driver you are', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_impairment-and-distraction_why-impairment-changes-the-driver-you-are_0', 'quiz_impairment-and-distraction_why-impairment-changes-the-driver-you-are', 'What are the three core abilities that almost all impairment damages?', '["Steering, braking, and signaling","Reaction time, judgment, and attention","Vision, hearing, and balance","Speed, lane position, and following distance"]', 1, 'Impairment of any kind tends to attack reaction time, judgment, and attention at the same time. Steering and braking get worse as a result, but they''re symptoms, not the root.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_impairment-and-distraction_why-impairment-changes-the-driver-you-are_1', 'quiz_impairment-and-distraction_why-impairment-changes-the-driver-you-are', 'Why is it dangerous to rely on whether you ''feel okay to drive'' after something has affected your brain?', '["Most people are too embarrassed to admit they feel bad","The same brain systems that notice impairment are themselves impaired","Feelings are always less accurate than thoughts","You usually only feel impairment after the drive is over"]', 1, 'The brain regions that judge whether you''re fit to drive are the same ones being slowed down. When they''re degraded, the internal warning system goes quiet at the worst possible time.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_impairment-and-distraction_why-impairment-changes-the-driver-you-are_2', 'quiz_impairment-and-distraction_why-impairment-changes-the-driver-you-are', 'At 45 mph, roughly how much extra distance does your car cover during one extra second of reaction time?', '["About 10 feet","About 25 feet","About 66 feet","About 200 feet"]', 2, 'At 45 mph you''re moving about 66 feet per second. Every extra second of delay is another car length and a half of road covered before you even start to brake.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_impairment-and-distraction_why-impairment-changes-the-driver-you-are_3', 'quiz_impairment-and-distraction_why-impairment-changes-the-driver-you-are', 'Which of these is the most common real-world sign of an impaired driver?', '["Driving on the wrong side of the road","Subtle drifting, late braking, and missed details","Sleeping at the wheel for long stretches","Driving extremely fast in a straight line"]', 1, 'Impaired driving is usually quiet: small lane drifts, late brake inputs, and missed cues. Dramatic behavior happens, but the everyday version is what causes most crashes.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_impairment-and-distraction_why-impairment-changes-the-driver-you-are_4', 'quiz_impairment-and-distraction_why-impairment-changes-the-driver-you-are', 'Why does impairment hit new drivers especially hard?', '["New drivers have slower reflexes than adults","New cars are harder to control than older ones","New drivers don''t yet have the experience to catch their own small mistakes","New drivers are legally held to looser standards"]', 2, 'Experienced drivers have years of pattern recognition that lets them notice and correct small errors. New drivers haven''t built that yet, so any added impairment stacks on top of inexperience.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_impairment-and-distraction_drowsy-driving-and-fatigue', 'module_impairment-and-distraction', 'drowsy-driving-and-fatigue', 'Drowsy driving and fatigue', 'Tired driving doesn''t feel like impaired driving. It feels normal, then boring, then suddenly you can''t remember the last mile. That''s not a quirk. That''s your brain switching off in pieces while the car keeps going.

## What sleep loss actually does

Going without enough sleep doesn''t just make you yawn. It produces effects measurably similar to alcohol:

- Slower reaction time.
- Worse judgment, especially about your own state.
- Narrowed attention; you stop scanning and start staring.
- **Microsleeps**: brief lapses where your brain goes offline for one to several seconds while your eyes may stay open.

A microsleep of four seconds at highway speed means your car traveled the length of a basketball court with no one in charge of it.

## You can''t push through it

The popular fixes don''t really work:

- **Rolling down the windows** wakes you for a minute, then you adjust.
- **Loud music** does the same thing.
- **Caffeine** helps, but takes 20 to 30 minutes to kick in and wears off unevenly. It can''t replace sleep, only delay the crash.
- **"Just five more miles"** is the most dangerous thought a tired driver has, because the brain making that decision is the one that''s failing.

The only real fix for sleepiness is sleep.

## When you are at highest risk

Drowsy crashes cluster in predictable windows:

- **Late night and early morning** (roughly midnight to 6 a.m.), when your body wants to be asleep no matter how much you slept earlier.
- **Early afternoon**, when there''s a natural dip in alertness.
- **After a long day** of school, sports, or work, even if you don''t feel obviously tired.
- **On long, monotonous drives**, especially highways with little to look at.
- **After missing even one night** of normal sleep. You don''t have to be up for 24 hours to be dangerous.

New drivers are especially exposed because your schedule probably includes early school mornings, late practices or jobs, and weekends with late nights and early commitments. The math of teenage life adds up to chronic short sleep.

## Warning signs you should not ignore

If any of these happen while you''re driving, you are already too tired to be driving safely:

- Heavy or burning eyelids.
- Frequent yawning that you can''t control.
- Drifting within your lane, or hitting a rumble strip.
- Missing an exit or turn you knew was coming.
- Realizing you don''t remember the last few minutes of driving.
- Repeatedly losing track of your speed.

These are not signs to push harder. They are signs to get off the road.

## What to do instead

A real plan for fatigue is built before you''re tired:

- **Treat sleep as part of the trip.** If you know you have a long drive tomorrow, your bedtime tonight is part of the drive.
- **Don''t start a long drive after a full day.** Driving home after a 12-hour day is one of the highest-risk things you can do.
- **Take a real break, not a fake one.** A 20-minute nap in a safe parking spot beats two more coffees.
- **Bring someone.** A passenger who is also awake can help you stay alert and call out drift. A passenger who is asleep does not count.
- **Pull over the moment you feel any warning sign.** Find a safe, lit place. Lock the doors. Set an alarm. Nap.
- **Call for a ride.** A late ride from a parent or friend is always cheaper than a crash. Decide in advance that this is allowed.

## Saying no to a tired drive

A lot of teen driving fatigue comes from social pressure: late events, sleepovers, working a closing shift, then someone asks you to drive. You''re allowed to say no. Some lines that work:

- "I''m too tired to be safe right now. Can someone else drive, or can we wait?"
- "I''m going to nap for 20 minutes before I head out."
- "I can pick you up, but not until I''ve slept."

If you''re the passenger and the driver looks wrecked, you''re allowed to say no too. "You look exhausted. I''d rather get a ride or wait" is a complete sentence. Sleeping in the passenger seat while someone else fights to stay awake is not a plan, it''s a gamble.

The rule is simple: if your body is trying to sleep, do not be the one driving the car.', 13, 1
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_impairment-and-distraction_drowsy-driving-and-fatigue', 'lesson_impairment-and-distraction_drowsy-driving-and-fatigue', 'Quiz: Drowsy driving and fatigue', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_impairment-and-distraction_drowsy-driving-and-fatigue_0', 'quiz_impairment-and-distraction_drowsy-driving-and-fatigue', 'What is a microsleep?', '["A short period of light, refreshing rest","A brief lapse where the brain goes offline for seconds, even with eyes open","The drowsiness right before falling asleep at night","A medical condition only certain people get"]', 1, 'Microsleeps are involuntary brain shutoffs lasting a few seconds. Your eyes can stay open, but no one is processing the road, which is why they''re so dangerous at speed.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_impairment-and-distraction_drowsy-driving-and-fatigue_1', 'quiz_impairment-and-distraction_drowsy-driving-and-fatigue', 'Which of these is the only real fix for driving sleepiness?', '["Loud music","Cold air through open windows","Sleep","Energy drinks"]', 2, 'Cold air, music, and caffeine can buy a few minutes at most. Only sleep actually restores reaction time, judgment, and attention.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_impairment-and-distraction_drowsy-driving-and-fatigue_2', 'quiz_impairment-and-distraction_drowsy-driving-and-fatigue', 'You''re driving home after a long day and realize you don''t remember the last few minutes of the road. What should you do?', '["Speed up to get home faster","Roll down the windows and keep going","Pull over somewhere safe and either nap or call for a ride","Switch lanes to stay more engaged"]', 2, 'Losing track of the last few minutes is a sign you''ve already had microsleeps. The only safe move is to stop driving and either sleep or get a ride.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_impairment-and-distraction_drowsy-driving-and-fatigue_3', 'quiz_impairment-and-distraction_drowsy-driving-and-fatigue', 'Why is caffeine an unreliable defense against drowsy driving?', '["It always makes drivers more anxious","It takes 20 to 30 minutes to work and only delays the crash","It only works for adults","It causes microsleeps directly"]', 1, 'Caffeine has a delay before it kicks in and only masks sleep pressure temporarily. It can''t replace sleep, and when it wears off you can crash hard.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_impairment-and-distraction_drowsy-driving-and-fatigue_4', 'quiz_impairment-and-distraction_drowsy-driving-and-fatigue', 'A friend who has been awake since 5 a.m. and worked a closing shift offers to drive you home at 1 a.m. What''s the best response?', '["Get in; they know their limits better than you do","Offer to keep them talking so they stay alert","Suggest someone else drive, take a rideshare, or wait until they''ve rested","Let them drive but make sure they drink a soda first"]', 2, 'A driver in that state is severely impaired by fatigue. Talking and caffeine don''t fix it; getting a different driver or waiting until they''ve slept does.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_impairment-and-distraction_alcohol-and-other-drugs', 'module_impairment-and-distraction', 'alcohol-and-other-drugs', 'Alcohol and other drugs', 'Alcohol and other drugs change the chemistry of your brain. Driving is a brain task. There is no version of "a little" that leaves your driving untouched. This lesson is about what these substances actually do to you behind the wheel, and how to build a plan so you never have to make the impaired-or-not decision in a parking lot at midnight.

## What alcohol does to a driver

Alcohol is a depressant. It slows down the parts of your brain that handle:

- **Reaction time.** Even small amounts measurably slow how fast you respond to a brake light.
- **Coordination.** Steering smoothly, braking the right amount, keeping a steady lane.
- **Tracking objects.** Your eyes have a harder time following a moving target, like a kid on a bike or a car merging.
- **Judgment.** This is the cruel part: alcohol impairs the brain''s ability to notice it''s impaired. The drunker you are, the more confident you feel.
- **Multitasking.** Driving is constant multitasking. Alcohol makes it harder to do two things at once, exactly when you most need to.

For a brand-new driver, even amounts that wouldn''t legally count as "drunk" for an adult are enough to wreck the margin you''d otherwise have to catch a mistake.

## Why "buzzed" still counts

People tend to picture impaired driving as someone obviously drunk. The reality is that crashes happen at low levels too:

- A driver who is just "buzzed" still has slower reactions and worse judgment than a sober driver.
- They are also more likely to take a risk they''d normally skip: a yellow light, a faster lane change, a shorter following distance.
- They are far more likely to drive at all, because the same alcohol that slowed their brain also convinced them they''re fine.

For a new driver, the safe number is zero. Not because of any specific rule, but because you don''t have the experience to absorb the loss.

## Cannabis

Cannabis (marijuana, THC products, edibles, vapes) is not a safe alternative to alcohol behind the wheel. Research consistently shows it:

- Slows reaction time.
- Impairs lane-keeping and following distance.
- Distorts your sense of time and speed.
- Reduces your ability to divide attention between tasks.

A few specific traps:

- **Edibles** can hit much later than expected. You might feel fine when you start driving and severely impaired 45 minutes in.
- **"I drive better high"** is a classic example of impaired judgment, not evidence. Studies consistently show the opposite.
- **Mixing cannabis and alcohol** is worse than either alone. The effects multiply.

## Prescription and over-the-counter meds

Legal does not mean safe to drive on. Common offenders:

- **Allergy medications**, especially older antihistamines, can cause significant drowsiness.
- **Cold and flu medicines** often contain ingredients that impair alertness or coordination.
- **Pain medications**, especially opioids, are seriously impairing.
- **Anti-anxiety, sleep, and muscle-relaxant medications** are not compatible with driving.
- **ADHD and other stimulant medications** taken outside of how they were prescribed can also impair driving.

Rules of thumb:

- Read the label. If it says don''t operate heavy machinery, that includes a car.
- Don''t drive on a new medication until you know how it affects you.
- Combinations matter. Two mild things together can equal one strong impairment.

## Building a no-impaired-driving plan

The goal is to never have to decide while you''re impaired. You decide while sober.

- **Pick a ride before you go out.** Designated sober driver, parent pickup, rideshare, public transit, staying over. The plan exists before the event.
- **Pre-load the ride money.** If a rideshare home costs money, have it ready. Decide it''s already spent.
- **Have a no-questions-asked agreement** with a parent, older sibling, or trusted adult: "I can call for a ride from anywhere, anytime, and we deal with the rest later." This single agreement has saved enormous numbers of lives.
- **Keep your keys out of reach** if you might be tempted. Hand them to someone sober when you arrive.
- **Plan for the friend who might drive impaired.** Decide in advance you will take their keys, call them a ride, or call someone who can come get both of you.

## Being the passenger

You are also responsible for not getting in the car with an impaired driver. Some lines:

- "I''m going to grab a ride. You should too."
- "I''ll wait with you until your ride comes."
- "I''m not getting in. Let''s call someone."

It''s awkward for a minute. It''s awkward for a long time if something happens.

The summary: alcohol and drugs change the brain you drive with. Build the plan before you need it, so you never have to trust your impaired brain to make the right call.', 14, 2
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_impairment-and-distraction_alcohol-and-other-drugs', 'lesson_impairment-and-distraction_alcohol-and-other-drugs', 'Quiz: Alcohol and other drugs', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_impairment-and-distraction_alcohol-and-other-drugs_0', 'quiz_impairment-and-distraction_alcohol-and-other-drugs', 'Why is the safest blood alcohol level for a new driver effectively zero?', '["Because new drivers can''t legally drink at all in any country","Because new drivers don''t yet have the experience margin to absorb even small impairment","Because alcohol affects teens for longer than adults","Because alcohol mainly affects vision, which new drivers rely on more"]', 1, 'Experienced drivers have a margin built from years of pattern recognition. New drivers don''t, so any impairment, even mild, removes the cushion that helps them catch mistakes.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_impairment-and-distraction_alcohol-and-other-drugs_1', 'quiz_impairment-and-distraction_alcohol-and-other-drugs', 'Which of the following is a specific risk of edibles compared to other forms of cannabis?', '["They contain more THC by law","Their effects can hit much later than expected, often after driving has started","They only affect coordination, not judgment","They wear off faster, so they''re safer for short drives"]', 1, 'Edibles often have a delayed onset. A driver can feel fine pulling out of a driveway and become significantly impaired well into the trip.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_impairment-and-distraction_alcohol-and-other-drugs_2', 'quiz_impairment-and-distraction_alcohol-and-other-drugs', 'Your friend insists they drive better when they''re high. What''s the best way to think about that claim?', '["They might be right; some people compensate well","It''s a common example of impaired judgment, not evidence","It''s only true on short, familiar drives","It depends on the type of cannabis used"]', 1, 'Feeling like a better driver while impaired is a textbook sign of damaged self-judgment. Measured driving performance on cannabis is consistently worse, not better.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_impairment-and-distraction_alcohol-and-other-drugs_3', 'quiz_impairment-and-distraction_alcohol-and-other-drugs', 'Which statement about over-the-counter and prescription medications is most accurate?', '["Legal medicines are safe for driving as long as you take the right dose","Only opioids cause real driving impairment","Many common meds, including allergy and cold medicines, can seriously impair driving","Medications only matter when combined with alcohol"]', 2, 'Plenty of legal, common medications, especially older antihistamines, cold meds, and sedating prescriptions, can impair reaction time and alertness. Labels warning against operating machinery apply to driving too.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_impairment-and-distraction_alcohol-and-other-drugs_4', 'quiz_impairment-and-distraction_alcohol-and-other-drugs', 'What is the single most powerful piece of a personal no-impaired-driving plan?', '["Memorizing the legal limits","A no-questions-asked agreement with a trusted adult for a ride home anytime","A promise to only drink small amounts","Keeping caffeine in the car for the drive home"]', 1, 'A standing agreement with a trusted adult that you can call for a ride from anywhere, anytime, no consequences in the moment, removes the impaired decision and saves lives.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_impairment-and-distraction_distraction-and-staying-focused', 'module_impairment-and-distraction', 'distraction-and-staying-focused', 'Distraction and staying focused', 'Distraction is impairment you choose in the moment. Unlike fatigue or alcohol, you can usually fix it instantly. That''s the good news. The bad news is that distraction is constant, socially normal, and built into the device in your pocket.

## The three kinds of distraction

Every distraction is at least one of these:

- **Visual.** Your eyes leave the road. Looking at a phone, the radio, a passenger, a billboard.
- **Manual.** Your hands leave the wheel. Typing, eating, reaching into a bag, adjusting controls.
- **Cognitive.** Your mind leaves the drive. Thinking through a conversation, an argument, a song lyric, what you''re going to say next.

The worst distractions hit all three at once. Texting is the classic example: eyes on the screen, hands off the wheel, brain on the message.

## What "a couple of seconds" really means

Look away from the road for two seconds at 55 mph and your car has traveled more than half the length of a football field. Five seconds, the average time it takes to read a text, is about 360 feet at that speed. That''s longer than many city blocks, all driven completely blind.

The road doesn''t pause while you look down. A child can step out, a car can stop, a light can change, a tire can blow. You don''t get those seconds back.

## Phones are the biggest one, on purpose

Phones are designed to be hard to ignore. Notifications, streaks, group chats, snap maps — all of it is engineered to pull your attention away from whatever you''re doing. While driving, that engineering is working against you.

A few honest things:

- Hands-free is better than handheld, but not safe. The cognitive distraction stays.
- "I only look at red lights" still teaches your brain to check the phone in the car. The habit leaks into moving traffic.
- "I can drive and text" is a confidence not backed by reaction-time data. Drivers consistently overestimate their ability here.

## Practical phone rules that actually work

The goal is to make the phone a non-decision while you drive:

- **Turn on Do Not Disturb While Driving** (or your phone''s equivalent). It auto-silences notifications and can auto-reply.
- **Put the phone out of reach.** Glove box, bag in the back seat, anywhere you can''t grab it without stopping.
- **Set navigation and music before you put the car in drive.** Lock in your destination and playlist at the curb.
- **If you need to use the phone, pull over.** A parking lot, a side street, a driveway. Stopped means stopped, in park.
- **Tell people the rule.** "If I don''t text back for a while, I''m driving." Set the expectation once and stop apologizing for it.

## Passengers

Passengers are the other big distraction for new drivers, especially other teens. More teen passengers in a car driven by a teen means a measurably higher crash risk. The combination of social pressure, conversation, and showing off is a real factor.

What helps:

- **Keep early solo and friend drives short and familiar.** You''re still building basic skills. Don''t add a carful of friends to your first month.
- **Set the ground rules out loud.** "I need to focus, so I''m going to be quieter in traffic." Most friends will respect it.
- **Pull over for anything serious.** If a conversation needs your full attention, the conversation can wait until you''re parked.
- **Don''t perform.** Driving fast, taking corners hard, or showing off for passengers is a leading cause of teen crashes. The audience is not worth it.

## The smaller distractions add up

Not all distractions look like a phone:

- **Eating and drinking** take a hand and some attention. Save it for stops.
- **Adjusting climate, audio, or navigation** mid-drive. Do it before you move or at a long red.
- **Pets** loose in the car. Pets belong restrained, not in your lap.
- **Reaching for dropped items.** A dropped phone or fries are not worth a crash. Leave it. Get it when you stop.
- **Strong emotions.** Driving right after a fight, a breakup, or terrible news is genuinely dangerous. Your cognitive attention is gone. Sit for a few minutes before you turn the key.

## A simple pre-drive ritual

Build a 10-second routine before every drive:

1. Seat, mirrors, seatbelt.
2. Phone on Do Not Disturb and out of reach.
3. Navigation and music set.
4. Passengers briefed if needed.
5. Quick check-in with yourself: am I awake, calm, and ready?

If the answer to step 5 is no, you have permission to wait a few minutes, walk it off, or get a ride.

## The core idea

You cannot drive well while doing something else. The car is not a place to multitask. Every time you give the road your full attention, you are doing the actual job of driving. Every time you don''t, you are gambling with somebody''s life, often a stranger''s. Decide now what you''ll do with your phone, your passengers, and your attention, so you don''t have to decide it at 45 mph.', 13, 3
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_impairment-and-distraction_distraction-and-staying-focused', 'lesson_impairment-and-distraction_distraction-and-staying-focused', 'Quiz: Distraction and staying focused', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_impairment-and-distraction_distraction-and-staying-focused_0', 'quiz_impairment-and-distraction_distraction-and-staying-focused', 'Which combination of distraction types does texting while driving involve?', '["Only visual","Visual and manual only","Visual, manual, and cognitive","Only cognitive"]', 2, 'Texting takes your eyes off the road (visual), your hands off the wheel (manual), and your mind off driving (cognitive), which is why it''s one of the most dangerous things you can do at the wheel.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_impairment-and-distraction_distraction-and-staying-focused_1', 'quiz_impairment-and-distraction_distraction-and-staying-focused', 'At 55 mph, roughly how far does a car travel during the five seconds it takes to read a typical text?', '["About 50 feet","About 150 feet","About 360 feet","About 1,000 feet"]', 2, 'At 55 mph you''re moving about 80 feet per second. Five seconds is about 360 feet, longer than many city blocks, all driven without anyone watching the road.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_impairment-and-distraction_distraction-and-staying-focused_2', 'quiz_impairment-and-distraction_distraction-and-staying-focused', 'Why is hands-free phone use still not considered safe while driving?', '["It is illegal everywhere","The phone can fall and become a manual distraction","The cognitive distraction of the conversation remains","It drains the car''s battery"]', 2, 'Hands-free removes the manual and most of the visual distraction, but your brain is still doing the conversation instead of fully tracking the road. Cognitive distraction is the part you can''t outsource.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_impairment-and-distraction_distraction-and-staying-focused_3', 'quiz_impairment-and-distraction_distraction-and-staying-focused', 'What is one research-backed reason new drivers should limit teen passengers early on?', '["Teen passengers legally require a special license","Multiple teen passengers in a teen-driven car raise crash risk significantly","Teen passengers are more likely to refuse to wear seatbelts","Cars handle worse with more passengers"]', 1, 'Crash risk for teen drivers rises notably with each additional teen passenger, largely due to social distraction and pressure to perform. Building skills first with fewer passengers is safer.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_impairment-and-distraction_distraction-and-staying-focused_4', 'quiz_impairment-and-distraction_distraction-and-staying-focused', 'You drop your phone on the floor while driving on a busy road. What''s the best response?', '["Reach down quickly so you can answer the message","Slow down to about half the speed limit and lean over carefully","Leave it on the floor and pick it up when you safely stop","Pull into the next lane to give yourself room to reach"]', 2, 'Reaching for a dropped item is a high-risk distraction in every dimension. Leave it on the floor until you can stop somewhere safe. No message or item is worth crashing for.', 4
);

-- Module: Sharing the road
INSERT INTO module (id, courseId, slug, title, description, ordinal) VALUES (
  'module_sharing-the-road', 'course_national_teen_core', 'sharing-the-road', 'Sharing the road', 'How to drive safely around pedestrians, cyclists, motorcyclists, trucks, school buses, and emergency vehicles.', 7
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_sharing-the-road_pedestrians-and-crosswalks', 'module_sharing-the-road', 'pedestrians-and-crosswalks', 'Pedestrians and crosswalks', 'Pedestrians are the most vulnerable people on the road. They have no airbags, no seatbelts, and no metal frame around them. When a car and a person collide, the person loses. That makes the driver responsible for paying extra attention, even when a pedestrian does something unexpected.

## Where to expect pedestrians

Pedestrians can appear almost anywhere, but some places demand extra caution:

- Marked crosswalks at intersections
- Unmarked crosswalks (every intersection legally has one, even without paint)
- School zones, parks, and playgrounds
- Parking lots, especially near store entrances
- Bus stops and transit centers
- Residential streets where kids might run between parked cars
- Downtown areas with heavy foot traffic

At night, in rain, or in fog, pedestrians get much harder to see. Dark clothing, hoods, and umbrellas hide people. Slow down when visibility drops.

## Yielding the right of way

The general rule across the country is simple: yield to pedestrians in crosswalks. That means slow down or stop and let them cross before you go. Even when a pedestrian is technically jaywalking, you still have to try to avoid hitting them. Being legally right does not undo a tragedy.

When you approach a crosswalk:

- Cover the brake with your foot
- Scan both sidewalks, not just the road ahead
- Make eye contact with anyone near the curb
- Wait until the pedestrian is fully across your lane, plus a safety margin

## The hidden-pedestrian problem

If the car next to you stops at a crosswalk for no obvious reason, do not pass it. That driver almost certainly stopped for a pedestrian you cannot see. Drivers in the second lane cause many of the worst crosswalk crashes because they sweep around the stopped car at full speed.

The rule is: when a vehicle is stopped at a crosswalk, stop too. Then look.

## Backing up

More kids are hit in driveways and parking lots than people realize. Before backing up:

- Walk around the vehicle if you have been parked for a while
- Check the rear camera AND look over your shoulder
- Back slowly so you have time to react
- Stop completely if you hear a horn, a shout, or a thump

Rear cameras have blind spots. They do not see a toddler crouched right behind a bumper.

## School zones and buses

School zones often have lower speed limits when children are present, sometimes as low as 15 to 20 mph. Obey the posted limit and stay off your phone. Kids are unpredictable. A ball rolling into the street usually means a child is about to follow.

## Pedestrians with disabilities

A person using a white cane or a guide dog has the right of way at all times. Do not honk to hurry them. They may be listening for traffic to judge when to cross. Idle quietly and let them finish.

## Driving while distracted is even worse here

Looking at your phone for two seconds at 30 mph means you travel almost 90 feet blind. That is more than enough distance to miss a child stepping off a curb. In any pedestrian-heavy area, your phone goes down and your eyes go up.

## A simple habit

Every time you approach an intersection, do a quick sidewalk-to-sidewalk sweep before you commit to the turn or the crossing. That one-second habit prevents the kind of crash you never recover from emotionally.', 14, 0
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_sharing-the-road_pedestrians-and-crosswalks', 'lesson_sharing-the-road_pedestrians-and-crosswalks', 'Quiz: Pedestrians and crosswalks', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sharing-the-road_pedestrians-and-crosswalks_0', 'quiz_sharing-the-road_pedestrians-and-crosswalks', 'The car in the lane next to you stops at a crosswalk for no obvious reason. What should you do?', '["Pass them carefully since your lane is clear","Honk to ask why they stopped","Stop as well, then look for a pedestrian you cannot see","Maintain speed because they are probably just being overly cautious"]', 2, 'A stopped vehicle at a crosswalk almost always means a pedestrian is crossing. Passing creates a deadly multi-lane crash pattern, so you stop first and then look.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sharing-the-road_pedestrians-and-crosswalks_1', 'quiz_sharing-the-road_pedestrians-and-crosswalks', 'A pedestrian is jaywalking across the road in front of you. What is your responsibility?', '["None, since they are breaking the law","Honk and keep driving at your current speed","Slow down or stop to avoid hitting them","Swerve into the next lane without checking"]', 2, 'Even when a pedestrian is in the wrong, drivers must still try to avoid a collision. Being legally correct does not undo the harm of hitting a person.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sharing-the-road_pedestrians-and-crosswalks_2', 'quiz_sharing-the-road_pedestrians-and-crosswalks', 'You are about to back out of a driveway after the car has been parked for a few hours. What is the safest first step?', '["Trust the backup camera and reverse","Walk around the vehicle to check for kids, pets, or obstacles","Honk twice and back up quickly","Roll down the window and listen for movement"]', 1, 'Backup cameras have blind spots and miss small children crouched behind the bumper. A quick walk-around is the only way to be sure nothing is back there.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sharing-the-road_pedestrians-and-crosswalks_3', 'quiz_sharing-the-road_pedestrians-and-crosswalks', 'A person using a white cane is standing at the corner. What should you do?', '["Honk to let them know you are there","Wave them across through the window","Wait quietly and yield the right of way","Rev the engine so they hear you"]', 2, 'A white cane signals a person with a visual impairment. They often use traffic sounds to time their crossing, so honking or revving can actually confuse them. Wait quietly and yield.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sharing-the-road_pedestrians-and-crosswalks_4', 'quiz_sharing-the-road_pedestrians-and-crosswalks', 'Why is glancing at your phone for two seconds especially dangerous near pedestrians?', '["It drains your battery faster","At normal speeds you travel many car-lengths completely blind","It is only dangerous on the highway","Pedestrians can see you doing it and get angry"]', 1, 'At 30 mph, two seconds is roughly 90 feet of travel with your eyes off the road. That is more than enough distance to miss a child stepping off a curb.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_sharing-the-road_cyclists-and-motorcyclists', 'module_sharing-the-road', 'cyclists-and-motorcyclists', 'Cyclists and motorcyclists', 'Bicycles and motorcycles share the road with cars but have almost none of the protection. A rider has no crumple zone, no airbags, and no roof. A small mistake from a driver can put a rider in the hospital. Treating them with respect is not optional, it is part of the job.

## Cyclists belong on the road

In most places, bicycles are legally considered vehicles. They have the right to use the travel lane, not just the shoulder or a bike lane. A cyclist may move toward the center of the lane to avoid potholes, parked-car doors, debris, or to make a left turn. That is not them being rude. That is them protecting their life.

## Passing a cyclist

Give cyclists wide space when passing:

- Aim for at least 3 feet of clearance, more at higher speeds
- Slow down before you pass, do not speed up to get around
- Wait for a safe gap, even if it costs you a few seconds
- Never squeeze past a cyclist when an oncoming car is close

A gust of wind from a passing truck can knock a cyclist off balance. Your car, passing inches away, feels like the same thing.

## The dooring danger

If you are parked on the street, look before opening your door. A cyclist coming up alongside has almost no time to swerve. The safe move is the "reach across" habit: open the driver door with your right hand. That forces your body to turn and look back, and you naturally see anyone approaching.

## Watch at intersections

Most car-versus-bike crashes happen at intersections, not on open roads. The common ones:

- The right hook: a driver turns right across a cyclist going straight
- The left cross: a driver turning left fails to see an oncoming cyclist
- The pull-out: a driver leaving a driveway looks for cars but not for bikes

The fix is simple: actively look for narrow shapes, not just car-sized ones. Bicycles are easy to miss because your brain filters for vehicles your size.

## Motorcycles deserve a full lane

A motorcycle is entitled to the full width of a lane. Never try to share a lane with one or squeeze past in the same lane. Their position inside the lane is intentional: they shift left, center, or right to stay visible and to avoid oil, sand, and uneven pavement.

## Motorcycles hide in your blind spots

Because motorcycles are narrow, they can vanish behind your A-pillars, in your mirrors, or behind another car. Before any lane change:

- Signal early
- Check the mirror
- Turn your head and check the blind spot directly
- Do it again if traffic is heavy

A motorcycle that was clearly visible three seconds ago might now be right next to your door.

## Following distance changes too

Motorcycles can stop much faster than cars in many situations, especially on dry pavement. Tailgating one means you may not be able to stop in time if they brake hard. Give at least a 4-second following gap behind a motorcycle, more in rain or on loose surfaces.

## Weather makes everything worse

Rain, wet leaves, painted lines, metal grates, and gravel are all dangerous for two-wheeled vehicles. A rider may slow down, change lane position, or brake earlier than you expect. Give them more room in bad weather, not less.

## The mindset shift

The single best habit you can build is to assume there is always a cyclist or motorcyclist nearby that you have not noticed yet. That assumption makes you check twice, signal earlier, and leave more space. None of that costs you real time. All of it could save someone''s life.', 13, 1
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_sharing-the-road_cyclists-and-motorcyclists', 'lesson_sharing-the-road_cyclists-and-motorcyclists', 'Quiz: Cyclists and motorcyclists', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sharing-the-road_cyclists-and-motorcyclists_0', 'quiz_sharing-the-road_cyclists-and-motorcyclists', 'A cyclist is riding near the middle of the travel lane instead of hugging the curb. What is the most likely reason?', '["They are trying to slow down traffic on purpose","They are avoiding hazards like potholes, debris, or car doors","They forgot the rules of the road","They want to race the cars behind them"]', 1, 'Cyclists often move toward the center of the lane to avoid road hazards, parked-car doors, or to set up for a turn. It is a safety move, not a courtesy issue.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sharing-the-road_cyclists-and-motorcyclists_1', 'quiz_sharing-the-road_cyclists-and-motorcyclists', 'You are parked on a city street and ready to get out. What is the safest way to open your driver door?', '["Push it open quickly with your left hand","Open it slowly without looking, since you would feel any impact","Reach across with your right hand so your body turns and you can see behind","Open it fully then check for cyclists"]', 2, 'The reach-across habit forces your shoulders to turn so you naturally look back for cyclists. This prevents ''dooring,'' which can throw a rider into traffic.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sharing-the-road_cyclists-and-motorcyclists_2', 'quiz_sharing-the-road_cyclists-and-motorcyclists', 'Why are motorcycles especially hard to see during a lane change?', '["They are usually faster than cars","Their headlights are dimmer than car headlights","Their narrow profile lets them hide in blind spots and behind pillars","They almost always ride on the shoulder"]', 2, 'A motorcycle''s narrow shape can disappear behind A-pillars, mirrors, or other vehicles. That is why a head check is essential, not just a mirror glance.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sharing-the-road_cyclists-and-motorcyclists_3', 'quiz_sharing-the-road_cyclists-and-motorcyclists', 'What is the ''right hook'' crash between a car and a cyclist?', '["A cyclist passing a car on the right","A driver turning right across the path of a cyclist going straight","A cyclist swerving right to avoid a pothole","A driver opening a right-side passenger door into a cyclist"]', 1, 'The right hook happens when a driver turns right without checking for a cyclist continuing straight on their right side. It is one of the most common and serious intersection crashes.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sharing-the-road_cyclists-and-motorcyclists_4', 'quiz_sharing-the-road_cyclists-and-motorcyclists', 'What is a reasonable following distance behind a motorcycle in good conditions?', '["About one car length","The same as the car ahead of you in heavy traffic","At least 4 seconds, more in poor weather","Whatever feels normal, since bikes stop slower than cars"]', 2, 'Motorcycles can often stop faster than cars, so following too closely leaves you no time to react. A 4-second gap is the baseline, with more space in rain or on loose surfaces.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_sharing-the-road_large-trucks-and-buses', 'module_sharing-the-road', 'large-trucks-and-buses', 'Large trucks and buses', 'Big rigs, dump trucks, delivery trucks, and buses are not just bigger cars. They accelerate slower, stop slower, turn wider, and have huge blind spots. Driving around them safely means understanding how they actually work, not just staying out of their way.

## The blind spots are massive

Large trucks have four major blind spots, often called the "No Zones":

- Directly in front, about 20 feet ahead of the cab
- Directly behind, about 30 feet behind the trailer
- Along the driver''s side, under the side mirror
- Along the passenger side, extending across two lanes

A useful rule: if you cannot see the truck driver''s face in their side mirror, they cannot see you. Lingering in a blind spot is one of the most dangerous things you can do on the highway.

## Passing a truck

When you pass:

- Pass on the left whenever possible, since the right-side blind spot is bigger
- Maintain a steady speed, do not creep along beside the trailer
- Get clearly ahead before merging back, you should see the entire cab in your rearview mirror
- Never cut in front and brake, the truck cannot stop the way you can

A loaded semi traveling 65 mph may need the length of two football fields to stop. If you brake-check a truck, the truck wins.

## Wide turns

Trucks and buses need to swing wide to make turns, especially right turns. The trailer tracks inside the path of the cab. If a truck has its right turn signal on and is drifting left, do not try to squeeze up the right side. You will be crushed against the curb.

Watch for these clues:

- Right turn signal blinking
- The cab swinging left into your lane
- Slow speed approaching an intersection

When in doubt, hang back and let the truck complete the turn.

## Following distance

Following a large truck too closely creates two problems. First, you cannot see around it, so you have no idea what traffic ahead is doing. Second, if anything falls off the truck, you have no time to react. Drop back so you can see at least one full vehicle length of road between your hood and the rear of the trailer at highway speeds, ideally more.

If a truck is behind you and following too closely, do not brake to send a message. Change lanes when you can and let them pass. A panicked truck driver behind you is the last thing you want.

## Wind and spray

Passing a large truck on the highway in rain can soak your windshield in a single second. Turn on your wipers before you start the pass, not after. Crosswinds also push small cars around when they exit the truck''s wind shadow. Keep both hands on the wheel.

## School buses

School buses get extra legal protection because they carry kids who often dart across the road. When a school bus extends its stop arm and flashes red lights, traffic in both directions usually must stop. The few exceptions involve divided highways with a physical barrier. When in doubt, stop. The cost of being wrong is a child''s life.

Even after the lights turn off, scan for kids still crossing or running toward the bus. Pull away slowly.

## Transit and city buses

City buses pull in and out of traffic constantly. Many places require drivers to yield to a bus that is signaling to pull out from a stop. Even where it is not required, giving them space keeps traffic moving smoothly. Watch for pedestrians stepping out from in front of a stopped bus.

## The big mindset

A truck driver doing their job well is not your enemy. They want to get home too. Most truck crashes that involve a car are caused by the car driver, not the trucker. Give them space, stay visible, and never assume they can react as quickly as you can. Physics is not on their side.', 14, 2
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_sharing-the-road_large-trucks-and-buses', 'lesson_sharing-the-road_large-trucks-and-buses', 'Quiz: Large trucks and buses', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sharing-the-road_large-trucks-and-buses_0', 'quiz_sharing-the-road_large-trucks-and-buses', 'What is the simplest test for whether a truck driver can see you?', '["If you can see the truck''s trailer, the driver can see you","If you can see the truck driver''s face in their side mirror, they can probably see you","If the truck''s turn signal is on, the driver has spotted you","If you can hear the engine, you are within their view"]', 1, 'Truck blind spots are huge. If you cannot see the driver''s face in their side mirror, you are in a No Zone and they almost certainly cannot see you.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sharing-the-road_large-trucks-and-buses_1', 'quiz_sharing-the-road_large-trucks-and-buses', 'A large truck ahead has its right turn signal on and starts drifting toward the left side of its lane. What should you do?', '["Pass on the right while it is moving left","Honk to let them know they are in the wrong lane","Hang back and let the truck complete the wide right turn","Speed up and pass on the left immediately"]', 2, 'Trucks swing left to make wide right turns because the trailer tracks inside the cab''s path. Squeezing up the right side is how cars get crushed against the curb.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sharing-the-road_large-trucks-and-buses_2', 'quiz_sharing-the-road_large-trucks-and-buses', 'You are passing a semi truck on the highway. When is it safe to merge back into its lane?', '["As soon as you are past the trailer''s back wheels","When you can see the entire truck cab in your rearview mirror","When the truck flashes its headlights at you","When your front bumper is even with the cab"]', 1, 'Seeing the whole cab in your rearview confirms you have enough space ahead of the truck to merge safely. Trucks need long stopping distances, so cutting in too close is dangerous.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sharing-the-road_large-trucks-and-buses_3', 'quiz_sharing-the-road_large-trucks-and-buses', 'A school bus ahead extends its stop arm and turns on flashing red lights on a normal two-lane road. What should oncoming and following traffic do?', '["Only the cars behind the bus must stop","Traffic in both directions must stop","Cars may pass slowly with caution","Only cars within 50 feet must stop"]', 1, 'On an undivided road, traffic in both directions must stop for a school bus with its stop arm out and red lights flashing. Kids commonly cross in front of the bus, and a moving car would be deadly.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sharing-the-road_large-trucks-and-buses_4', 'quiz_sharing-the-road_large-trucks-and-buses', 'A large truck is following you too closely on the highway. What is the safest response?', '["Tap your brakes to make them back off","Slow way down so they are forced to pass","Change lanes when safe and let the truck pass","Speed up well above the limit to get away"]', 2, 'Trucks need much longer stopping distances than cars, so brake-checking one is dangerous. Moving aside and letting them pass removes the conflict and keeps you safe.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_sharing-the-road_emergency-vehicles-and-work-zones', 'module_sharing-the-road', 'emergency-vehicles-and-work-zones', 'Emergency vehicles and work zones', 'Some of the most stressful moments behind the wheel involve flashing lights: a fire truck behind you, a tow truck on the shoulder, a flagger waving a sign in a construction zone. These situations have clear rules, and following them protects people who are doing some of the most dangerous jobs on the road.

## When you hear a siren

The first thing to do when you hear or see an emergency vehicle is figure out where it is coming from. Sirens echo between buildings and can sound like they are everywhere at once.

- Turn down the radio
- Check all your mirrors
- Look left, right, and ahead at intersections
- Roll down a window briefly if you need to locate the sound

Do not assume the siren is for someone else. Find it before you decide what to do.

## Pulling over

The general rule across the country: when an emergency vehicle approaches with lights and siren, pull as far to the right as you can and stop. Then stay there until it passes.

A few important details:

- Use your turn signal so other drivers know your plan
- Do not slam on the brakes in the middle of a lane
- Do not stop in an intersection, clear the intersection first, then pull right
- On a one-way street with no right shoulder, pulling left may be allowed
- On a divided highway, vehicles on the opposite side may not need to stop, but stay alert

If you are at a red light and an emergency vehicle is behind you, do not run the light. Stay put unless you can safely and legally move to clear a path. The emergency driver is trained to navigate around stopped traffic.

## Never follow an emergency vehicle

It can be tempting to tuck in behind a fire truck or ambulance to slip through traffic. Do not do it. In most places it is illegal, and it puts you in the path of other emergency vehicles that may be following or approaching from a different direction.

## Move-over laws

When you see flashing lights on the shoulder, whether police, fire, ambulance, tow truck, or road maintenance, you have two responsibilities:

- Move over one lane away from them if it is safe to do so
- If you cannot move over, slow down significantly below the posted limit

These laws exist because roadside workers are struck and killed every year by drivers who did not give them room. A few seconds of inconvenience is nothing compared to a tow operator''s life.

## Work zones

Work zones change the road temporarily, and they are full of hazards: workers on foot, narrowed lanes, sudden stops, uneven pavement, and equipment crossing your path. Speed limits in work zones are usually lower and often carry doubled fines.

Driving safely through a work zone means:

- Slow down as soon as you see the orange signs, not when you reach the cones
- Increase your following distance, traffic stops fast in work zones
- Watch for flaggers and obey their signals over any traffic light or sign
- Merge early when a lane closure is announced, not at the last second
- Stay off the phone, completely

Flaggers have legal authority to direct traffic. A flagger holding a STOP paddle means stop, even if the light ahead is green.

## Funeral processions

If you encounter a funeral procession, the lead car typically has its headlights and flashers on, and following cars do too. Do not cut into the line. Let it pass. Many places give the procession the right of way through intersections, even against a red light.

## After the emergency passes

Once the emergency vehicle is well past you, signal, check your mirrors and blind spot, and merge back into the lane carefully. Other drivers may pull out at the same time, so do not just shoot back into traffic.

## The bottom line

Flashing lights mean someone is having the worst day of their life, or working to prevent yours. Treat every emergency scene, work zone, and roadside breakdown as a place where the rules tighten and your attention sharpens. The people in those reflective vests are counting on you.', 13, 3
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_sharing-the-road_emergency-vehicles-and-work-zones', 'lesson_sharing-the-road_emergency-vehicles-and-work-zones', 'Quiz: Emergency vehicles and work zones', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sharing-the-road_emergency-vehicles-and-work-zones_0', 'quiz_sharing-the-road_emergency-vehicles-and-work-zones', 'You are stopped at a red light when an ambulance approaches from behind with lights and siren. What should you do?', '["Run the red light to clear a path immediately","Stay where you are unless you can safely and legally move aside","Reverse to make more room behind you","Pull forward into the intersection and stop"]', 1, 'Running a red light to make way creates a serious crash risk. Emergency drivers are trained to maneuver around stopped traffic, so staying put is usually the safest choice.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sharing-the-road_emergency-vehicles-and-work-zones_1', 'quiz_sharing-the-road_emergency-vehicles-and-work-zones', 'You see a tow truck with flashing yellow lights parked on the shoulder ahead. What does a typical move-over law require?', '["Only slow down if a worker is visible","Move one lane over if safe, or slow down significantly if you cannot","Honk to alert the tow operator that you are passing","Move over only for police vehicles, not tow trucks"]', 1, 'Move-over laws cover police, fire, ambulance, tow trucks, and road maintenance. The rule is to give them a buffer lane, or slow well below the limit if you cannot change lanes.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sharing-the-road_emergency-vehicles-and-work-zones_2', 'quiz_sharing-the-road_emergency-vehicles-and-work-zones', 'You hear a siren but cannot tell where it is coming from. What is the best first move?', '["Speed up to clear the area","Immediately pull to the right and stop, regardless of location","Turn down the radio and scan mirrors and intersections to locate it","Assume it is for someone else and keep driving normally"]', 2, 'Sirens echo and can be hard to locate. Reducing noise inside the car and scanning around you lets you respond appropriately rather than reacting blindly.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sharing-the-road_emergency-vehicles-and-work-zones_3', 'quiz_sharing-the-road_emergency-vehicles-and-work-zones', 'A flagger in a work zone is holding up a STOP paddle, but the traffic light ahead is green. What should you do?', '["Follow the green light, since signals outrank workers","Stop, because flaggers have authority to direct traffic in a work zone","Slow down and proceed with caution","Honk to ask the flagger to step aside"]', 1, 'Flaggers have legal authority to direct traffic in work zones, and their signals override regular signs and lights. Ignoring them puts workers in immediate danger.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_sharing-the-road_emergency-vehicles-and-work-zones_4', 'quiz_sharing-the-road_emergency-vehicles-and-work-zones', 'Why is it dangerous (and usually illegal) to follow closely behind a fire truck or ambulance that is responding to a call?', '["You might run out of fuel trying to keep up","Other emergency vehicles or cross traffic may not expect you and could collide with you","The siren can damage your hearing through the windshield","Emergency vehicles often back up suddenly"]', 1, 'Other drivers and additional emergency vehicles are reacting to the first one, not to you. Tucking in behind puts you in a path where no one expects a regular car.', 4
);

-- Module: Emergencies and breakdowns
INSERT INTO module (id, courseId, slug, title, description, ordinal) VALUES (
  'module_emergencies-and-breakdowns', 'course_national_teen_core', 'emergencies-and-breakdowns', 'Emergencies and breakdowns', 'How to recognize, respond to, and recover from sudden vehicle problems and crashes on the road.', 8
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_emergencies-and-breakdowns_skids-and-loss-of-traction', 'module_emergencies-and-breakdowns', 'skids-and-loss-of-traction', 'Skids and loss of traction', 'A skid happens when your tires lose their grip on the road. Once that grip is gone, steering and braking stop working the way you expect. Most skids come from doing too much, too fast: too much brake, too much gas, or too much steering for the conditions. Rain, snow, ice, gravel, and even painted lines can take grip away in a heartbeat.

The single best thing you can do about skids is prevent them. Slow down before a curve, not in it. Increase your following distance when the road is wet or cold. Look far ahead so you spot shiny pavement, slush, or leaves before you reach them. Smooth inputs on the wheel, gas, and brake keep your tires loaded evenly and gripping.

## The three common skids

- **Rear-wheel skid (oversteer):** the back of the car slides out sideways. The car wants to spin.
- **Front-wheel skid (understeer):** you turn the wheel, but the car keeps going straight. Common when you brake and turn at the same time on a slick road.
- **Four-wheel skid:** all four tires lock or slide. You feel like you are gliding with no control.

## Recovering from a rear-wheel skid

1. Ease off the gas. Do not stab the brake.
2. Look where you want the car to go, not at what you are sliding toward.
3. Steer gently in the same direction the rear is sliding. If the back swings right, steer right.
4. As the car straightens, smoothly straighten the wheel. Do not over-correct, or the car will fishtail the other way.

## Recovering from a front-wheel skid

1. Ease off the gas or brake, whichever you were doing.
2. Hold the wheel pointed where you want to go, but do not crank it harder. More steering input will not help when the front tires have no grip.
3. Wait a beat for the tires to regain traction.
4. Once you feel grip return, gently steer through the turn.

## Recovering from a four-wheel skid

1. Take your feet off both pedals.
2. Keep the wheel pointed straight or aimed where you want to go.
3. Let the car slow down on its own until the tires bite again.
4. Then steer and brake gently.

## ABS changes the feel, not the rule

If your car has anti-lock brakes (almost all modern cars do), press the brake firmly and hold it down in an emergency. You will feel a buzzing or pulsing through the pedal. That is normal. Do not pump the pedal. ABS lets you steer while you brake hard, which is the whole point.

## Hydroplaning

Hydroplaning is a skid on water. A thin layer of water lifts the tires off the pavement, usually above 35 mph in heavy rain or through standing water. If it happens:

- Do not brake hard.
- Ease off the gas.
- Keep the wheel straight and steady.
- Wait for the tires to settle back onto the road, then continue.

Good tires with deep tread and correct air pressure are your best defense.', 13, 0
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_emergencies-and-breakdowns_skids-and-loss-of-traction', 'lesson_emergencies-and-breakdowns_skids-and-loss-of-traction', 'Quiz: Skids and loss of traction', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_emergencies-and-breakdowns_skids-and-loss-of-traction_0', 'quiz_emergencies-and-breakdowns_skids-and-loss-of-traction', 'Your back tires start to slide to the left as you go around a curve. What should you do first?', '["Brake hard and steer right","Ease off the gas and steer gently to the left","Turn the wheel sharply to the right","Pull the parking brake to slow down"]', 1, 'In a rear-wheel skid, you steer in the same direction the rear is sliding while easing off the gas. Hard braking or yanking the wheel makes the slide worse.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_emergencies-and-breakdowns_skids-and-loss-of-traction_1', 'quiz_emergencies-and-breakdowns_skids-and-loss-of-traction', 'You are driving in heavy rain and feel the steering go light and unresponsive. You are hydroplaning. What is the correct response?', '["Brake firmly to slow down right away","Steer sharply to test if the tires are gripping","Ease off the gas and keep the wheel straight","Accelerate gently to push through the water"]', 2, 'Hydroplaning means your tires are riding on water. Easing off the gas and holding the wheel steady lets the tires settle back onto the pavement. Braking or steering hard can cause a spin.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_emergencies-and-breakdowns_skids-and-loss-of-traction_2', 'quiz_emergencies-and-breakdowns_skids-and-loss-of-traction', 'You have anti-lock brakes (ABS) and need to stop suddenly. What should you do?', '["Pump the brake pedal rapidly","Press the brake firmly and hold it down","Press lightly so the ABS does not kick in","Use the parking brake instead"]', 1, 'ABS is designed to be pressed firmly and held. The pulsing you feel is the system working. Pumping defeats it and increases stopping distance.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_emergencies-and-breakdowns_skids-and-loss-of-traction_3', 'quiz_emergencies-and-breakdowns_skids-and-loss-of-traction', 'You turn the steering wheel to go around a curve on a wet road, but the car keeps going straight. This is:', '["A rear-wheel skid; turn the wheel harder","A front-wheel skid; ease off the pedals and wait for grip to return","Normal behavior in rain; keep accelerating","A brake failure; pull the parking brake"]', 1, 'This is a front-wheel skid (understeer). The front tires have lost grip, so more steering will not help. Easing off the gas or brake lets the tires regain traction.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_emergencies-and-breakdowns_skids-and-loss-of-traction_4', 'quiz_emergencies-and-breakdowns_skids-and-loss-of-traction', 'What is the best way to avoid skids in the first place?', '["Drive in a lower gear at all times","Keep one hand on the parking brake in bad weather","Slow down before curves and make smooth steering, braking, and gas inputs","Brake hard before every turn to test traction"]', 2, 'Skids almost always come from sudden or harsh inputs. Slowing down early and being smooth keeps the tires loaded and gripping. Hard braking or jerky steering invites a skid.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_emergencies-and-breakdowns_tire-blowouts-and-brake-failure', 'module_emergencies-and-breakdowns', 'tire-blowouts-and-brake-failure', 'Tire blowouts and brake failure', 'A blowout or a brake failure feels terrifying because the car suddenly does not respond the way it should. The good news: both have clear, learnable responses. The wrong instinct in either case is to slam on the brakes. Train yourself now so your hands and feet know what to do before your brain catches up.

## Tire blowout

A blowout is a sudden loss of tire pressure, usually with a loud bang. The car will pull hard toward the side of the failed tire. A front blowout pulls the steering wheel. A rear blowout makes the back of the car wag or fishtail.

Do this:

1. Grip the wheel firmly with both hands.
2. Do **not** slam the brakes. Hard braking shifts weight forward and can spin the car.
3. Ease off the gas and let the car slow down on its own.
4. Steer gently to keep the car going straight in your lane.
5. Once you are under about 30 mph, lightly apply the brakes.
6. Signal and coast to the right shoulder, as far off the road as you safely can.
7. Turn on hazard lights. Exit on the side away from traffic if it is safe to do so.

To avoid blowouts: check tire pressure monthly, look for bulges or cracks, replace tires with worn tread, and do not overload the car.

## Brake failure

Total brake failure is rare in modern cars, but partial loss of braking (soft pedal, pedal sinking to the floor, brakes that grab on one side) does happen.

If the pedal feels soft or sinks:

1. Pump the brake pedal quickly several times. This can build pressure in the system and may restore some braking.
2. If pumping does not help, shift to a lower gear (D2, L, or downshift a manual). Lower gears use the engine to slow the car.
3. Apply the parking brake slowly and steadily. Do not yank it on all at once or you can lock the rear wheels and spin. Most parking brake handles or pedals can be eased on gradually; if your car has an electronic parking brake, hold the switch and the system will apply gradually.
4. Steer toward an escape path: an empty shoulder, an uphill exit, an empty parking lot. Avoid oncoming traffic.
5. As a last resort, rub the tires against a curb or scrape the side of the car along a guardrail to bleed off speed. Property damage beats hitting a person or another car.
6. Once stopped, turn on hazards and do not drive again until the brakes are fixed.

## Accelerator stuck

If the gas pedal sticks down:

1. Shift to neutral. The engine will rev loudly, but the wheels will disconnect from the engine. This is the most important step.
2. Steer to a safe spot and brake normally.
3. Once stopped, turn the engine off. Do not turn the key all the way off while moving, or you will lose power steering and may lock the steering column.

## The common thread

In every one of these emergencies, the right move is to stay off the brake at first, keep both hands on the wheel, and guide the car to a safe stopping place. Panic braking turns a manageable problem into a crash. Practice saying the steps out loud now, so they are there when you need them.', 13, 1
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_emergencies-and-breakdowns_tire-blowouts-and-brake-failure', 'lesson_emergencies-and-breakdowns_tire-blowouts-and-brake-failure', 'Quiz: Tire blowouts and brake failure', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_emergencies-and-breakdowns_tire-blowouts-and-brake-failure_0', 'quiz_emergencies-and-breakdowns_tire-blowouts-and-brake-failure', 'You hear a loud bang and your steering wheel jerks to the right. You have a front-right tire blowout. What should you do first?', '["Slam on the brakes to stop as fast as possible","Grip the wheel firmly, ease off the gas, and steer to keep going straight","Jerk the wheel to the left to counter the pull","Turn on cruise control to keep speed steady"]', 1, 'Hard braking after a blowout can spin the car. The correct response is to hold the wheel, ease off the gas, and let the car slow gradually before braking lightly.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_emergencies-and-breakdowns_tire-blowouts-and-brake-failure_1', 'quiz_emergencies-and-breakdowns_tire-blowouts-and-brake-failure', 'Your brake pedal sinks toward the floor and the car is not slowing. After pumping the brake with no result, what is the next best step?', '["Turn the engine off immediately","Shift to a lower gear and slowly apply the parking brake","Open the door and drag your foot","Steer into oncoming traffic to find help"]', 1, 'Downshifting uses the engine to slow the car, and a gradual parking brake adds rear-wheel braking without locking the wheels. Turning off the engine costs you power steering and brake assist.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_emergencies-and-breakdowns_tire-blowouts-and-brake-failure_2', 'quiz_emergencies-and-breakdowns_tire-blowouts-and-brake-failure', 'Your gas pedal is stuck down and the car is accelerating. What should you do?', '["Turn the ignition key off right away","Pump the brakes only","Shift the transmission to neutral, then brake and steer to a safe spot","Pull the parking brake hard"]', 2, 'Shifting to neutral disconnects the engine from the wheels so the car can be braked normally. Turning off the engine while moving can lock the steering and remove power assist.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_emergencies-and-breakdowns_tire-blowouts-and-brake-failure_3', 'quiz_emergencies-and-breakdowns_tire-blowouts-and-brake-failure', 'Why should you avoid yanking the parking brake fully on during a brake failure emergency?', '["It can damage the parking brake cable","It can lock the rear wheels and cause the car to spin","It will not slow the car at all","It will turn off the engine"]', 1, 'A fully locked rear axle can break traction and send the car into a spin. Easing the parking brake on gradually provides controlled braking.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_emergencies-and-breakdowns_tire-blowouts-and-brake-failure_4', 'quiz_emergencies-and-breakdowns_tire-blowouts-and-brake-failure', 'What is the single best way to reduce your chance of a tire blowout?', '["Drive only in the right lane","Check tire pressure and tread regularly and avoid overloading the car","Use cruise control on the highway","Brake gently at every stop"]', 1, 'Underinflation, worn tread, and overloading are the leading causes of blowouts. Regular tire checks catch problems before they fail at speed.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_emergencies-and-breakdowns_engine-fires-stalls-and-warning-lights', 'module_emergencies-and-breakdowns', 'engine-fires-stalls-and-warning-lights', 'Engine fires, stalls, and warning lights', 'Cars give you warnings before most major failures. The trick is knowing which signals mean "deal with it soon" and which mean "pull over right now." This lesson covers the dashboard warnings that matter most, what to do if the engine stalls while you are moving, and how to handle the rare but serious situation of a vehicle fire.

## Reading warning lights

Not every light is an emergency. Color is your first clue.

- **Green or blue:** a system is on (headlights, high beams, cruise). Informational.
- **Yellow or amber:** something needs attention soon. Drive carefully and get it checked. Examples: check engine light, low fuel, low tire pressure, ABS warning.
- **Red:** stop as soon as it is safe. Red lights mean the car can hurt itself, you, or both. Examples: oil pressure, engine temperature, brake system, charging system, airbag.

The two red lights most worth memorizing:

- **Oil pressure (oil can icon):** the engine is not getting oil. Driving even a few more miles can destroy the engine. Pull over and shut it off.
- **Engine temperature (thermometer icon):** the engine is overheating. Keep driving and you risk a cracked head or a fire. Pull over, shut the engine off, and let it cool for at least 30 minutes before opening the hood.

Never open a hot radiator cap. Pressurized steam can spray and cause serious burns.

## If the engine stalls while you are driving

An engine that quits at speed is startling because the power steering gets heavy and the brakes get firm after one or two pumps. The car still steers and stops, it just takes more effort.

1. Both hands on the wheel. Steer toward the shoulder.
2. Signal and check mirrors. Other drivers will not know you are losing power.
3. Brake firmly but smoothly. Power assist may be reduced, so push harder than usual.
4. Once on the shoulder, shift to park (or neutral with parking brake on for a manual).
5. Try restarting. If it will not start, turn on hazards.
6. Get out on the side away from traffic if it is safe. Stand well off the road.

## Vehicle fires

Car fires usually start small, in the engine bay or under the dash, and grow fast. Warning signs include smoke from under the hood, a burning smell, or flames visible anywhere.

If you see or smell fire while driving:

1. Signal and pull off the road right away. Get as far from traffic as you can.
2. Shut off the engine. This stops fuel from pumping.
3. Get everyone out. Do not stop to grab belongings.
4. Move at least 100 feet away (about the length of two school buses). Move further if the fire is large or near the fuel tank.
5. Call 911. Tell them it is a vehicle fire and give your location.
6. Do **not** open the hood. Opening it gives the fire more oxygen and can cause flames to jump out at you.
7. Warn approaching traffic if you safely can, but never go back to the car.

A small fire extinguisher in the trunk can help with a tiny fire spotted early. But your safety always comes first. If you are not absolutely sure you can put it out in seconds, get away and let the fire department handle it.

## Smoke and steam are not the same

- **White steam from under the hood** usually means coolant is leaking or boiling. Pull over and shut off.
- **Blue or black smoke from the exhaust** means an engine problem, but not usually an immediate fire risk. Drive gently to a safe stopping point.
- **Smoke from inside the dash or under the hood** is a fire warning. Treat it as a fire until proven otherwise.

When in doubt, get out.', 12, 2
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_emergencies-and-breakdowns_engine-fires-stalls-and-warning-lights', 'lesson_emergencies-and-breakdowns_engine-fires-stalls-and-warning-lights', 'Quiz: Engine fires, stalls, and warning lights', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_emergencies-and-breakdowns_engine-fires-stalls-and-warning-lights_0', 'quiz_emergencies-and-breakdowns_engine-fires-stalls-and-warning-lights', 'A red oil pressure light comes on while you are driving. What should you do?', '["Keep driving to the next gas station to add oil","Pull over as soon as it is safe and shut off the engine","Rev the engine to build oil pressure","Ignore it unless the engine sounds different"]', 1, 'A red oil pressure light means the engine is not being lubricated. Continuing to drive can destroy the engine in minutes. Stop and shut off the engine right away.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_emergencies-and-breakdowns_engine-fires-stalls-and-warning-lights_1', 'quiz_emergencies-and-breakdowns_engine-fires-stalls-and-warning-lights', 'Your engine stalls at highway speed. What changes about how the car drives?', '["The steering and brakes stop working completely","Power steering gets heavier and brakes need more pressure, but both still work","The car will coast without slowing","The transmission locks up immediately"]', 1, 'Power assist is reduced when the engine quits, so the wheel feels heavy and the brake pedal gets firm after a pump or two. The car still steers and stops, but it takes more effort.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_emergencies-and-breakdowns_engine-fires-stalls-and-warning-lights_2', 'quiz_emergencies-and-breakdowns_engine-fires-stalls-and-warning-lights', 'You see flames under the hood. After pulling over and getting everyone out, what should you do next?', '["Open the hood to see how bad it is","Move at least 100 feet away and call 911","Try to drive the car to a safer location","Spray the hood with water from a bottle"]', 1, 'Opening the hood feeds the fire oxygen and can cause a flare-up. Get well clear and let trained responders handle it.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_emergencies-and-breakdowns_engine-fires-stalls-and-warning-lights_3', 'quiz_emergencies-and-breakdowns_engine-fires-stalls-and-warning-lights', 'You see white steam rising from under the hood and the temperature gauge is in the red. What should you do?', '["Pull over, shut off the engine, and wait at least 30 minutes before opening the hood","Open the radiator cap right away to release pressure","Keep driving with the heater on high to cool the engine","Pour cold water on the engine block"]', 0, 'An overheated engine and its radiator are under high pressure. Opening the cap hot can spray scalding steam. Let it cool fully before doing anything under the hood.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_emergencies-and-breakdowns_engine-fires-stalls-and-warning-lights_4', 'quiz_emergencies-and-breakdowns_engine-fires-stalls-and-warning-lights', 'How should you treat dashboard warning lights based on color?', '["Green means urgent, red means informational","All lights are equally urgent","Yellow means stop now; red means check soon","Yellow means attention needed soon; red means stop as soon as safely possible"]', 3, 'Yellow and amber lights are cautions to address soon. Red lights signal a problem that can damage the car or cause injury if you keep driving.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_emergencies-and-breakdowns_collisions-and-roadside-breakdowns', 'module_emergencies-and-breakdowns', 'collisions-and-roadside-breakdowns', 'Collisions and roadside breakdowns', 'Even careful drivers end up in fender benders or stranded on the shoulder. Knowing what to do in the first few minutes keeps you safe, keeps the situation from getting worse, and protects you legally and financially. This lesson is your checklist for after the worst has already happened.

## If you are in a collision

The moments right after a crash are chaotic. Adrenaline makes it hard to think. Run through these steps in order.

1. **Stop.** Leaving the scene of a crash, even a minor one, is a crime almost everywhere. Stop your vehicle.
2. **Check yourself, then your passengers.** Are you hurt? Is anyone bleeding, struggling to breathe, or unable to move? If yes, call 911 immediately.
3. **Make the scene safer.** If the cars can be driven and are blocking traffic, move them to the shoulder. If they cannot move, turn on hazard lights. Set out reflective triangles or flares if you have them.
4. **Call for help.** Call 911 for any crash with injuries, large vehicle damage, or a blocked roadway. Even for minor crashes, calling the non-emergency police line creates an official report. Many insurance companies require one.
5. **Exchange information** with the other driver: name, phone, address, driver''s license number, license plate, insurance company and policy number, and the make/model of their car.
6. **Document the scene.** Take photos of all vehicles from multiple angles, the license plates, the road, skid marks, traffic signs or signals, and any visible injuries. Note the time, weather, and street names.
7. **Get witness info** if anyone saw it: names and phone numbers.
8. **Do not admit fault.** Do not argue. Do not say "I''m sorry" or "It was my fault," even if you think it was. Let the police and insurance companies sort out responsibility based on evidence.
9. **Notify your insurance company** as soon as you can. Most have a 24-hour claims line and an app.
10. **Tell a parent or guardian** right away if you are a teen driver. They need to know, and they can help you handle the next steps.

## If someone is seriously hurt

- Do not move them unless the car is on fire or in immediate danger. Moving someone with a neck or spine injury can paralyze them.
- Call 911 and follow the dispatcher''s instructions.
- If they are unconscious but breathing, stay with them and keep them calm.
- Turn off the engines of damaged cars to reduce fire risk.

## Roadside breakdowns

A breakdown is not a crash, but it can become dangerous if you handle it badly. Cars stopped on the shoulder get hit by passing traffic every day.

When you sense trouble (warning light, strange noise, loss of power):

1. Turn on your hazard lights early. Other drivers need warning.
2. Get to the right shoulder, an exit, or a parking lot. The further off the road, the safer.
3. Steer straight and park as far right as you can. If there is a wide shoulder or grass, use it.
4. Turn the wheels away from the road in case the car gets bumped.
5. Leave hazard lights on.
6. Set out reflective triangles or flares behind the car if you have them: one about 10 feet behind, one about 100 feet behind.

## Should you get out of the car?

This is the most important decision after a breakdown.

- On a quiet road with a wide shoulder, exit on the passenger side away from traffic and stand well off the road, behind a guardrail if there is one.
- On a busy highway with narrow shoulders, it is often **safer to stay in the car** with your seatbelt on and call for help. A car hit at highway speed is more survivable than a person standing next to it.
- Never stand between your car and oncoming traffic. Never try to push a car out of a travel lane by yourself.

## Calling for help

Know your roadside assistance number before you need it (insurance, auto club, or the car maker''s app). Be ready to share:

- Your location: nearest exit, mile marker, or cross streets.
- The problem (flat, dead battery, overheating, won''t start).
- Whether you are in a safe spot or in traffic.

## A breakdown kit pays for itself

Keep these in your trunk: jumper cables or a portable jump pack, a flashlight, reflective triangles, a phone charger, a basic first aid kit, water, a blanket, and gloves. In cold climates, add a snow brush, ice scraper, and warm hat. You may go years without using any of it, then be very glad you have it on one bad night.', 14, 3
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_emergencies-and-breakdowns_collisions-and-roadside-breakdowns', 'lesson_emergencies-and-breakdowns_collisions-and-roadside-breakdowns', 'Quiz: Collisions and roadside breakdowns', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_emergencies-and-breakdowns_collisions-and-roadside-breakdowns_0', 'quiz_emergencies-and-breakdowns_collisions-and-roadside-breakdowns', 'You are in a minor fender bender. The other driver says it was all their fault. What should you say?', '["Agree and say it was their fault so it is documented","Apologize and say it was actually your fault to be polite","Stick to facts, exchange information, and do not admit or assign fault","Tell them no report is needed since they admitted fault"]', 2, 'Fault is decided by police and insurance based on evidence, not by what either driver says at the scene. Statements you make can be used against you later, so stick to facts and let the process work.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_emergencies-and-breakdowns_collisions-and-roadside-breakdowns_1', 'quiz_emergencies-and-breakdowns_collisions-and-roadside-breakdowns', 'You break down on a busy highway with a narrow shoulder. Cars are passing at high speed just a few feet away. What is usually the safest choice?', '["Get out and stand next to the driver''s door so help can see you","Stay in the car with your seatbelt on and call for help","Walk along the shoulder to the next exit","Stand behind the car and wave at traffic"]', 1, 'On a busy highway with little shoulder, a person is more vulnerable than a car. Staying belted in with hazards on and calling for help is usually safer than exiting into traffic.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_emergencies-and-breakdowns_collisions-and-roadside-breakdowns_2', 'quiz_emergencies-and-breakdowns_collisions-and-roadside-breakdowns', 'Someone in the other car appears unconscious after a crash but is breathing. What should you do?', '["Pull them out of the car so they get fresh air","Try to wake them by shaking them","Leave them in place unless there is fire or immediate danger, and call 911","Drive them to a hospital yourself"]', 2, 'Moving someone with a possible spine or neck injury can cause permanent damage. Unless the car is on fire or about to be hit, leave them in place and let trained responders handle it.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_emergencies-and-breakdowns_collisions-and-roadside-breakdowns_3', 'quiz_emergencies-and-breakdowns_collisions-and-roadside-breakdowns', 'After pulling onto the shoulder with a breakdown, why should you turn your front wheels away from the road?', '["It helps the engine restart","If your car gets bumped, it will roll away from traffic instead of into it","It saves fuel while you wait","It signals to other drivers that you need help"]', 1, 'A car that is rear-ended on the shoulder can be pushed forward. Wheels turned away from the road send it onto the shoulder instead of into a travel lane.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_emergencies-and-breakdowns_collisions-and-roadside-breakdowns_4', 'quiz_emergencies-and-breakdowns_collisions-and-roadside-breakdowns', 'Which item is most important to have in a basic roadside breakdown kit?', '["A spare set of car keys","Reflective triangles or flares and a flashlight","A toolbox with wrenches","A gallon of motor oil"]', 1, 'Visibility is the biggest safety issue during a breakdown, especially at night or in bad weather. Triangles, flares, and a flashlight help other drivers see you and help you see your surroundings.', 4
);

-- Module: Insurance and basic responsibility
INSERT INTO module (id, courseId, slug, title, description, ordinal) VALUES (
  'module_insurance-and-responsibility', 'course_national_teen_core', 'insurance-and-responsibility', 'Insurance and basic responsibility', 'How auto insurance works, what to do after a crash, the real cost of owning a car, and the daily habits that make you a responsible driver.', 9
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_insurance-and-responsibility_how-auto-insurance-works', 'module_insurance-and-responsibility', 'how-auto-insurance-works', 'How auto insurance works', 'Auto insurance is a contract. You pay a company a regular fee, and in return, they agree to pay for certain costs if something goes wrong with your car or if you cause harm to someone else. It exists because car crashes can cost more money than almost any teenager (or adult) has sitting in a bank account. A single crash with injuries can run into tens or hundreds of thousands of dollars. Insurance spreads that risk across a huge pool of drivers so no one person gets wiped out by one bad day.

## The words you need to know

- **Premium**: the amount you pay the insurance company, usually every month or every six months. It is the price of the policy.
- **Policy**: the written contract. It lists what is covered, what is not, and how much the company will pay.
- **Deductible**: the amount you pay out of your own pocket before the insurance company pays anything. If your deductible is $500 and the repair is $2,000, you pay $500 and the insurer pays $1,500.
- **Claim**: a request you file with the insurance company asking them to pay for a covered loss.
- **Coverage limit**: the maximum the insurance company will pay for a certain type of loss. Anything above that is on you.

## The main kinds of coverage

Almost every policy is built from a few standard pieces. You will see these on any insurance card or quote.

- **Liability coverage** pays for damage and injuries *you cause to other people and their property*. If you rear-end someone, liability pays for their bumper and their hospital bill. It does not pay for your car or your injuries. Driving without liability coverage is illegal in essentially every state.
- **Collision coverage** pays to repair *your* car when it is damaged in a crash, no matter who was at fault.
- **Comprehensive coverage** pays for damage to your car from things that are not crashes: theft, hail, a tree falling, a deer running into the road, vandalism, fire.
- **Uninsured/underinsured motorist coverage** protects you when the other driver caused the crash but does not have enough insurance (or any) to pay for your injuries or repairs.
- **Medical payments / personal injury protection** helps cover medical bills for you and your passengers, regardless of fault.

## How the premium gets calculated

Insurance companies try to predict how likely you are to file a claim. The more likely they think a claim is, the higher your premium. Things that push a teen driver''s premium up:

- Being new to driving. Less experience equals more risk in the data.
- Tickets, especially for speeding or reckless driving.
- At-fault crashes.
- Driving a car that is expensive to repair or commonly stolen.
- Living somewhere with lots of traffic or theft.

Things that can lower it:

- Good grades (many insurers offer a student discount).
- Completing an approved driver education course.
- Staying ticket- and crash-free over time.
- Choosing a higher deductible (you pay more out of pocket but the monthly premium drops).
- Being added to a parent''s policy instead of having your own.

## What insurance does NOT do

Insurance is not a free pass. A few things to keep straight:

- It does not erase a ticket or a citation. You still face fines and points.
- It does not cover intentional damage. If you crash on purpose or drive drunk, claims can be denied.
- It does not cover business use of your personal car unless you add it (this matters if you ever deliver food or drive for an app).
- It does not pay more than your coverage limits. If you cause $200,000 in damage and you only have $50,000 in liability, the other $150,000 can come from your savings, wages, or assets.

That last point is the real reason insurance matters. It is not just paperwork to make the law happy. It is the wall between one bad afternoon and years of debt.', 14, 0
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_insurance-and-responsibility_how-auto-insurance-works', 'lesson_insurance-and-responsibility_how-auto-insurance-works', 'Quiz: How auto insurance works', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_insurance-and-responsibility_how-auto-insurance-works_0', 'quiz_insurance-and-responsibility_how-auto-insurance-works', 'What is a deductible?', '["The total amount the insurance company will pay on a claim","The amount you pay out of pocket before insurance starts paying","The monthly fee you pay to keep the policy active","A discount given for completing driver''s ed"]', 1, 'A deductible is your share of the cost on a covered claim. The insurer pays the rest, up to your coverage limit. The monthly fee is called the premium.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_insurance-and-responsibility_how-auto-insurance-works_1', 'quiz_insurance-and-responsibility_how-auto-insurance-works', 'You rear-end another driver and damage their car. Which coverage on your policy pays for the other driver''s repairs?', '["Collision","Comprehensive","Liability","Uninsured motorist"]', 2, 'Liability covers damage and injuries you cause to other people. Collision would pay for your own car, and comprehensive covers non-crash damage like hail or theft.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_insurance-and-responsibility_how-auto-insurance-works_2', 'quiz_insurance-and-responsibility_how-auto-insurance-works', 'A hailstorm dents your car''s hood and cracks the windshield. Which coverage typically pays for this?', '["Liability","Collision","Comprehensive","Medical payments"]', 2, 'Comprehensive covers damage to your car from non-crash events like weather, theft, fire, or animals. Collision applies only when your car hits something or is hit.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_insurance-and-responsibility_how-auto-insurance-works_3', 'quiz_insurance-and-responsibility_how-auto-insurance-works', 'Which of the following is most likely to LOWER a teen driver''s insurance premium?', '["Getting a speeding ticket","Choosing a very low deductible","Completing an approved driver education course","Driving a brand-new sports car"]', 2, 'Many insurers offer a discount for finishing driver''s ed. Tickets, low deductibles, and expensive cars all tend to raise the premium, not lower it.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_insurance-and-responsibility_how-auto-insurance-works_4', 'quiz_insurance-and-responsibility_how-auto-insurance-works', 'You cause a crash that results in $150,000 of damage, but your liability coverage limit is only $50,000. What happens to the remaining $100,000?', '["The insurance company is required to pay it anyway","The other driver''s insurance always covers the gap","You can be personally responsible for paying the rest","The amount above the limit is automatically forgiven"]', 2, 'Insurance only pays up to your policy limits. Anything above that can come out of your savings, wages, or other assets, which is why coverage limits matter so much.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_insurance-and-responsibility_at-the-scene-of-a-crash', 'module_insurance-and-responsibility', 'at-the-scene-of-a-crash', 'At the scene of a crash', 'Even careful drivers get into crashes. The goal of this lesson is simple: if it happens to you, you should know exactly what to do in the first ten minutes, because those minutes affect your safety, your legal standing, and your insurance claim.

## Step 1: Stop. Always stop.

If you are involved in a crash, you must stop. This is true even if the damage looks tiny, even if no one seems hurt, and even if you only hit a parked car or a mailbox. Leaving the scene of a crash you were part of is a serious crime in every state, often a much bigger deal than the crash itself.

If you hit an unattended parked car, leave a note with your name, phone number, and a brief description of what happened, and report it.

## Step 2: Check for injuries

Before anything else, check yourself. Then check your passengers. Then, if it is safe, check the other vehicle.

- If anyone is hurt, call emergency services right away.
- Do not move someone who is injured unless they are in immediate danger (like a car on fire). Moving an injured person can make spinal injuries worse.
- If you are not sure whether someone is hurt, call for help anyway. Adrenaline hides pain.

## Step 3: Make the scene safer

A crash often turns into a second crash when other drivers come around a curve and do not see it in time. If the cars can be driven and you are blocking traffic:

- Move them to the shoulder or a nearby parking lot.
- Turn on hazard lights.
- If you have flares or a reflective triangle, set them out.

If a car cannot be moved, get yourself and your passengers out and away from the roadway, behind a barrier if possible.

## Step 4: Call the police

For anything beyond the most minor fender bender, call the police and ask for an officer to come to the scene. A police report is one of the most useful documents you can have when filing an insurance claim. Even in a small crash, a report helps protect you against false claims later.

While you wait, do not argue with the other driver about who is at fault. Do not say "it was my fault," do not say "don''t worry about it," and do not promise to pay for anything out of pocket. Fault is for the insurance companies and, if needed, the police to determine.

## Step 5: Exchange information

Get, and give, the following:

- Full name and phone number
- Driver''s license number
- License plate number
- Insurance company name and policy number
- Make, model, and color of the vehicle

If there are witnesses, ask for their names and phone numbers too. They can disappear fast once traffic clears.

## Step 6: Document everything

Your phone is your best tool here. Take photos of:

- All damage to every vehicle involved, close up and from a few feet back.
- The position of the cars before you move them, if possible.
- The street, intersection, traffic signs, skid marks, and any debris.
- The other driver''s insurance card and license (with permission, or just photograph the info).
- Any visible injuries.

Write down or voice-memo what happened while it is fresh: the time, the weather, the direction each car was going, and what you remember seeing right before impact.

## Step 7: Report it to your insurance company

Call your insurance company (or your parent''s, if you are on their policy) as soon as you reasonably can, ideally that same day. Most policies require prompt reporting. Tell them the facts. Do not guess, do not exaggerate, and do not minimize. If you do not remember something, say so.

## What not to do

- Do not flee, even if you are scared or unlicensed.
- Do not post about the crash on social media. Insurance companies and lawyers can and do look at posts.
- Do not sign anything from the other driver or a stranger at the scene.
- Do not accept a quick cash offer to "forget the whole thing." Hidden damage and hidden injuries often show up later, and once you accept money, your options shrink.

A crash is scary. Having a plan in your head ahead of time is the single best way to keep a bad moment from getting worse.', 13, 1
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_insurance-and-responsibility_at-the-scene-of-a-crash', 'lesson_insurance-and-responsibility_at-the-scene-of-a-crash', 'Quiz: At the scene of a crash', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_insurance-and-responsibility_at-the-scene-of-a-crash_0', 'quiz_insurance-and-responsibility_at-the-scene-of-a-crash', 'You back into a parked car in a lot and the owner is nowhere in sight. What should you do?', '["Drive away if no one saw it","Leave a note with your name, number, and what happened, and report it","Wait only five minutes and then leave","Move the other car to hide the damage"]', 1, 'Leaving the scene without making a good-faith effort to notify the owner is a hit-and-run, which is a serious offense. A note plus a report protects you legally.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_insurance-and-responsibility_at-the-scene-of-a-crash_1', 'quiz_insurance-and-responsibility_at-the-scene-of-a-crash', 'Someone in the other car appears seriously injured and is not moving. What is the best general approach?', '["Pull them out of the car immediately so they can breathe","Call emergency services and avoid moving them unless they are in immediate danger","Drive them to the hospital yourself to save time","Wait to see if they get up on their own before calling anyone"]', 1, 'Moving an injured person can worsen spinal injuries. Unless there is an immediate threat like fire, wait for trained responders and call for help right away.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_insurance-and-responsibility_at-the-scene-of-a-crash_2', 'quiz_insurance-and-responsibility_at-the-scene-of-a-crash', 'While waiting for the police after a crash, the other driver asks if you''ll just admit it was your fault. What is the smart response?', '["Apologize and say yes to keep the peace","Argue loudly that it was their fault","Stay calm, exchange information, and let the insurance companies and police determine fault","Offer to pay them cash on the spot to drop it"]', 2, 'You may not have the full picture in the moment, and statements at the scene can be used against you. Fault is determined later, based on evidence.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_insurance-and-responsibility_at-the-scene-of-a-crash_3', 'quiz_insurance-and-responsibility_at-the-scene-of-a-crash', 'Which of the following is NOT something you should typically exchange with the other driver?', '["Insurance company name and policy number","Driver''s license number","License plate number","Your home address and social security number"]', 3, 'You don''t need to hand over your home address or social security number at the scene. Name, phone, license number, plate, and insurance info are enough for a claim.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_insurance-and-responsibility_at-the-scene-of-a-crash_4', 'quiz_insurance-and-responsibility_at-the-scene-of-a-crash', 'Why is it a bad idea to post about your crash on social media?', '["It uses too much data","Insurance companies and lawyers can review your posts and use them against your claim","Your phone could overheat","Social media sites delete crash photos automatically"]', 1, 'Posts, photos, and even jokes can be pulled into a claim or lawsuit and used to challenge your version of events. Keep crash details off public feeds.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_insurance-and-responsibility_the-real-cost-of-owning-a-car', 'module_insurance-and-responsibility', 'the-real-cost-of-owning-a-car', 'The real cost of owning a car', 'The sticker price of a car is just the beginning. The real cost of owning a vehicle shows up month after month, and it surprises a lot of new drivers. Understanding the full picture helps you make a smart choice about what car to drive, when to drive it, and whether to drive at all on a given day.

## The big buckets of car costs

Think of car ownership as five ongoing buckets, plus the price of the car itself.

- **The car** — either an upfront purchase or a monthly loan/lease payment, plus sales tax and registration fees.
- **Fuel** — gas or electricity. Varies wildly with how much you drive and how efficient the car is.
- **Insurance** — covered in detail in the first lesson of this module.
- **Maintenance** — routine work that keeps the car running.
- **Repairs** — fixing things that break or wear out.
- **Fees and taxes** — registration, inspection, parking, tolls.

Miss any one of these and you will eventually find yourself stuck on the side of the road or unable to legally drive your car.

## Routine maintenance you cannot skip

Maintenance is what you do *before* something breaks. It is almost always cheaper than waiting for a failure.

- **Oil changes**: typically every few thousand miles, based on the owner''s manual. Old oil ruins engines.
- **Tire pressure**: check at least once a month. Low pressure costs you fuel and chews up tires.
- **Tire rotation and replacement**: tires wear unevenly. Rotating extends life. Bald tires are a crash waiting to happen, especially in rain or snow.
- **Brakes**: brake pads wear down. Squealing or grinding sounds mean it is time for a shop visit.
- **Fluids**: coolant, brake fluid, transmission fluid, windshield washer fluid. Each has a job.
- **Lights and wipers**: a burned-out brake light can get you pulled over and is dangerous. Streaky wipers reduce visibility.
- **Battery**: most last a few years. Slow starts are an early warning.

## Repairs: the surprise bucket

Even a well-maintained car will eventually need repairs. A new battery, a set of tires, or a brake job can each cost several hundred dollars. A failed transmission or engine can cost more than the car is worth. Build a small repair fund if you can. A common rule of thumb: try to save the equivalent of one car payment per month in a separate account so a surprise repair doesn''t become a crisis.

## The hidden cost: depreciation

Cars lose value over time. A new car loses a big chunk of its value the moment you drive it off the lot, and continues to lose value every year. Used cars lose value more slowly, which is one reason they are often a smarter first car for a teen driver. Depreciation isn''t a bill in your mailbox, but if you ever sell the car, you will feel it.

## What it actually adds up to

When you stack the buckets, owning even a modest used car often costs several hundred dollars a month once you average out insurance, fuel, maintenance, and the occasional repair. That is real money. Before you commit to a car, sketch out a monthly budget that includes every bucket above. If the total doesn''t fit your income or your family''s plan, the car doesn''t fit either.

## Smart habits that save real money

- **Drive smoothly.** Hard acceleration and hard braking waste fuel and wear out parts.
- **Combine trips.** Cold engines use more fuel; one longer trip is more efficient than several short ones.
- **Keep tires properly inflated.** It improves fuel economy and tire life.
- **Follow the maintenance schedule** in the owner''s manual. It is written for your specific car.
- **Compare gas prices**, but don''t drive ten miles out of your way to save two cents a gallon.
- **Address small issues early.** A small leak ignored becomes a big repair.
- **Don''t ignore warning lights.** A check-engine light is the car telling you something. Get it scanned.

## Driving less is also a choice

The cheapest mile is the one you don''t drive. Carpooling, biking, walking, and public transit all reduce wear on your car and your wallet. Being a responsible driver also means recognizing when driving isn''t the right call.', 13, 2
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_insurance-and-responsibility_the-real-cost-of-owning-a-car', 'lesson_insurance-and-responsibility_the-real-cost-of-owning-a-car', 'Quiz: The real cost of owning a car', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_insurance-and-responsibility_the-real-cost-of-owning-a-car_0', 'quiz_insurance-and-responsibility_the-real-cost-of-owning-a-car', 'Which of the following is the BEST description of the true cost of owning a car?', '["Just the purchase price plus gas","The monthly car payment only","Purchase or payment plus fuel, insurance, maintenance, repairs, and fees","Insurance and oil changes"]', 2, 'Car ownership has many ongoing buckets. Ignoring any of them, like insurance or maintenance, leads to financial or legal trouble down the road.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_insurance-and-responsibility_the-real-cost-of-owning-a-car_1', 'quiz_insurance-and-responsibility_the-real-cost-of-owning-a-car', 'What is the main reason regular oil changes matter?', '["They make the car smell better","Old oil can damage the engine, leading to expensive repairs","They are required to keep the warranty on tires","They make the car faster"]', 1, 'Engine oil breaks down over time and stops protecting moving parts. Skipping changes is one of the fastest ways to destroy an engine.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_insurance-and-responsibility_the-real-cost-of-owning-a-car_2', 'quiz_insurance-and-responsibility_the-real-cost-of-owning-a-car', 'What is depreciation?', '["A type of insurance discount","The loss of a car''s value over time","A monthly maintenance fee","A tax paid only on new cars"]', 1, 'Depreciation is the gradual decline in a car''s market value. It is invisible month-to-month but very real when you sell or trade in.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_insurance-and-responsibility_the-real-cost-of-owning-a-car_3', 'quiz_insurance-and-responsibility_the-real-cost-of-owning-a-car', 'You notice a small puddle of fluid under your car each morning. What is the responsible move?', '["Ignore it; small leaks fix themselves","Add water to whichever fluid is low and forget about it","Get it checked soon, before a small issue turns into a major repair","Wait until a warning light comes on"]', 2, 'Small leaks usually get worse, not better. Catching problems early is almost always cheaper than waiting for a breakdown.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_insurance-and-responsibility_the-real-cost-of-owning-a-car_4', 'quiz_insurance-and-responsibility_the-real-cost-of-owning-a-car', 'Which habit is most likely to lower your long-term cost of driving?', '["Hard, fast acceleration from every stoplight","Ignoring the maintenance schedule to save money short-term","Driving smoothly and following the maintenance schedule","Skipping oil changes when the car seems to run fine"]', 2, 'Smooth driving saves fuel and reduces wear, and routine maintenance prevents expensive failures. Skipping either tends to cost more in the long run.', 4
);
INSERT INTO lesson (id, moduleId, slug, title, body, estimatedSeatMinutes, ordinal) VALUES (
  'lesson_insurance-and-responsibility_what-responsible-driving-looks-like', 'module_insurance-and-responsibility', 'what-responsible-driving-looks-like', 'What responsible driving looks like', 'Being a "responsible driver" sounds vague until you break it down into habits. Responsibility is not a personality trait. It is a set of small choices you make every time you get behind the wheel. Done consistently, those choices keep you, your passengers, and everyone else on the road safer.

## Before you drive

Responsibility starts before the engine is on.

- **Are you fit to drive?** Driving impaired by alcohol, drugs (including some prescriptions), or extreme tiredness is one of the leading causes of fatal crashes. If you are not sure you are okay to drive, you are not okay to drive.
- **Do you have what you need?** License, insurance card, registration. Some states allow digital versions, but always know where yours are.
- **Is the car ready?** Quick walk-around: tires look full, no obvious leaks, mirrors clean, lights working. Thirty seconds.
- **Plan the route.** Set up navigation and music *before* you put the car in drive. Adjusting these while moving is how crashes happen.

## While you drive

Most responsible-driver habits live in this stage.

- **Wear your seatbelt. Every trip. Every seat.** Seatbelts are the single most effective safety device in a car.
- **Put the phone away.** Texting, scrolling, or even glancing at a notification takes your eyes off the road long enough to travel the length of a football field at highway speed. Use Do Not Disturb or a similar mode.
- **Follow speed limits.** They exist for the road, weather, and traffic conditions of that area. "Going with the flow of traffic" is not a legal defense if the flow is speeding.
- **Leave space.** Tailgating gives you no time to react. A common guideline is at least a few seconds of following distance, more in bad weather.
- **Signal early.** Other drivers can only cooperate with you if they know what you plan to do.
- **Yield when in doubt.** Being right doesn''t matter if you''re in a crash.
- **Manage emotions.** Frustration and anger behind the wheel lead to bad decisions. If another driver does something rude, let it go. Do not chase, brake-check, or escalate.

## Passengers and distractions

Passengers are one of the biggest risk factors for new drivers. The more people in the car, the higher the crash risk, especially for teens.

- Set expectations with friends: phone goes down, voices stay calm, no messing with the wheel or controls.
- You are responsible for what happens in the car. If passengers are being unsafe, pull over.
- Pets should be secured. A loose animal can become a projectile in a crash and is a major distraction.

## When the weather is bad

Rain, snow, ice, fog, and heavy wind all change what your car can do.

- Slow down. Stopping distances grow on wet or icy roads.
- Turn on headlights any time visibility drops, even during the day.
- Increase following distance.
- If conditions are dangerous and the trip can wait, wait.

## When something goes wrong

Responsibility includes knowing what to do when things don''t go to plan.

- **If a warning light comes on**, check the owner''s manual. Some lights mean "schedule service soon." Others (oil pressure, engine temperature) mean "pull over safely now."
- **If you break down**, get the car as far off the road as possible, turn on hazards, and stay buckled inside if you are in a dangerous spot. Standing next to a car on a busy road is risky.
- **If you make a mistake**, own it. Tell your parents. Tell your insurance company if needed. Hiding problems usually makes them bigger.

## The bigger picture

When you drive, you are using a heavy, fast machine in a shared public space. The privilege comes with real obligations:

- To the people in your car.
- To other drivers, cyclists, and pedestrians who assume you will follow the rules.
- To the community whose roads, signals, and emergency services make driving possible.
- To yourself, your future, and the people who care about you.

Responsible driving is not about being perfect. It is about taking the job seriously every time you sit in the driver''s seat. Do that, and the rest, including lower insurance costs, fewer scary moments, and a clean record, tends to follow.', 12, 3
);
INSERT INTO quiz (id, lessonId, title, passingScore, shuffleQuestions) VALUES (
  'quiz_insurance-and-responsibility_what-responsible-driving-looks-like', 'lesson_insurance-and-responsibility_what-responsible-driving-looks-like', 'Quiz: What responsible driving looks like', 80, 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_insurance-and-responsibility_what-responsible-driving-looks-like_0', 'quiz_insurance-and-responsibility_what-responsible-driving-looks-like', 'Which of the following is the single most effective safety device in a car?', '["Anti-lock brakes","The seatbelt","The horn","Cruise control"]', 1, 'Seatbelts are consistently shown to be the most effective tool for preventing serious injury and death in crashes. They should be worn on every trip, in every seat.', 0
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_insurance-and-responsibility_what-responsible-driving-looks-like_1', 'quiz_insurance-and-responsibility_what-responsible-driving-looks-like', 'You receive a text while driving on the highway. What is the responsible choice?', '["Read it quickly at the next red light only","Wait to read and respond until you have safely parked","Glance at it; one second won''t matter","Ask a passenger to type your reply while you read the text yourself"]', 1, 'Even brief glances at a phone at highway speeds cover huge distances blind. Reading at red lights is still distracted driving and can keep you from noticing changing signals or pedestrians.', 1
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_insurance-and-responsibility_what-responsible-driving-looks-like_2', 'quiz_insurance-and-responsibility_what-responsible-driving-looks-like', 'Another driver cuts you off and gestures rudely. What is the responsible response?', '["Speed up and cut them off in return","Follow them closely to teach them a lesson","Take a breath, leave space, and let it go","Honk repeatedly and brake-check them"]', 2, 'Retaliating turns a small annoyance into a serious risk for everyone. Managing emotions is a core part of responsible driving.', 2
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_insurance-and-responsibility_what-responsible-driving-looks-like_3', 'quiz_insurance-and-responsibility_what-responsible-driving-looks-like', 'Your oil pressure warning light comes on while you are driving. What is generally the right move?', '["Ignore it; warning lights usually mean nothing","Keep driving until you reach home, however far that is","Find a safe place to pull over soon and address the issue before driving further","Turn off the dashboard so the light doesn''t distract you"]', 2, 'Oil pressure and engine temperature lights signal problems that can quickly destroy an engine. Pull over safely as soon as you can and figure out the cause.', 3
);
INSERT INTO quiz_question (id, quizId, prompt, choices, correctIndex, explanation, ordinal) VALUES (
  'q_insurance-and-responsibility_what-responsible-driving-looks-like_4', 'quiz_insurance-and-responsibility_what-responsible-driving-looks-like', 'Why are passengers, especially other teens, considered a risk factor for new drivers?', '["They add weight that slows the car","They increase distractions and crash risk, particularly for inexperienced drivers","They make insurance illegal","They block the driver''s mirrors automatically"]', 1, 'Data consistently shows that crash risk rises for new drivers with additional passengers, largely due to distraction and social pressure. Setting expectations in the car helps reduce that risk.', 4
);

